-- VB-MAPP Milestone-Specific Program Plan Templates
-- These rows override the broader domain template when a selected milestone
-- needs more specific teaching guidance (for example, LR-11 vs LR-12 vs LR-13).

CREATE TABLE IF NOT EXISTS vbmapp_milestone_templates (
  id                         SERIAL PRIMARY KEY,
  milestone_code             VARCHAR(20) UNIQUE NOT NULL REFERENCES vbmapp_milestones(milestone_code) ON DELETE CASCADE,
  vbmapp_domain              VARCHAR(100) NOT NULL,
  data_collection            TEXT,
  prerequisite_skills        TEXT,
  materials                  TEXT,
  sd                         TEXT,
  correct_responses          TEXT,
  incorrect_responses        TEXT,
  prompting_hierarchy        VARCHAR(20) DEFAULT 'most_to_least'
    CHECK (prompting_hierarchy IN ('most_to_least', 'least_to_most')),
  prompting_hierarchy_detail TEXT,
  error_correction           TEXT,
  transfer_procedure         TEXT,
  reinforcement_schedule     TEXT,
  generalization_plan        TEXT,
  maintenance_plan           TEXT,
  template_origin            VARCHAR(40) NOT NULL DEFAULT 'manual_override'
);



-- Full coverage: 240 rows, one per VB-MAPP milestone.

-- template_origin = 'full_coverage' for all auto-generated rows.



INSERT INTO vbmapp_milestone_templates (milestone_code, vbmapp_domain, data_collection, prerequisite_skills, materials, sd, correct_responses, incorrect_responses, prompting_hierarchy, prompting_hierarchy_detail, error_correction, transfer_procedure, reinforcement_schedule, generalization_plan, maintenance_plan) VALUES
('MND-1', 'Mand',
 'Record each unprompted mand attempt using a frequency tally. Track the 2 target words or approximations separately. Criterion: 2 different spontaneous mands observed across 3 sessions.',
 'Basic attending skills; eye contact or orientation to preferred items; tolerance of brief delays before access to reinforcers.',
 'Two to three highly preferred tangible items identified via preference assessment (e.g., bubbles, a snack, a toy car); accessible but slightly out of reach to create an establishing operation.',
 'Arrange the environment so 1–2 highly preferred items are visible but inaccessible. Wait up to 10 seconds for a spontaneous vocal, sign, or AAC output. Do NOT present a verbal model first.',
 'Child emits at least 2 different mands (vocal word, functional approximation, sign, or AAC symbol) without an immediate verbal prompt or echolalic repetition, across at least 3 separate observations.',
 'Prompted mand (immediately after instructor model), echolalic repetition of instructor speech, or no response within 10 seconds.',
 'most_to_least',
 'Begin with full physical or full verbal model if no spontaneous mand appears; fade to partial verbal model ("bub…"), then time-delay (wait expectantly 5 s), then no prompt.',
 'If no mand occurs within 10 s, provide a least-to-most prompt starting with a time-delay, then a partial model. Do NOT deliver the reinforcer for prompted mands during criterion probes.',
 'Once 2 spontaneous mands are reliable, introduce a 3rd item to expand the vocabulary. Use incidental teaching during natural routines (snack, play) to promote transfer.',
 'CRF (continuous reinforcement): deliver the requested item immediately for every spontaneous mand to build the response.',
 'Rotate which 2 preferred items are available across sessions; conduct probes across at least 2 different adults and 2 settings (classroom, home).',
 'Probe spontaneous manding weekly once criterion is met; re-introduce preferred items after brief satiation breaks to maintain motivation.'),

('MND-2', 'Mand',
 'Track mands using a frequency count per session, noting the specific reinforcer requested. Criterion: 5 different reinforcers manded without prompts across 3 consecutive sessions.',
 'MND-1 (2 spontaneous mands); basic communication modality established (vocal, sign, or AAC); preference assessment identifying at least 5 distinct preferred items.',
 'Five or more distinct preferred items/activities identified via paired-stimulus or free-operant preference assessment; communication device or sign prompts available if using AAC/sign.',
 'Present each of the 5 preferred items one at a time (or visible but withheld) and wait 5–10 seconds for a spontaneous mand. Rotate through all 5 items within each session.',
 'Child independently mands for 5 different reinforcers (vocal, sign, or AAC) without prompts or echolalia, with at least 1 instance per reinforcer per session.',
 'Mand only for items already mastered (fewer than 5 different), prompted mands, or stereotyped vocalizations unrelated to the item.',
 'most_to_least',
 'Verbal model → partial verbal model → time-delay → no prompt. Use time-delay (5 s expectant wait) as the primary fading step once 3 items are reliable.',
 'Following an incorrect or prompted response, remove the item briefly (1–2 s), then re-present with a lesser intrusive prompt. Deliver reinforcer only for unprompted correct mands during probes.',
 'Once 5 items are mastered, add 2–3 new items per week, following the same MO-based presentation. Move to naturalistic incidental teaching across the day.',
 'CRF: immediate access to requested item for every unprompted mand.',
 'Probe manding across 3 different adults, 2 physical settings, and varying times of day to ensure generalization beyond structured trials.',
 'Conduct monthly generalization probes; reintroduce items after satiation if frequency drops below 1 mand per item per session.'),

('MND-3', 'Mand',
 'Log each mand with the setting and listener noted. Criterion: 10 different reinforcers manded without prompts across at least 3 different settings over a 1-week period.',
 'MND-2 (5 spontaneous mands); ability to mand with at least one communication partner other than primary therapist.',
 'Ten or more preferred items spanning multiple categories (food, toys, social activities); 3 or more distinct settings (e.g., therapy room, classroom, home, outdoors).',
 'During naturally occurring routines across at least 3 settings, arrange the environment to create an MO for each of the 10 target items. Withhold items or pause activities and wait for spontaneous mands.',
 'Child emits mands for at least 10 different reinforcers without prompts across a minimum of 3 different settings within a single week of data collection.',
 'Manding for fewer than 10 distinct items, manding only in the structured therapy room, or requiring prompts to initiate.',
 'most_to_least',
 'In new settings, briefly re-introduce time-delay prompting; fade back to no prompt as the child establishes manding in that setting.',
 'If manding fails to occur in a new setting, use a within-stimulus prompt (place item in view at eye level) then fade to more natural arrangement.',
 'Schedule brief incidental teaching probes across all 3 settings daily. Coordinate with caregivers and teachers to record any spontaneous mands that occur outside structured sessions.',
 'Thinning to VR-2 in familiar settings; maintain CRF in new settings until criterion is met there.',
 'Introduce new settings systematically (add 1 new setting per week); rotate communication partners (parent, teacher, aide, peer).',
 'Monthly probes across all 3+ settings; if any setting drops below criterion, re-introduce structured MO arrangements for that setting.'),

('MND-4', 'Mand',
 'Record presence or absence of a spontaneous mand upon each EO presentation using a Y/N event-based data sheet. Criterion: mand occurs on 8 of 10 EO presentations across 2 sessions.',
 'MND-3 (10 mands across 3 settings); understanding that specific items/actions satisfy specific motivational states; basic recognition of own internal states.',
 'Items that naturally create establishing operations (e.g., a locked container for a desired toy, a missing puzzle piece, a snack just out of reach); no additional verbal prompts by the instructor.',
 'Arrange a clear EO naturally (e.g., child is thirsty—offer cup without drink; child wants a toy—show it behind a barrier) and simply wait. Do NOT add "What do you want?" or any other prompt.',
 'Child emits a contextually appropriate mand in response to the naturally occurring EO alone, without any additional verbal, gestural, or physical prompts from the instructor.',
 'Prompted mands (any instructor cue following EO presentation), mands that occur outside the EO context, or echolalic responses not functionally tied to the EO.',
 'most_to_least',
 'Initially pair EO with a gestural prompt (point to item); fade gestural prompt over successive presentations until EO alone controls the mand.',
 'If no mand after 10 s, briefly re-present the EO with a subtle gestural prompt, then retry pure EO on the next trial.',
 'Expand to novel EOs not previously trained (e.g., broken toy, spilled item) to confirm the mand is truly under EO control rather than tied to a specific setup.',
 'CRF: immediately fulfill the mand to strengthen the EO–mand relationship.',
 'Systematically vary the type of EO (deprivation, presence of barrier, broken item); probe with novel communication partners.',
 'Conduct weekly EO probes; re-create EOs periodically in naturalistic settings to ensure the skill is maintained without structured prompting.'),

('MND-5', 'Mand',
 'Collect daily frequency counts of all spontaneous mands throughout the full school/therapy day using a wrist counter or tally sheet. Criterion: 20 or more different mand words observed across a full day, documented over 3 consecutive days.',
 'MND-4 (mands under EO control); established vocabulary of at least 15 functional mand words; manding generalized across multiple settings and partners.',
 'Naturalistic environment across full school/therapy day; a wide array of preferred items, activities, and social interactions available; communication device if using AAC.',
 'Throughout the natural day, engineer the environment to present ongoing opportunities (snack, play, transitions, social games). No structured trial format—manding is recorded as it naturally occurs.',
 'Child spontaneously mands for 20 or more different reinforcers (items, actions, social interactions) across the entire day without prompts, documented across at least 3 full days.',
 'Manding fewer than 20 different items per day, requiring prompts for most mands, or manding only within structured therapy sessions.',
 'most_to_least',
 'Environmental engineering (visible but withheld preferred items, incomplete activities) serves as the primary prompt; fade engineering as the child initiates manding more frequently.',
 'If frequency is low, temporarily increase the density of MO-based opportunities; review preference assessment to ensure items remain highly preferred.',
 'Begin tracking 2-word mands as they emerge; document any novel spontaneous combinations as precursors to MND-6.',
 'FR-1 (CRF) for novel or rare mands; moving to VR-2 for high-frequency mands with very familiar items.',
 'Coordinate with all adults in the child''s environment to record mands; vary available items weekly to prevent satiation and encourage novel manding.',
 'Continue daily frequency monitoring monthly; if count drops below 15, conduct a new preference assessment and increase MO-based opportunities.'),

('MND-6', 'Mand',
 'Record each 2-word mand combination, noting both words, the setting, and whether prompted. Criterion: 2-word mands observed spontaneously across 10 different combinations over 2 sessions.',
 'MND-5 (20+ single-word mands); emerging use of 2-word combinations in any verbal operant; basic understanding of modifier + noun or verb + noun structure.',
 'Highly preferred items that naturally lend themselves to 2-word mands (e.g., "more juice," "big cookie," "open box"); choice boards with picture pairs if using AAC.',
 'Present a situation where a single-word mand is ambiguous or insufficient (e.g., two types of juice available) to create a natural opportunity for a 2-word combination. Wait up to 10 s.',
 'Child spontaneously emits 2-word mand combinations (e.g., "more juice," "want cookie," "push swing") without prompting, using at least 10 different combinations.',
 'Single-word mand only, imitated 2-word combination immediately after instructor model, or unintelligible vocalization.',
 'most_to_least',
 'Full verbal model of 2-word mand → partial verbal model (first word only, "more…") → time-delay → no prompt.',
 'If single-word mand is emitted, provide a partial model for the second word and reinforce the completed 2-word mand on that trial; next trial, use time-delay only.',
 'Once 10 combinations are reliable, shift all training to naturalistic incidental teaching and begin targeting 3-word mands (MND-11 precursor).',
 'CRF for 2-word mands; single-word mands during criterion probes result in a brief pause before fulfilling request to encourage expansion.',
 'Target 2-word combinations across different semantic relationships: action+object, more+noun, adjective+noun, possessive+noun.',
 'Weekly probes for 2-word mand frequency; track whether new combinations emerge without direct training.'),

('MND-7', 'Mand',
 'Record instances where the child mands for a missing item (specifying what is absent) vs. manding for present items. Criterion: 5 different missing-item mands across 2 sessions.',
 'MND-6 (2-word mand combinations); ability to notice absence of a key item; basic problem recognition in activity context.',
 'Activities with a required but deliberately omitted component (e.g., playdough without a tool, art project without glue, snack without a utensil); the missing item is within view but withheld.',
 'Set up an activity and omit a necessary item that the child would typically request. Present the incomplete activity without comment and wait up to 15 s for a spontaneous mand for the missing item.',
 'Child independently mands for a specific missing item needed to complete an activity (e.g., "I need scissors," "where''s the glue?", "more paint") without being told what is missing.',
 'Manding for an unrelated item, requesting help without specifying the missing item, or waiting passively without any communicative attempt.',
 'most_to_least',
 'Point-and-pause (gesture toward empty spot) → partial verbal ("you need the…") → full verbal model → no prompt. Fade over successive presentations.',
 'If child does not mand after 15 s, provide the minimal intrusive prompt; deliver the missing item; on the next opportunity, use a less intrusive prompt.',
 'Generalize to novel activities; include activities at home (reported by caregivers) to document naturalistic missing-item mands.',
 'CRF: immediately provide the missing item when manded correctly.',
 'Vary activities weekly; probe missing-item manding during play, art, cooking, and academic tasks.',
 'Monthly probe: set up 5 different incomplete activities and record whether missing-item mands occur spontaneously.'),

('MND-8', 'Mand',
 'Record each spontaneous "what" or "where" question mand, noting the context and whether the information was genuinely unknown to the child. Criterion: 5 different spontaneous "what" or "where" mands across 3 sessions.',
 'MND-7 (mands for missing items); understanding that asking questions yields information; basic question-form grammar in tacting or intraverbal context.',
 'Novel objects in opaque containers or bags; items placed in unexpected locations; activities with an unknown next step; no visual cues about the answer available.',
 'Present a situation where the child genuinely does not know the location or identity of a desired item (e.g., reinforcer placed in one of several boxes). Wait for a spontaneous "what" or "where" question.',
 'Child spontaneously asks "what is that?", "where is it?", "what''s in there?", or equivalent without gestural or verbal prompt, in response to genuine information-gap contexts.',
 'Echoing the instructor''s recent question, asking a question immediately after a verbal model, or stating rather than asking ("I don''t know").',
 'most_to_least',
 'Verbal model of the question form → partial model (first word of question) → expectant pause → no prompt.',
 'If a statement is produced instead of a question, provide a partial prompt for question form; reinforce with information (answer) only when question form is used.',
 'Fade to fully naturalistic contexts once 5 spontaneous instances are observed; coordinate with caregivers to capture home occurrences.',
 'CRF: answer the question immediately and accurately to reinforce the mand for information.',
 'Vary the type of information gap (location vs. identity vs. action); use different objects and settings.',
 'Monthly probe: create 5 novel information-gap situations and record spontaneous question mands.'),

('MND-9', 'Mand',
 'Daily frequency tally of all spontaneous mands across the full day, categorized by unique reinforcer labels. Criterion: 50 different reinforcer labels manded with minimal prompting over a 1-week period.',
 'MND-8 (mands for information); established 2-word mand repertoire; manding generalized across settings and partners with 20+ items (MND-5).',
 'Full naturalistic day across all environments (home, school, community); wide variety of preferred items, activities, and social interactions; communication system (vocal, AAC, sign) established.',
 'Conduct naturalistic environment engineering throughout the day to create MOs for a broad range of items and activities. Record all spontaneous mands; minimal prompting means no more than a time-delay.',
 'Child spontaneously mands for at least 50 different reinforcers across the day using the established communication modality, with no more than a 5-second time-delay prompt on fewer than 20% of trials.',
 'Requiring a full verbal model for more than 20% of mands, manding fewer than 50 different items per day, or manding only within structured sessions.',
 'most_to_least',
 'Primary fading strategy is time-delay (5 s). Verbal models used only for items not in current vocabulary; fade immediately once word is established.',
 'For items below 80% unprompted, temporarily increase MO-based opportunities and use graduated time-delay (1 s → 3 s → 5 s) to build independence.',
 'Update preference assessments bi-weekly to maintain motivational relevance of the 50 target items; introduce new vocabulary to push toward MND-14.',
 'Thinning to VR-2 for well-established mands; CRF for new or low-frequency mand targets.',
 'Coordinate with all communication partners; document mands across home, school, and community settings.',
 'Bi-weekly review of mand frequency data; conduct preference assessment if frequency drops; add new items to maintain growth trajectory.'),

('MND-10', 'Mand',
 'Record each mand that includes an adjective modifier, noting the adjective used and whether it was spontaneous or prompted. Criterion: 5 different adjective+noun mand combinations observed spontaneously across 2 sessions.',
 'MND-9 (50+ reinforcers manded); established 2-word mand combinations; receptive understanding of basic adjective categories (color, size, shape).',
 'Pairs of similar items differing by a single attribute (two balls of different sizes, two cups of different colors, two cookies with different shapes); choice situations where the adjective is necessary.',
 'Present a choice between two similar items that differ by one attribute (e.g., a big cup and a small cup) and wait for the child to specify which one is wanted using an adjective.',
 'Child spontaneously uses adjective+noun mand combinations (e.g., "big ball," "red cup," "round cracker") to specify desired items, with at least 5 different adjective+noun combinations.',
 'Single-noun mand without adjective when the adjective is necessary for disambiguation, or immediately imitating instructor''s adjective model.',
 'most_to_least',
 'If child says noun only, hold up both items and say "which one?" → partial model of adjective ("big…") → full model → no prompt.',
 'Provide the wrong item when only a noun is manded (natural consequence) to increase the need for adjective specification; then prompt adjective use.',
 'Once adjective manding is established with color/size, expand to shape, texture, and quantity adjectives; begin targeting 3-word mands.',
 'CRF for adjective+noun mands; deliver the correct item immediately to reinforce precision.',
 'Vary attribute types across sessions (color, size, shape, texture); generalize across different nouns and settings.',
 'Monthly probe: present 5 choice pairs and record spontaneous adjective+noun mands without prompting.'),

('MND-11', 'Mand',
 'Record each mand that uses a complete sentence of 3 or more words, noting the full utterance and context. Criterion: 10 different 3+-word sentence mands across 2 sessions without prompts.',
 'MND-10 (adjective+noun mand combinations); ability to produce 3-word utterances in tacting or echoic contexts; emerging sentence structure in other verbal operants.',
 'Naturalistic activities that create clear desires for action+object combinations (e.g., "push the swing," "open the door"); preferred items requiring assistance; novel activities with multiple components.',
 'During play, snack, or activity routines, withhold or create a barrier to a desired action or item and wait up to 10 s for a 3+-word mand without prompting.',
 'Child spontaneously emits complete sentence mands of 3 or more words (e.g., "I want more juice," "can you open it?", "give me the big ball") without any verbal prompt.',
 '2-word mands when a 3-word sentence would be contextually appropriate, immediately imitating a sentence model, or requesting using only a single word.',
 'most_to_least',
 'If 2-word mand occurs, provide a partial model for the third word ("I want…") and reinforce the completed sentence; use expectant pause as primary strategy.',
 'Shape 3-word mands from established 2-word mands using a forward-chaining model: reinforce 2-word → require 3-word on next trial.',
 'Generalize to phone/video calls with caregivers and peer interactions to ensure sentence manding occurs in fully naturalistic social contexts.',
 'Differential reinforcement: immediate access for 3+-word mands; brief pause (3 s) before honoring 2-word mands to encourage expansion.',
 'Target different sentence types: requests for items, requests for actions, requests for information, and requests for permission.',
 'Weekly frequency count of 3+-word mands across all settings; track mean length of utterance (MLU) as a supplementary measure.'),

('MND-12', 'Mand',
 'Record each spontaneous "why," "how," or "when" question mand, noting the specific question and context. Criterion: 5 different why/how/when mands across 3 sessions.',
 'MND-11 (3+-word sentence mands); MND-8 (what/where mands); understanding that different question words yield different types of information; causal and temporal language emerging.',
 'Situations with genuine information gaps related to reason (why something happened), process (how something works), or timing (when something will occur); surprising events; novel procedures.',
 'Create genuine information gaps: break a toy and wait for "why is it broken?"; start a new activity and withhold instructions to elicit "how do I do it?"; approach transition and wait for "when are we going?"',
 'Child spontaneously asks why, how, or when questions in response to genuine information gaps, without verbal prompting, using grammatically appropriate question forms.',
 'Asking what/where questions when why/how/when would be more appropriate, or making statements rather than questions in information-gap situations.',
 'most_to_least',
 'Model the question form → partial model (question word only, "why…?") → expectant pause → no prompt.',
 'If a statement is produced ("I don''t know why"), provide a partial model for the question form; reinforce only question form with the requested information.',
 'Generalize to classroom discussions, peer interactions, and community settings where why/how/when questions arise naturally.',
 'CRF: answer questions immediately and fully to reinforce information-seeking behavior.',
 'Target all three question types (why, how, when) across varied topics; probe during academic tasks, play, and social routines.',
 'Monthly probe across 5 novel information-gap situations; track whether question type matches the type of information needed.'),

('MND-13', 'Mand',
 'Record instances where the child uses language to terminate or avoid non-preferred activities, noting the specific utterance and whether it was appropriate. Criterion: 5 appropriate mands to terminate/avoid across 2 sessions.',
 'MND-12 (why/how/when mands); tolerance for some non-preferred activities; basic self-advocacy language; understanding that verbal behavior can change one''s situation.',
 'Non-preferred but tolerable activities (not highly aversive); visual schedule showing the activity sequence; break cards or choice boards as supplementary supports initially.',
 'During a non-preferred activity, wait for the child to use appropriate language to request a break, termination, or avoidance (e.g., "I''m done," "can I stop?", "I don''t want to do this") rather than engaging in problem behavior.',
 'Child appropriately uses language (verbal or AAC) to request termination or avoidance of non-preferred activities using complete and polite phrases, without problem behavior.',
 'Engaging in problem behavior (tantrum, aggression, elopement) instead of using language, using appropriate language only after being prompted, or manding to avoid all demands including preferred ones.',
 'most_to_least',
 'Prompt use of break card → prompt partial phrase ("I need a…") → expectant pause → no prompt. Reduce intrusiveness as child demonstrates the functional link between language and break.',
 'Honor appropriate mands immediately to strongly reinforce the behavior; if problem behavior occurs first, wait for it to subside then prompt and reinforce the verbal alternative.',
 'Gradually increase the demand before a break is honored (DRA + demand fading) to build tolerance while maintaining the mand repertoire.',
 'CRF: immediately honor appropriate mands to terminate/avoid; do NOT honor them if preceded by problem behavior.',
 'Target varied non-preferred activities (academic tasks, hygiene routines, transitions); teach across all settings where non-preferred activities occur.',
 'Weekly review of data; track whether problem behavior decreases as verbal mands increase; maintain a low to moderate non-preferred activity ratio to support maintenance.'),

('MND-14', 'Mand',
 'Count unique mand vocabulary words across a full week using a running vocabulary log. Criterion: 200 or more different mand words documented across varied sentence structures over a 2-week period.',
 'MND-13 (mands to terminate/avoid); sentence-level manding established; wide expressive vocabulary across multiple verbal operants; manding generalized across all settings.',
 'Full naturalistic environments across all daily settings; communication system supporting 200+-word vocabulary; vocabulary log template for all communication partners.',
 'Across the naturalistic day, provide ongoing MO-based opportunities. Track every novel mand word that appears. No structured trial format—manding is recorded as it naturally occurs across all environments.',
 'Child spontaneously mands using 200 or more different words appearing across various sentence structures (simple requests, conditional requests, embedded clause requests) across a 2-week documentation window.',
 'Manding with fewer than 200 different words, using only one sentence structure, or requiring structured prompting for the majority of mands.',
 'most_to_least',
 'Environmental engineering is the primary strategy; time-delay (5 s) for any item not in current 200-word repertoire; verbal model only for brand-new vocabulary.',
 'For words appearing infrequently, temporarily increase the MO and use a 1-trial verbal model followed by immediate fading.',
 'Maintain a running vocabulary log shared with all adults; celebrate milestone of 200 words; begin targeting conditional and complex sentence mands (MND-15).',
 'CRF for novel or low-frequency mand words; VR-3 for high-frequency established words.',
 'Ensure mand vocabulary spans all semantic categories: nouns, verbs, adjectives, social phrases, questions, conditional statements.',
 'Monthly review of vocabulary log; track rate of new word emergence; conduct preference assessment to introduce new items that motivate novel mand vocabulary.'),

('MND-15', 'Mand',
 'Record instances of mands used to direct others'' behavior or initiate social interactions, noting the full utterance and social outcome. Criterion: 5 different social-direction or social-initiation mands per session across 3 sessions.',
 'MND-14 (200+ mand words); sentence-level manding; emerging social interaction skills; understanding that language can influence others'' behavior and social relationships.',
 'Naturalistic social environments with peers and adults; cooperative play materials; group activities; games requiring partner participation.',
 'During social activities, wait for the child to use language to direct a peer''s behavior ("come play with me," "it''s your turn," "watch what I do") or initiate a social interaction without adult prompting.',
 'Child uses mands to direct others'' behavior (e.g., "come here," "you go first," "help me build this") or initiate social interactions (e.g., "let''s play," "want to see something?") spontaneously.',
 'Using gestures or physical prompts instead of language to direct others, adult-directed social mands only, or waiting passively for social opportunities.',
 'most_to_least',
 'Arrange cooperative activities requiring a partner''s specific action; use peer confederate training if needed; fade adult prompting to allow natural peer-to-peer exchanges.',
 'If child attempts to physically direct another person, interrupt gently and prompt appropriate verbal alternative; reinforce verbal direction immediately.',
 'Embed social-direction mands into structured peer play groups, then fade structure to fully free play; coordinate with school staff to document classroom social mands.',
 'Social reinforcement (compliance from peer, enthusiastic response) serves as natural reinforcer; supplement with brief praise if needed initially.',
 'Target different social functions: directing action, inviting participation, sharing information, requesting joint attention.',
 'Monthly observation in unstructured peer settings; track whether social mands result in successful social interactions; monitor peer reciprocity as an outcome measure.')
ON CONFLICT (milestone_code) DO UPDATE
SET vbmapp_domain = EXCLUDED.vbmapp_domain,
    data_collection = EXCLUDED.data_collection,
    prerequisite_skills = EXCLUDED.prerequisite_skills,
    materials = EXCLUDED.materials,
    sd = EXCLUDED.sd,
    correct_responses = EXCLUDED.correct_responses,
    incorrect_responses = EXCLUDED.incorrect_responses,
    prompting_hierarchy = EXCLUDED.prompting_hierarchy,
    prompting_hierarchy_detail = EXCLUDED.prompting_hierarchy_detail,
    error_correction = EXCLUDED.error_correction,
    transfer_procedure = EXCLUDED.transfer_procedure,
    reinforcement_schedule = EXCLUDED.reinforcement_schedule,
    generalization_plan = EXCLUDED.generalization_plan,
    maintenance_plan = EXCLUDED.maintenance_plan,
    template_origin = EXCLUDED.template_origin;

-- ============================================================
-- TACT (TAC-1 through TAC-15)
-- ============================================================

INSERT INTO vbmapp_milestone_templates (milestone_code, vbmapp_domain, data_collection, prerequisite_skills, materials, sd, correct_responses, incorrect_responses, prompting_hierarchy, prompting_hierarchy_detail, error_correction, transfer_procedure, reinforcement_schedule, generalization_plan, maintenance_plan) VALUES
('TAC-1', 'Tact',
 'Record correct/incorrect responses for each item presented using a plus/minus data sheet. Criterion: 5 different items tacted correctly on 4 of 5 opportunities each across 2 consecutive sessions.',
 'Basic attending and eye contact; ability to imitate vocalizations; some echoic repertoire to establish tact labels; no prerequisite tacts required.',
 'Five highly familiar objects the child interacts with daily (e.g., cup, ball, shoe, spoon, book); objects presented one at a time in front of the child.',
 'Present one item at a time to the child and ask "What is this?" or simply hold it up expectantly. Wait 3–5 seconds for a spontaneous label before prompting.',
 'Child correctly labels all 5 target items without prompts on 4 of 5 presentations each, across 2 consecutive sessions.',
 'Incorrect label, no response within 5 s, or echolalic repetition of the SD rather than the item name.',
 'most_to_least',
 'Full vocal model ("ball") → partial model ("ba…") → time-delay (3 s) → no prompt.',
 'Immediately after an error, remove the item (1 s), re-present it, and provide a full vocal model. Reinforce the imitated response; on the next trial, use a partial model.',
 'Once 5 items reach criterion in structured trials, probe tacting in naturalistic settings (e.g., "what''s that?" during play or snack) with the same items.',
 'CRF: immediate social praise plus access to the named item (if appropriate) for every correct tact.',
 'Generalize each item across at least 3 different exemplars (e.g., 3 different balls), 2 settings, and 2 different instructors.',
 'Probe all 5 mastered tacts weekly using novel exemplars; re-introduce structured trials for any item falling below 80% correct.'),

('TAC-2', 'Tact',
 'Use a rotating probe list of all 10 items, 2 opportunities per item per session. Criterion: 10 items tacted correctly across multiple settings and communication partners on 80% of probes.',
 'TAC-1 (5 tacts mastered); ability to attend to novel objects; basic generalization of labels across at least 2 exemplars per item.',
 'Ten familiar objects from at least 3 categories; multiple exemplars of each object; 2 different settings prepared for generalization probes.',
 'Present each of the 10 items across different settings and with different instructors. Use a naturalistic "what''s that?" format during ongoing activities as well as structured probes.',
 'Child correctly labels all 10 items without prompts, achieving 80% or greater accuracy across multiple settings and at least 2 different communication partners.',
 'Correct label only in the structured therapy room, correct label with only one instructor, or falling below 80% with novel exemplars.',
 'most_to_least',
 'Partial model → time-delay → no prompt. Move to no-prompt condition as soon as 3 consecutive correct responses are recorded.',
 'For items failing to generalize, return to structured teaching with new exemplars; use multiple exemplar training to build generalization.',
 'After reaching criterion, add 5 new items using the same procedure while probing maintenance of the original 10.',
 'FR-1 in new settings/with new partners; thin to VR-2 in familiar settings.',
 'Introduce all 10 items across at least 3 physical settings and 3 different adults within the data collection week.',
 'Bi-weekly maintenance probes of all mastered tacts; add new items at a pace of 3–5 per week once criterion is reached.'),

('TAC-3', 'Tact',
 'Record action tacts separately from item tacts using a frequency or percentage correct data sheet. Criterion: 2 different actions tacted correctly on 4 of 5 opportunities each across 2 sessions.',
 'TAC-2 (10 item tacts); basic verb vocabulary; ability to discriminate between an object and an action performed on or with an object.',
 'Person or puppet demonstrating actions (running, eating, jumping, clapping, sleeping); action pictures if live demonstration is not feasible; video clips of actions.',
 'Demonstrate an action live or show a picture/video of an action and ask "What is he/she doing?" or "What am I doing?" Wait 5 s for the child''s response.',
 'Child correctly labels at least 2 different actions (e.g., "running," "eating") when demonstrated, on 4 of 5 opportunities each across 2 consecutive sessions.',
 'Labeling the person or object involved rather than the action (e.g., "boy" instead of "running"), or not responding.',
 'most_to_least',
 'Full model of the action word → partial model ("run…") → time-delay → no prompt.',
 'After incorrect response, immediately model the correct action word, have child repeat it, then re-demonstrate the action and prompt with time-delay.',
 'Once 2 actions reach criterion, expand to a bank of 10 action words; integrate action tacting into ongoing play and daily routines.',
 'CRF for action tacts initially; thin to VR-2 once both actions are stable.',
 'Demonstrate actions across different people performing the action; use pictures, videos, and live demonstrations; test in different rooms.',
 'Monthly probe of all mastered action tacts using novel demonstrators and novel media (new pictures, new video clips).'),

('TAC-4', 'Tact',
 'Rotating probe across all 20 items, organized by category. Criterion: 20 or more items tacted across at least 4 different categories with 80% accuracy across 2 sessions.',
 'TAC-3 (action tacts); established item tact repertoire of at least 10 items; basic categorical knowledge (understanding that items belong to groups).',
 'Twenty objects or pictures spanning at least 4 categories (e.g., animals, foods, vehicles, clothing, furniture); category labels accessible for later categorization tasks.',
 'Present items one at a time from across categories. Ask "What is this?" Rotate through all 20 items within each session, ensuring representation from each category.',
 'Child correctly labels 20 or more different items from at least 4 different categories without prompts, achieving 80% or greater accuracy across 2 sessions.',
 'Correctly labeling only items from 1–2 categories, labeling fewer than 20 items, or requiring prompts for more than 20% of items.',
 'most_to_least',
 'Time-delay (5 s) as primary strategy for items in early acquisition; full model only for brand-new items.',
 'For items below 80%, implement errorless teaching using a within-stimulus prompt (color highlight on first letter) then fade.',
 'Begin introducing category labels once 20 items are mastered; connect to listener responding tasks.',
 'VR-2 for well-established items; CRF for items new to the probe list.',
 'Ensure at least 4 items per category and probe across at least 3 settings and 2 instructors.',
 'Maintain probe list; add 3–5 new items per week; track category distribution to ensure breadth.'),

('TAC-5', 'Tact',
 'Present pictures of all 20 target items and record correct/incorrect. Criterion: 80% or greater accuracy tacting items from pictures across 2 sessions.',
 'TAC-4 (20+ item tacts with objects); basic visual discrimination of 2D images; understanding that a picture represents a real object.',
 'Photographs and line drawings of all previously mastered items; picture flashcards; picture books; digital image displays on a tablet.',
 'Present photographs or line drawings of familiar items one at a time and ask "What is this?" Wait 5 s for child''s response.',
 'Child correctly labels items from photographs or pictures with 80% or greater accuracy, demonstrating that tacts generalize from 3D objects to 2D representations.',
 'Correctly naming the object only when the real object is present but failing on pictures, or providing categorical rather than specific labels.',
 'most_to_least',
 'Pair picture with real object initially → fade real object over trials → picture alone → time-delay with picture alone.',
 'For pictures below 80%, return to paired object+picture teaching; use a gradual fading procedure to transition from real object to picture.',
 'Expand to pictures of novel exemplars of mastered categories; introduce tacting from photographs of people, places, and events.',
 'VR-2 for established picture tacts; CRF for novel picture formats (new photographs of same item).',
 'Use pictures from books, magazines, the internet, and the child''s own photo library to maximize generalization.',
 'Monthly probe using novel photographs of mastered items; ensure generalization to different image styles (photo, line drawing, cartoon).'),

('TAC-6', 'Tact',
 'Probe 50 target items across sessions, 2 opportunities each. Criterion: 80% or greater accuracy across all 50 items without prompts over 3 consecutive sessions.',
 'TAC-5 (picture tacts); established vocabulary of at least 20–30 item tacts; ability to sustain attention across longer probe sessions.',
 'Fifty objects or pictures spanning multiple categories; organized probe list; rotating presentation order to prevent positional responding.',
 'Present each of the 50 items (objects or pictures) and ask "What is this?" Rotate items to prevent memorization of order. Probe across settings and with different instructors.',
 'Child correctly labels 50 or more different items across multiple categories without prompts, achieving 80% or greater accuracy across 3 consecutive sessions.',
 'Labeling fewer than 50 items correctly, requiring prompts on more than 20% of items, or correct only in the structured therapy room.',
 'most_to_least',
 'Time-delay (5 s) is primary; full model only for items newly added to the list.',
 'Group items below 80% into a "targeted for re-teaching" list; use errorless teaching then graduated time-delay for each.',
 'Once 50 items are at criterion, begin attribute tacting (TAC-7) using items from the established pool.',
 'VR-3 for established items; CRF for items just reaching criterion.',
 'Probe all 50 items across at least 3 settings and with at least 3 different adults across the data collection period.',
 'Monthly maintenance probe of all 50 items using novel exemplars; retire mastered items to a maintenance schedule as new items are added.'),

('TAC-7', 'Tact',
 'Record attribute tacts (color, size, shape) separately from object label tacts. Criterion: 5 different attribute tacts correct on 4 of 5 probes each across 2 sessions.',
 'TAC-6 (50+ item tacts); receptive knowledge of basic attributes; basic descriptive vocabulary in echoic or intraverbal contexts.',
 'Sets of items varying by single attributes (color swatches, size-graded objects, shape manipulatives); items from established tact vocabulary used as base objects.',
 'Present an item and ask "What color is it?", "What size is it?", or "What shape is it?" using established items. Vary the attribute question across trials.',
 'Child correctly tacts attributes including color (at least 5 colors), size (big/little, large/small), and shape (circle, square, triangle, rectangle) when asked about items.',
 'Providing the item label only when asked about an attribute, randomly guessing attributes, or requiring prompts for most attribute tacts.',
 'most_to_least',
 'Full model ("it''s red") → partial model ("it''s r…") → time-delay → no prompt.',
 'For attribute confusion (e.g., consistently labeling size when asked about color), use blocked practice on a single attribute type before mixing.',
 'Once 5 attribute types are established, combine attribute+noun tacting ("a big red ball") to prepare for expanded tacts.',
 'CRF for novel attribute-item combinations; VR-2 for well-established attribute-item pairs.',
 'Vary which attributes are probed with which items; test attributes in naturalistic descriptions during play and art activities.',
 'Weekly probe of attribute tacts using novel items; track whether attributes generalize to items not previously used in training.'),

('TAC-8', 'Tact',
 'Record action tacts from pictures specifically, using a percentage correct data sheet. Criterion: 10 different action labels tacted from pictures on 80% of opportunities across 2 sessions.',
 'TAC-7 (attribute tacts); TAC-3 (live action tacts); understanding that pictures depict ongoing actions; verb vocabulary of at least 10 words.',
 'Action pictures from picture books, flashcards, or printed photographs showing clear, unambiguous actions; at least 10 different action pictures.',
 'Present a picture showing a person or animal performing an action and ask "What is he/she doing?" or "What is happening in this picture?" Wait 5 s.',
 'Child correctly labels the action depicted in at least 10 different pictures using correct verb labels (e.g., "running," "eating," "jumping," "reading") with 80% or greater accuracy.',
 'Labeling the person or object rather than the action, using incorrect verb forms (e.g., "run" for "running" consistently), or not responding.',
 'most_to_least',
 'Point to the action in the picture → partial model → full model → no prompt. Fade pointing first, then verbal cues.',
 'For action pictures below 80%, return to live demonstration of the action paired with the picture; fade live model.',
 'Once 10 picture action tacts are mastered, expand to action pictures in story books and videos paused at action scenes.',
 'VR-2 for established action labels; CRF for novel action pictures of established actions.',
 'Use action pictures from varied sources: storybooks, magazines, photos of familiar people; probe with different instructors.',
 'Monthly probe using novel action pictures; track whether action vocabulary generalizes to new images without additional teaching.'),

('TAC-9', 'Tact',
 'Record location and preposition tacts, noting both the preposition used and the item pair. Criterion: 5 different prepositions tacted correctly on 4 of 5 opportunities each across 2 sessions.',
 'TAC-8 (action tacts from pictures); receptive understanding of at least 5 prepositions; basic spatial vocabulary.',
 'Common objects placed in varied spatial relationships (cup on/under/next to/in/behind a table); photographs of objects in different locations; books depicting spatial relationships.',
 'Physically arrange objects in a spatial relationship and ask "Where is the ball?" or "Where is the cup?" Alternate between live arrangements and pictures.',
 'Child correctly labels locations and prepositions (e.g., "on the table," "under the chair," "next to the box," "inside the bag") with 5 different prepositions at 80% accuracy.',
 'Using incorrect preposition (e.g., "on" for "under"), labeling the object without the location, or requiring prompts for most preposition tacts.',
 'most_to_least',
 'Demonstrate placement while modeling the preposition → partial model → time-delay → no prompt.',
 'For confused prepositions, implement blocked practice (practice "on" alone until 5 consecutive correct, then mix) before randomizing.',
 'Generalize preposition tacting to pictures in books and naturalistic environments; combine with listener responding for prepositions.',
 'CRF for novel preposition-object combinations; VR-2 for established combinations.',
 'Vary object pairs and locations; probe in different rooms and outdoor settings; include pictures from books.',
 'Monthly probe using novel object arrangements; check generalization to locations not specifically trained.'),

('TAC-10', 'Tact',
 'Record tacts of private events (emotions, physical states) using a frequency count noting the specific state tacted and the context. Criterion: 5 different private events tacted correctly across 3 sessions.',
 'TAC-9 (location/preposition tacts); basic emotion recognition in pictures; some awareness of internal states; early interoceptive awareness.',
 'Emotion picture cards; photographs of people displaying clear emotional expressions; physical state scenarios (running to create tiredness, not eating to create hunger); mirrors for self-observation.',
 'Present pictures of people with clear emotional expressions or create physical state conditions (after running: "how do you feel?") and ask "How does he/she feel?" or "How do you feel?"',
 'Child correctly tacts private events including at least 5 different emotions or physical states (e.g., happy, sad, angry, scared, hungry, tired) in pictures and in self-referential contexts.',
 'Labeling surface behavior instead of the emotion (e.g., "he''s crying" instead of "he''s sad"), or correctly labeling emotions in pictures but not in self-referential contexts.',
 'most_to_least',
 'Pair physical state with label during the experience → model the label → prompt with partial cue → no prompt.',
 'For confusions between similar emotions (e.g., sad vs. scared), use discrimination training with the two target pictures presented in an array.',
 'Begin connecting emotion tacting to self-advocacy and social interaction contexts; link to manding for comfort or help.',
 'CRF for private event tacts, especially self-referential ones; these are inherently naturalistic in application.',
 'Probe emotion tacting in storybooks, TV shows, real interactions, and self-referential contexts; involve caregivers in naturalistic probes.',
 'Monthly probe with novel emotion pictures and in-the-moment self-referential probes; track whether the child uses emotion vocabulary spontaneously.'),

('TAC-11', 'Tact',
 'Record function-based tacts, noting the item, the function stated, and the prompt level. Criterion: 10 different items tacted by function with 80% accuracy across 2 sessions.',
 'TAC-10 (private event tacts); established item tact vocabulary of 50+ items; basic feature-function-class knowledge in listener responding context.',
 'Common objects with clear functions; picture cards of items and their uses; functional use scenarios (demonstrate using scissors to cut).',
 'Present an item and ask "What is it used for?" or "What do you do with it?" Alternatively, describe the function and ask "What is it?" to check the reverse relation.',
 'Child correctly tacts items by their function (e.g., "you use it to cut," "you write with it," "you eat with it") for at least 10 different items at 80% accuracy.',
 'Providing the item label without the function, providing a functionally incorrect description, or requiring prompts for most items.',
 'most_to_least',
 'Demonstrate the function while modeling the description → partial model → time-delay → no prompt.',
 'For items below 80%, pair the function description with a live demonstration; repeat until the function is established before testing with time-delay.',
 'Connect function tacts to listener responding by function (TAC-11 and LR-12 teach the same concept from different directions); integrate into conversation.',
 'VR-2 for established function tacts; CRF for novel items.',
 'Probe function tacts across at least 10 different items from varied categories; include items found at home, school, and community settings.',
 'Monthly probe using novel items; assess whether child spontaneously provides function information when tacting items in conversation.'),

('TAC-12', 'Tact',
 'Weekly vocabulary count of all spontaneous tacts across all settings using communication logs from all partners. Criterion: 200 or more unique tact labels documented over a 2-week period.',
 'TAC-11 (function-based tacts); sentence-level tacting emerging; tacting generalized across all settings; broad vocabulary across multiple domains.',
 'Full naturalistic environments; tact vocabulary log shared with all communication partners; books, magazines, outings, and varied activities to stimulate diverse tacting.',
 'Across all natural environments and activities, prompt caregivers and staff to ask "what''s that?" in novel contexts. Document all spontaneous tacts as they occur. No structured trial format required.',
 'Child spontaneously labels 200 or more different items, actions, events, and attributes across all natural settings, with labels documented over a 2-week period.',
 'Tacting fewer than 200 unique items, tacting only in structured sessions, or requiring prompts for the majority of labels.',
 'most_to_least',
 'Environmental enrichment (outings, novel activities, picture books) serves as the primary stimulus for new tacts; time-delay for items not in current vocabulary.',
 'For any item falling below 80% in naturalistic probes, add it to structured teaching to bring to mastery before re-testing naturalistically.',
 'Begin targeting expanded tacts (attributes + category + function in a single utterance); connect to intraverbal and conversational skill building.',
 'VR-3 for established tacts; social praise and conversational continuation as natural reinforcers.',
 'Document tacts across home, school, community, and recreational settings; ensure vocabulary spans all major semantic categories.',
 'Monthly review of vocabulary log; track rate of new tact emergence; conduct novel environment probes (e.g., a zoo visit) to assess generalization to untrained settings.'),

('TAC-13', 'Tact',
 'Record category and subcategory tacts, noting the level of categorization provided. Criterion: 10 different category labels used correctly when items are presented across 2 sessions.',
 'TAC-12 (200+ tacts); basic categorization skills; understanding of hierarchical category relationships (animal → dog); receptive category knowledge.',
 'Items and pictures from multiple categories; category sorting activities; Venn diagram-style visual supports for subcategory relationships.',
 'Present an item or group of items and ask "What kind of thing is this?" or "What group does this belong to?" Probe both basic category ("it''s an animal") and subcategory ("it''s a mammal") levels.',
 'Child correctly provides category and subcategory labels when items are presented (e.g., "it''s a fruit—it''s a citrus fruit," "it''s a vehicle—it''s a truck") for at least 10 different category levels.',
 'Providing only the specific item label without the category, reversing category and subcategory labels, or requiring prompts for categorical tacting.',
 'most_to_least',
 'Explicitly teach category membership using sorting tasks → model category label → use time-delay → no prompt.',
 'For category confusions, use blocked practice by category (teach all animals before mixing with vehicles) then randomize.',
 'Connect to intraverbal tasks where the child must name members of a category; expand to hierarchical category discussions.',
 'VR-2 for established category tacts; CRF for new category-level distinctions.',
 'Probe across at least 10 different categories spanning biological and human-made domains; include subcategories within at least 3 categories.',
 'Monthly probe using novel items from established categories; track whether category tacting generalizes to items not specifically trained.'),

('TAC-14', 'Tact',
 'Record tacts of environmental events and sequences, noting the specificity and accuracy of the response. Criterion: 5 different environmental events or sequences tacted correctly across 2 sessions.',
 'TAC-13 (category tacts); temporal and sequential language; understanding of cause-effect relationships in the environment; basic narrative language.',
 'Visual schedules; seasonal pictures; weather charts; pictures of daily routines in sequence; photographs of familiar events (birthday party, school day steps).',
 'Present a sequential picture series, a visual schedule, or an environmental condition (e.g., weather outside) and ask "What is happening?" or "What comes next?" or "What season is it?"',
 'Child correctly tacts environmental events (seasons, weather, time of day) and sequences (steps in a routine, order of a picture story) for at least 5 different events or sequences.',
 'Labeling only a single image without the sequence or context, providing a label for only one element of a multi-step sequence, or requiring prompts for most responses.',
 'most_to_least',
 'Use visual sequences as embedded prompts → model the narrative or event label → partial model → time-delay → no prompt.',
 'For sequences with errors, re-teach the specific step that is incorrect using errorless teaching, then re-probe the full sequence.',
 'Connect environmental event tacting to narrative language and conversational topic maintenance; begin building story-telling skills.',
 'VR-2 for established events; CRF for novel environmental events or new sequences.',
 'Probe across seasons, weather types, daily routine sequences, and community event sequences; involve caregivers in documenting home-based tacting of events.',
 'Monthly probe across different environmental events; check seasonal knowledge at appropriate times of year.'),

('TAC-15', 'Tact',
 'Record novel stimulus tacts, noting whether the label was previously trained or was a generalized novel use of an established label. Criterion: 5 instances of appropriate labeling of novel untrained stimuli across 3 different sessions.',
 'TAC-14 (environmental event tacts); broad tact vocabulary of 200+ items; category and feature knowledge; analogical reasoning emerging.',
 'Novel objects the child has never been specifically taught to label; items from broader categories of established vocabulary; unusual exemplars of known categories.',
 'Present a novel item from a known category or a novel exemplar of a trained category and ask "What is that?" without providing any prompting or prior teaching of that specific item.',
 'Child appropriately labels novel stimuli using generalized category labels, descriptive labels, or correctly generalizes an established label to a new exemplar (e.g., labeling a novel breed of dog as "dog").',
 'Refusing to label novel items, providing a completely unrelated label, or requiring extensive prompting before labeling novel stimuli.',
 'most_to_least',
 'Primary strategy is no prompt—the criterion is spontaneous generalization; if the child refuses, a hint about the category may be offered but is not counted as criterion.',
 'For failures to generalize, implement multiple exemplar training with varied examples of the category until the child begins to generalize labels spontaneously.',
 'Track emergence of label generalization across categories; use novel item probes in naturalistic settings (community outings, new environments).',
 'Social reinforcement (enthusiastic confirmation: "Yes! That is a kind of dog!") is the natural reinforcer for generalized tacts.',
 'Systematically introduce novel items from all established categories; vary the typicality of items (typical vs. atypical exemplars).',
 'Monthly novel stimulus probes; track generalization rate across categories; use as an indicator of conceptual vocabulary strength.')
ON CONFLICT (milestone_code) DO UPDATE
SET vbmapp_domain = EXCLUDED.vbmapp_domain,
    data_collection = EXCLUDED.data_collection,
    prerequisite_skills = EXCLUDED.prerequisite_skills,
    materials = EXCLUDED.materials,
    sd = EXCLUDED.sd,
    correct_responses = EXCLUDED.correct_responses,
    incorrect_responses = EXCLUDED.incorrect_responses,
    prompting_hierarchy = EXCLUDED.prompting_hierarchy,
    prompting_hierarchy_detail = EXCLUDED.prompting_hierarchy_detail,
    error_correction = EXCLUDED.error_correction,
    transfer_procedure = EXCLUDED.transfer_procedure,
    reinforcement_schedule = EXCLUDED.reinforcement_schedule,
    generalization_plan = EXCLUDED.generalization_plan,
    maintenance_plan = EXCLUDED.maintenance_plan,
    template_origin = EXCLUDED.template_origin;

-- ============================================================
-- LISTENER RESPONDING (LR-1 through LR-15)
-- ============================================================

INSERT INTO vbmapp_milestone_templates (milestone_code, vbmapp_domain, data_collection, prerequisite_skills, materials, sd, correct_responses, incorrect_responses, prompting_hierarchy, prompting_hierarchy_detail, error_correction, transfer_procedure, reinforcement_schedule, generalization_plan, maintenance_plan) VALUES
('LR-1', 'Listener Responding', 'Record C/I/P per trial from 2-item array. Criterion: 90%+ across 3 consecutive sessions.', 'Basic visual attention to objects; tolerates items on table.', '2 common objects per trial (cup, ball, shoe); preferred reinforcers.', 'Place 2 items on table. Say "Touch [item]" once. Randomize positions every trial.', 'Child touches correct item from array of 2 within 5 s, independently.', 'Touches wrong item, no response in 5 s, or requires repeated SD.', 'most_to_least', '1. Full physical (hand-over-hand) > 2. Partial physical > 3. Gestural > 4. Independent.', 'Remove items; pause 3 s; re-present with physical guidance; reinforce; 1 known trial; re-probe.', 'Increase array to 3 once 90% stable. Rotate pairs to prevent position habits.', 'CRF during acquisition; thin to VR2 after mastery.', 'Generalize across 3+ adults and 2+ settings. Vary object exemplars.', 'Monthly probes with novel items. Re-teach if below 80% for 2 consecutive probes.'),
('LR-2', 'Listener Responding', 'Record + or - per instruction trial. Criterion: 90%+ across 3 sessions for 5 different instructions.', 'LR-1 (selects from 2-item array); responds to name 50%+; basic sitting tolerance.', 'Open space; common instructions: sit, stand, come here, clap, arms up.', 'Give one-step instruction once ("Sit down"). Wait 5 s. No gesture or repetition.', 'Child performs correct action within 5 s across 5 different one-step instructions without prompts.', 'Wrong action, no response in 5 s, or echoes instruction without acting.', 'most_to_least', '1. Full physical (guide through action) > 2. Model action > 3. Independent.', 'Model action; physically guide if needed; reinforce; easy known instruction; re-probe.', 'Once 5 instructions mastered in structured setting, introduce in natural contexts.', 'CRF for each correct independent response. Thin to VR2 once all 5 instructions stable.', 'Rotate instructors and settings. Test instructions from different positions in the room.', 'Monthly probe with novel phrasing of same 5 instructions. Embed in daily transitions.'),
('LR-3', 'Listener Responding', 'Record C/I/P per trial from 3-item array. Criterion: 90%+ across 3 consecutive sessions.', 'LR-1 (array of 2 at 90%+); LR-2 (5 one-step instructions).', '3 distinct objects per trial; varied across trials; preferred reinforcers.', 'Place 3 items on table. "Touch [item]" once. Randomize target position each trial.', 'Child touches correct item from array of 3 within 5 s, independently, across multiple named items.', 'Touches wrong item, no response, requires gesture, or scrolls through all items.', 'most_to_least', '1. Gestural (point after SD) > 2. Positional cue (target closest) > 3. Independent.', 'Remove array; pause; re-present with gestural prompt; known trial; re-probe.', 'Expand to 4-item array once criterion met. Mix new items with mastered items.', 'CRF > VR2 after mastery. Shift from tangible toward praise only.', 'Generalize across 3+ object categories, 2+ settings, 3+ adults. Novel exemplars monthly.', 'Monthly probe with novel items. Maintain 90% criterion.'),
('LR-4', 'Listener Responding', 'Record + or - per instruction trial across 10 targets. Criterion: 90%+ across 3 sessions.', 'LR-2 (5 one-step instructions at 90%+); LR-3 (array of 3).', 'Varied environmental props for each instruction type; open classroom or therapy space.', 'Deliver one-step instruction once in natural tone. Vary across all 10 targets each session.', 'Child follows 10 different one-step instructions across varied settings and 2+ adults, 90%+.', 'Wrong action, no response, requires repeated instruction, or only partial response.', 'most_to_least', '1. Model action > 2. Gestural cue > 3. Independent.', 'Model action; physically guide if needed; easy known instruction; re-probe target.', 'Rotate all 10 instructions across sessions. Introduce in multiple settings and with different adults.', 'CRF per new instruction during acquisition; VR2 once all 10 stable.', 'Test in home, clinic, classroom, community. Vary phrasing slightly.', 'Monthly probe of all 10 instructions. Embed in daily transition routines.'),
('LR-5', 'Listener Responding', 'Record latency and orientation per name-call trial. Criterion: 90%+ orientation within 5 s across 3 sessions.', 'Basic auditory awareness; some history of responding to voice.', 'Natural settings where child is engaged in preferred activity. No specific materials.', 'Call child name once at natural volume from 3-10 feet while child is engaged in preferred activity.', 'Child stops current activity and orients toward speaker within 5 seconds.', 'No orientation within 5 s, continues ignoring, or orients in wrong direction.', 'least_to_most', '1. Call name > wait 5 s > 2. Light tap on shoulder > 3. Move into visual field. Fade physical cues.', 'Move into visual field; call name; when child orients, reinforce immediately and enthusiastically.', 'Pair name-call with highly preferred reinforcer. Practice across rooms, activities, noise levels.', 'Enthusiastic social reinforcement (big smile, praise) immediately upon orientation.', 'Practice at varied noise levels, distances, activity contexts across all adults.', 'Monthly probes in naturalistic contexts throughout all daily environments.'),
('LR-6', 'Listener Responding', 'Record C/I/P per 2-step instruction trial. Criterion: 80%+ across 3 sessions without gestural/physical prompts.', 'LR-4 (10 one-step instructions at 90%+); basic working memory for 2 sequential steps.', 'Familiar classroom/home materials for 2-step chains (backpack, lunch box, shelf).', 'Give 2-step instruction once clearly. Wait 10 seconds. Do NOT repeat or gesture.', 'Child completes both steps in correct sequence within 10 s, without gestural or physical prompts.', 'Completes only 1 step, reverses steps, requires prompt, or stops after first step.', 'most_to_least', '1. Gestural cue for step 2 after step 1 done > 2. Verbal prompt for step 2 only > 3. Independent.', 'If step 2 missed, brief verbal reminder; reinforce completion; do not repeat full instruction.', 'Begin with chains where step 1 naturally leads to step 2. Gradually use unrelated pairs.', 'CRF for complete 2-step sequences. Thin to VR2 once reliable.', 'Practice in all environments. Vary first and second steps to prevent rote chains.', 'Monthly probes with novel 2-step combinations. Embed in morning routines and transitions.'),
('LR-7', 'Listener Responding', 'Record C/I/P per trial from varied arrays. Criterion: 90%+ across 3 sessions for 25 different named items.', 'LR-3 (array of 3 at 90%+); tact vocabulary growing; 10+ items already mastered.', 'Arrays of 4-6 pictures or objects organized by category; varied item pools.', '"Touch [item]" from array of 4+. Rotate target items and array composition every trial.', 'Child selects correct item when named, across a repertoire of 25+ items, from arrays of 4+.', 'Selects wrong item, requires prompt, or responds to items only in fixed array positions.', 'most_to_least', '1. Gestural (point to correct item) > 2. Position cue (target first) > 3. Independent. Increase array size as skill grows.', 'Remove array; pause; re-present with gestural prompt; easy known item; re-probe target.', 'Increase array size and reduce redundancy between distractors. Begin grouping items by category.', 'CRF per correct response during expansion; VR2-VR3 once 25 items stable.', 'Vary array composition, object exemplars, and settings. Include novel exemplars monthly.', 'Monthly maintenance probes across all 25 items. Track items below 80%; re-teach.'),
('LR-8', 'Listener Responding', 'Record C/I/P per body part trial. Criterion: 90%+ across 3 sessions for 8+ body parts.', 'LR-4 (10 one-step instructions); tolerates touch; basic body awareness.', 'No materials required; child seated or standing. Mirror optional.', '"Touch your [body part]" or "Show me your [body part]." Child responds on own body.', 'Child touches named body part on self within 5 seconds across 8+ body parts, independently.', 'Touches wrong body part, touches on another person instead of self, or no response.', 'most_to_least', '1. Full physical (guide hand) > 2. Partial physical > 3. Model on own body > 4. Independent.', 'Guide hand to correct part; reinforce; easy known body part; re-probe target.', 'Expand from high-salience parts (nose, ears) to less salient (elbow, ankle). Embed in songs.', 'CRF per new body part. Thin to VR2 across all mastered parts.', 'Generalize to body parts on pictures, dolls, and peers. Practice in multiple settings.', 'Monthly probes across all mastered body parts. Add novel body parts gradually.'),
('LR-9', 'Listener Responding', 'Record + or - per identification trial. Criterion: 90%+ across 3 sessions for 5+ named people.', 'LR-5 (responds to name); LR-7 (25+ items); familiarity with target people.', 'Photos of familiar people (parents, siblings, teachers) in photo array of 3-5 pictures.', '"Show me [name]" or "Where is [Mom/teacher]?" from photo array or natural group.', 'Child correctly identifies familiar people by name or relationship across 5+ people.', 'Points to wrong person, no response, or identifies only 1-2 people reliably.', 'most_to_least', '1. Gestural (point to correct photo) > 2. Positional prompt (target closest) > 3. Independent.', 'Point to correct photo; name person; re-present SD; reinforce correct independent response.', 'Begin with parent photos, expand to siblings and teachers. Move from photos to in-person ID.', 'Enthusiastic social reinforcement. Use emotionally salient people to maintain motivation.', 'Generalize to varied photos of same people (different clothing, angles). In-person ID in groups.', 'Monthly probes with new photo exemplars. Update arrays as social circle expands.'),
('LR-10', 'Listener Responding', 'Record C/I/P per prepositional instruction trial. Criterion: 80%+ across 3 sessions for 5+ prepositions.', 'LR-6 (2-step instructions); basic object manipulation; spatial awareness emerging.', 'Common objects and containers: box, cup, chair, book. Used for on, under, in, next to, behind.', '"Put the [object] [preposition] the [location]." One instruction per trial.', 'Child places object in correct spatial location within 5 seconds, for 5+ different prepositions.', 'Places in wrong location, confuses prepositions, no response, or requires gestural prompt.', 'most_to_least', '1. Gestural (point to correct location after SD) > 2. Model correct placement > 3. Independent.', 'Model correct placement; guide child to replicate; reinforce; easy known preposition; re-probe.', 'Begin with on/in, then under/next to, then behind/in front of/between. Pair with tact training.', 'CRF per new preposition. Thin to VR2 once all targets stable.', 'Generalize across multiple objects and containers. Practice at snack, play, dressing routines.', 'Monthly probes with novel object-location combinations. Embed in daily routines.'),
('LR-11', 'Listener Responding', 'Record C/I/P per 3-step instruction trial. Criterion: 80%+ across 3 sessions.', 'LR-6 (2-step instructions at 80%+); working memory for 3 steps; LR-10 (prepositions).', 'Natural classroom or home materials for 3-step chains. No written supports.', 'Give 3-step instruction once at normal pace. Wait 15 seconds. Do not repeat.', 'Child completes all 3 steps in correct sequence without visual supports or repeated instructions.', 'Skips a step, reverses steps, requires prompt, or stops after step 2.', 'most_to_least', '1. Verbal reminder for step 3 only > 2. Visual 3-icon card (then fade) > 3. Independent.', 'Prompt the specific missed step only; do not restart full sequence; reinforce completion.', 'Begin with routine 3-step chains. Progress to novel non-routine sequences.', 'CRF for complete 3-step execution. VR2 once reliable. Natural activity completion as reinforcement.', 'Vary sequences and step combinations. Test in novel settings.', 'Monthly probes with novel 3-step combinations. Track which step position is most error-prone.'),
('LR-12', 'Listener Responding', 'Record C/I/P per LRFFC-style verbal description trial. Criterion: 90%+ across 3 sessions for 20+ items.', 'LR-7 (25+ items by name); basic category and function knowledge; tact repertoire of 50+.', 'Arrays of 4-6 pictures or objects across categories. No item name used in SD.', '"Find something that flies" / "Show me what you cut with." One description per trial.', 'Child selects correct item from array based on function, feature, or class, without item name in SD.', 'Selects wrong item, requires item name prompt, selects by position, or no response.', 'most_to_least', '1. Gestural (point to correct item) > 2. Partial description repeat > 3. Independent.', 'Point to correct item; explain relevance; re-probe after a known trial.', 'Rotate between function, feature, class SDs for same items. Increase distractors as skill develops.', 'CRF during acquisition; VR2 once 20 items mastered.', 'Generalize to novel items within trained categories. Practice in naturalistic contexts.', 'Monthly probes with novel items in each category. Maintain all 3 descriptor types.'),
('LR-13', 'Listener Responding', 'Record accuracy per session across 100-item rotating probe. Criterion: 90%+ across 3 sessions.', 'LR-7 (25 items); LR-12 (LRFFC style); broad receptive vocabulary across all prior levels.', 'Large rotating pools of picture cards across 10+ categories; arrays of 4-8 items.', '"Show me [item name]" from rotating array. Use all 100 items across multiple sessions.', 'Child accurately selects from pool of 100+ named items from arrays of 4-8.', 'Errors on previously mastered items; position-based responding; requires prompt.', 'most_to_least', '1. Gestural for individual missed items > 2. Independent. Most items at maintenance level.', 'Re-teach individual items below 80%; focused acquisition block for those items only.', 'Rotate arrays to prevent position learning. All 100 items probed at least once per month.', 'VR3 for bulk of repertoire; CRF for newly added items. Social praise as primary reinforcer.', 'Generalize to novel exemplars of all categories. Test in naturalistic settings with unfamiliar adults.', 'Monthly 20-item rotating probe sampling across all 100 items. Re-teach items below 80%.'),
('LR-14', 'Listener Responding', 'Record C/I/P per conditional instruction trial. Criterion: 80%+ across 3 sessions.', 'LR-11 (3-step instructions); LR-12 (LRFFC); basic conditional reasoning emerging.', 'Sets of items with varied attributes: colored blocks, objects of different sizes.', '"If it is red, give it to me. If it is blue, put it in the box." One conditional instruction per trial.', 'Child correctly executes conditional action based on stated condition without prompting.', 'Ignores condition and performs one action for all items, or confuses the two outcomes.', 'most_to_least', '1. Gestural (highlight condition-matching item) > 2. Verbal reminder of condition > 3. Independent.', 'Point to condition-matching item; re-state condition; re-present instruction; reinforce.', 'Begin with binary color conditions. Progress to size, shape, multi-attribute conditions.', 'CRF during acquisition of each condition type. VR2 once reliable across 3+ condition pairs.', 'Vary attributes (color > size > shape > category). Generalize to naturalistic conditional instructions.', 'Monthly probes with novel condition types. Maintain all previously trained condition pairs.'),
('LR-15', 'Listener Responding', 'Record C/I/P per complex sentence trial. Criterion: 80%+ across 3 sessions.', 'LR-14 (conditional instructions); advanced listener responding repertoire across all prior levels.', 'Objects and pictures for comprehension tasks; short verbal scenarios read aloud.', 'Read complex sentence once: "The dog that is in the yard is brown - show me the brown dog."', 'Child correctly responds to target meaning of complex sentence with embedded clause, without extra explanation.', 'Responds to only part of sentence, acts on simpler interpretation, or requires simplification.', 'most_to_least', '1. Gestural cue to target element > 2. Restatement of embedded clause only > 3. Independent.', 'Restate embedded clause; point to target; re-present full sentence; reinforce correct response.', 'Begin with subject-relative clauses before object-relative clauses. Scaffold complexity gradually.', 'CRF per structure type during acquisition. VR2 once reliable.', 'Generalize to novel sentences with same grammatical structures. Practice in story comprehension.', 'Monthly probes with novel complex sentences. Track error patterns by sentence type.')
ON CONFLICT (milestone_code) DO UPDATE
SET vbmapp_domain = EXCLUDED.vbmapp_domain,
    data_collection = EXCLUDED.data_collection,
    prerequisite_skills = EXCLUDED.prerequisite_skills,
    materials = EXCLUDED.materials,
    sd = EXCLUDED.sd,
    correct_responses = EXCLUDED.correct_responses,
    incorrect_responses = EXCLUDED.incorrect_responses,
    prompting_hierarchy = EXCLUDED.prompting_hierarchy,
    prompting_hierarchy_detail = EXCLUDED.prompting_hierarchy_detail,
    error_correction = EXCLUDED.error_correction,
    transfer_procedure = EXCLUDED.transfer_procedure,
    reinforcement_schedule = EXCLUDED.reinforcement_schedule,
    generalization_plan = EXCLUDED.generalization_plan,
    maintenance_plan = EXCLUDED.maintenance_plan,
    template_origin = EXCLUDED.template_origin;

-- ============================================================
-- VP/MTS (VP-1 through VP-15)
-- ============================================================

INSERT INTO vbmapp_milestone_templates (milestone_code, vbmapp_domain, data_collection, prerequisite_skills, materials, sd, correct_responses, incorrect_responses, prompting_hierarchy, prompting_hierarchy_detail, error_correction, transfer_procedure, reinforcement_schedule, generalization_plan, maintenance_plan) VALUES
('VP-1', 'VP/MTS', 'Record C/I/P per matching trial. Criterion: 90%+ across 3 sessions.', 'Basic visual attention to objects; reaches/grasps objects; basic sitting tolerance.', 'Sets of identical 3D objects (2 cups, 2 cars, 2 balls); table surface.', 'Present sample object. Place 2-3 identical and non-identical objects. "Match" or "Put with same."', 'Child independently selects or places the identical 3D object to the sample within 5 seconds.', 'Selects non-matching object, no response, or requires physical prompt.', 'most_to_least', '1. Full physical (hand-over-hand placement) > 2. Partial physical > 3. Gestural (point) > 4. Independent.', 'Remove materials; pause; re-present with physical guidance to correct match; reinforce.', 'Progress to non-identical same-category objects once identical 3D matching is 90%+.', 'CRF during acquisition; VR2 after mastery. Tangible + social praise.', 'Generalize matching across multiple exemplars of each category. Include matching in daily routines.', 'Monthly probes across all mastered matching sets. Embed in classroom and home activities.'),
('VP-2', 'VP/MTS', 'Record C/I/P per 2D matching trial. Criterion: 90%+ across 3 sessions.', 'VP-1 (identical 3D objects at 90%+); adequate visual scanning of 2D stimuli.', 'Matching picture card sets (identical pictures of animals, objects, shapes).Present sample picture card. Place 2-3 identical and non-identical cards. Match.', 'Child independently selects the identical picture card to the sample within 5 seconds.', 'Selects non-matching picture, no response, or requires prompt.', 'most_to_least', '1. Full physical > 2. Gestural (point to correct card) > 3. Independent.', 'Remove cards; pause; re-present with gestural prompt; reinforce; re-probe.', 'Once 2D identical matching is 90%+, introduce picture-to-object matching.', 'CRF during acquisition; VR2 after mastery.', 'Generalize across different picture styles (photos, drawings, cartoon). Vary card sizes.', 'Monthly probes. Progress to non-identical picture matching once criterion met.'),
('VP-3', 'VP/MTS', 'Record C/I/P per cross-modal matching trial. Criterion: 90%+ across 3 sessions for 5+ items.', 'VP-1 (3D objects at 90%+); VP-2 (2D pictures at 90%+); visual scanning of both modalities.', 'Sets of 5 objects paired with corresponding picture cards (cup + cup photo, ball + ball photo).', 'Present 3D object as sample; place 3-4 picture cards as array. "Match." Reverse direction each session.', 'Child matches 3D object to corresponding 2D picture (and vice versa) across 5+ items independently.', 'Matches to non-corresponding picture, no response, or requires prompt.', 'most_to_least', '1. Gestural (point to correct picture) > 2. Positional cue (place correct picture closest) > 3. Independent.', 'Remove array; pause; gestural prompt to correct picture; reinforce; known item; re-probe.', 'Expand to 8-10 items once 5 items mastered. Begin mixing object-to-picture and picture-to-object directions.', 'CRF during acquisition; VR2 after mastery.', 'Vary object exemplars and picture styles. Generalize across 3+ adults and settings.', 'Monthly probes across all 5+ items. Track accuracy in both matching directions.'),
('VP-4', 'VP/MTS', 'Record C/I/P per sorting trial. Criterion: 90%+ across 3 sessions for 2-category sorts.', 'VP-2 (2D matching at 90%+); basic categorization exposure; fine motor skills for placing objects.', 'Sets of objects/pictures from 2 distinct categories (animals vs. vehicles; food vs. toys); 2 containers or mats.', 'Place 2 sorting containers/mats. Present items one at a time. "Sort" or "Where does it go?"', 'Child independently places each item into the correct category container across 2 distinct categories.', 'Places in wrong category, no response, or requires prompt for each item.', 'most_to_least', '1. Gestural (point to correct container) > 2. Model first item sorting > 3. Independent.', 'Point to correct container; guide child to place correctly; reinforce; easy known item; re-probe.', 'Once 2-category sort mastered, expand to 3 categories. Begin with maximally distinct categories.', 'CRF per correct sort during acquisition; VR2-VR3 once both categories stable.', 'Generalize to novel category members. Practice sorting in functional contexts (laundry, toys).', 'Monthly probes with novel items in each category. Expand to 3-5 category sorts over time.'),
('VP-5', 'VP/MTS', 'Record C/I/P per color-matching trial. Criterion: 90%+ across 3 sessions for 5+ colors.', 'VP-2 (2D matching at 90%+); VP-4 (sorting into 2 categories); visual discrimination of hue.', 'Color chips, colored blocks, or colored picture cards in red, blue, green, yellow, orange.', 'Present color sample; place array of 5 different colors. "Match" or "Find the same color."', 'Child matches colors across 5+ different color categories independently within 5 seconds.', 'Matches wrong color, no response, or confuses similar colors (e.g., blue/purple).', 'most_to_least', '1. Gestural (point to correct color) > 2. Positional cue > 3. Independent.', 'Remove array; pause; gestural prompt; reinforce; easy known color; re-probe.', 'Progress to color sorting by category once 5 colors mastered. Connect to tact training for color names.', 'CRF during acquisition; VR2 after mastery.', 'Generalize color matching to varied objects and materials (crayons, clothing, blocks, food).', 'Monthly probes across all 5+ colors. Add new colors (purple, orange, brown) as skill develops.'),
('VP-6', 'VP/MTS', 'Record C/I/P per puzzle completion attempt. Criterion: independent completion of 4-piece puzzle 90%+ across 3 sessions.', 'VP-3 (object-to-picture matching); VP-5 (color matching); fine motor skills for placing pieces.', '3-5 different 4-piece inset puzzles at varying complexity; puzzle rack or flat surface.', 'Place partially completed or empty puzzle frame. "Do the puzzle" or "Finish it." No model provided.', 'Child independently completes 4-piece puzzle correctly without prompting.', 'Attempts wrong piece placement, gives up, or requires physical guidance.', 'most_to_least', '1. Full physical (guide each piece placement) > 2. Partial physical > 3. Gestural (point to correct location) > 4. Independent.', 'Guide hand to correct piece or location; reinforce correct placement; continue to next piece.', 'Progress to 6-piece, then 8-piece puzzles. Rotate puzzle types to prevent memorization.', 'CRF for completion of full puzzle; provide praise throughout for each correct piece.', 'Generalize across multiple different puzzle types and themes. Use puzzles from different settings.', 'Monthly probe with a novel puzzle not previously practiced. Track completion time as fluency measure.'),
('VP-7', 'VP/MTS', 'Record C/I/P per non-identical matching trial. Criterion: 90%+ across 3 sessions for 10+ pairs.', 'VP-3 (object-to-picture matching at 90%+); category knowledge of common items; tact repertoire of 20+.', 'Arrays of functionally related but non-identical items (spoon + fork, shoe + boot, car + truck).', 'Present one item as sample; array of 3-4 non-identical but related items. "Match" or "Find one like this."', 'Child selects functionally or categorically related item from array matching the sample concept, not appearance.', 'Selects visually identical item (not the concept match), unrelated item, or requires prompt.', 'most_to_least', '1. Gestural (point to correct item) > 2. Model the relationship verbally > 3. Independent.', 'Point to correct item; explain relationship; re-present after a known trial; reinforce.', 'Begin with same-category non-identical pairs, then cross-category functional pairs. Build reasoning repertoire.', 'CRF during initial non-identical matching; VR2-VR3 once 10+ pairs mastered.', 'Generalize to novel pairs within trained categories. Include functional matching in daily activities.', 'Monthly probes with novel non-identical pairs. Ensure generalization across category types.'),
('VP-8', 'VP/MTS', 'Record C/I/P per sorting trial. Criterion: 90%+ across 3 sessions for 5 different categories.', 'VP-4 (2-category sort at 90%+); VP-7 (non-identical matching); category knowledge of 5+ distinct groups.', 'Items from 5 distinct categories (animals, vehicles, food, clothing, furniture); 5 sorting containers.', 'Present mixed set of 15-20 items one at a time or as a group. "Sort" or "Put them where they belong."', 'Child independently sorts items into 5 or more correct category groups without prompting.', 'Misplaces item, refuses to sort, or requires prompt for more than 20% of items.', 'most_to_least', '1. Model first item in each category > 2. Gestural (point to container) > 3. Independent.', 'Point to correct container for misplaced item; re-present; reinforce correct independent sort.', 'Expand from 5 categories to 8-10 as vocabulary grows. Include subcategory sorting.', 'CRF during acquisition of each new category; VR2-VR3 once 5 categories stable.', 'Generalize to novel items in each category. Sort in functional contexts (organizing toys, food).', 'Monthly probes with novel items across all categories. Track accuracy per category.'),
('VP-9', 'VP/MTS', 'Record C/I/P per letter/number matching trial. Criterion: 90%+ across 3 sessions for 10+ letters and 5+ numbers.', 'VP-3 (object-to-picture matching); VP-5 (color matching); adequate visual discrimination of symbols.', 'Alphabet and number matching cards or tiles; sample cards with printed letters/numbers.', 'Present sample printed letter or number; array of 3-5 printed symbols. "Match" or "Find the same."', 'Child matches printed letters and numbers to corresponding sample letters/numbers independently.', 'Matches wrong symbol, confuses visually similar letters (b/d, p/q), or requires prompt.', 'most_to_least', '1. Gestural (point to correct symbol) > 2. Positional cue > 3. Independent.', 'Remove array; pause; gestural prompt; reinforce; easy known symbol; re-probe.', 'Begin with maximally distinctive letters (A, B, T), then introduce visually similar pairs. Connect to reading curriculum.', 'CRF during acquisition; VR2 after mastery.', 'Generalize to varied fonts, sizes, and styles of the same letters/numbers.', 'Monthly probes across all trained symbols. Track error patterns for visually similar pairs.'),
('VP-10', 'VP/MTS', 'Record C/I/P per pattern completion trial. Criterion: 90%+ across 3 sessions for 5+ pattern types.', 'VP-8 (5-category sort); VP-9 (letter/number matching); basic sequential reasoning.', 'Pattern blocks, colored beads, or picture card sequences for AB, ABB, ABC patterns.', 'Present pattern with 3-4 repetitions and a gap. "What comes next?" or "Finish the pattern."', 'Child correctly identifies and extends or completes a repeating pattern in a visual sequence.', 'Selects wrong next element, breaks the pattern, or requires hint about the rule.', 'most_to_least', '1. Point to pattern elements one by one and verbalize rule > 2. Gestural to next position > 3. Independent.', 'Verbalize the pattern rule; point to where next element goes; reinforce correct selection; re-probe.', 'Begin with AB patterns (red-blue-red-blue), progress to ABB, ABC, ABBC patterns.', 'CRF during pattern acquisition; VR2 once 5+ pattern types mastered.', 'Generalize across different materials (colors, shapes, objects) and different pattern types.', 'Monthly probes with novel pattern types. Track complexity level achieved.'),
('VP-11', 'VP/MTS', 'Record C/I/P per puzzle completion. Criterion: independent completion of 10-piece puzzle 90%+ across 3 sessions.', 'VP-6 (4-piece puzzle at 90%+); VP-10 (pattern completion); fine motor skills for smaller puzzle pieces.', 'Multiple different 10-piece puzzles; varied themes; puzzle rack or flat surface.', 'Place empty puzzle frame with pieces available. "Do the puzzle." No model, no gestures.', 'Child independently completes 10+ piece puzzle correctly and without prompting, across different puzzle types.', 'Cannot complete without prompts, places pieces incorrectly, or quits before completion.', 'most_to_least', '1. Gestural (point to location for specific piece) > 2. Independent. Use only piece-specific prompts as needed.', 'Point to correct location for a specific misplaced piece; reinforce correct insertion; allow child to continue.', 'Progress from 10-piece to 15-piece to 20-piece puzzles. Rotate puzzle themes.', 'CRF for puzzle completion; praise throughout for persistence.', 'Probe across multiple novel puzzles. Track completion time for fluency monitoring.', 'Monthly probe with novel puzzle not previously practiced. Target completion without any prompts.'),
('VP-12', 'VP/MTS', 'Record C/I/P per multi-attribute matching trial. Criterion: 90%+ across 3 sessions for 10+ item-attribute pairs.', 'VP-10 (pattern completion); VP-8 (5-category sort); tact repertoire including attributes.', 'Arrays of items varying on 2 simultaneous attributes (red small circle, blue large square).', 'Present sample item with 2 attributes. Array of 4 items varying on attributes. "Match" or "Find the same one."', 'Child selects item that matches on both specified attributes simultaneously, not just one.', 'Matches on only one attribute (e.g., matches color but not size), or selects unrelated item.', 'most_to_least', '1. Verbalize both attributes while pointing to sample > 2. Gestural > 3. Independent.', 'Verbalize both attributes; point to sample; guide to correct match; re-probe independently.', 'Begin with 2 attributes that are easily discriminated (color + size). Progress to color + shape, then 3 attributes.', 'CRF during acquisition; VR2 once 10 item-attribute pairs mastered.', 'Vary attribute combinations and materials. Generalize to classroom sorting tasks.', 'Monthly probes with novel attribute combinations. Track accuracy per attribute pairing.'),
('VP-13', 'VP/MTS', 'Record C/I/P per missing element identification trial. Criterion: 90%+ across 3 sessions.', 'VP-12 (multi-attribute matching); VP-10 (pattern completion); analytical visual processing emerging.', 'Picture arrays with one element missing (incomplete face, pattern with gap, object with missing part).', 'Present incomplete visual array. "What is missing?" or "Find what is missing here."', 'Child correctly identifies the missing element in a visual array or incomplete pattern independently.', 'Identifies wrong element, cannot identify the absence, or requires verbal hints.', 'most_to_least', '1. Point to the location of the missing element > 2. Compare to complete version > 3. Independent.', 'Point to missing location; provide complete version for comparison; re-present incomplete array; reinforce.', 'Begin with obvious missing elements (missing wheel on car), progress to subtle omissions.', 'CRF during acquisition; VR2 once reliable across multiple array types.', 'Generalize to novel incomplete arrays across many categories and contexts.', 'Monthly probes with novel incomplete arrays. Track ability to identify both obvious and subtle omissions.'),
('VP-14', 'VP/MTS', 'Record C/I/P per sequence completion trial. Criterion: 90%+ across 3 sessions for 5+ sequence types.', 'VP-13 (missing elements); VP-10 (pattern completion); sequential and predictive reasoning.', 'Sequence cards showing 3-step visual progressions (seasonal changes, growth, cause-effect).', 'Present 3-step sequence with final step missing. "What comes next?" or "What happens next?"', 'Child correctly selects the next step in a visual sequence and explains the logic if asked.', 'Selects non-sequential item, reverses sequence, or cannot predict next step.', 'most_to_least', '1. Verbalize each prior step > 2. Gestural to correct next item > 3. Independent.', 'Verbalize prior steps; point to next location; reinforce correct selection; re-probe.', 'Begin with simple 3-step sequences; progress to 4-5 step sequences and more abstract progressions.', 'CRF during acquisition; VR2 once 5+ sequence types mastered.', 'Generalize to daily routine sequences and naturalistic cause-effect reasoning.', 'Monthly probes with novel sequence types. Track ability to verbalize the reasoning.'),
('VP-15', 'VP/MTS', 'Record C/I/P per complex categorization trial. Criterion: 80%+ across 3 sessions.', 'VP-12 (multi-attribute); VP-14 (sequence completion); advanced categorization and conceptual reasoning.', 'Sets of items that share some but not all features (items that can belong to multiple categories).', 'Present complex categorization task: "Sort these by which ones could be both a tool AND a toy." Or Venn-style tasks.', 'Child correctly categorizes items considering overlapping or shared features across 2+ categories.', 'Places all items in one category only, ignores shared features, or cannot manage overlap.', 'most_to_least', '1. Verbalize the overlapping property > 2. Model placement of one shared item > 3. Independent.', 'Explain the shared feature; model one placement; re-present task; reinforce correct categorization.', 'Begin with clear overlapping categories; progress to more abstract overlaps (living/non-living + can swim).', 'CRF during acquisition; VR2 once complex categorization is reliable.', 'Generalize to academic sorting tasks and conceptual classification in reading/science contexts.', 'Monthly probes with novel overlapping category sets. Track reasoning explanations as skill develops.')
ON CONFLICT (milestone_code) DO UPDATE
SET vbmapp_domain = EXCLUDED.vbmapp_domain,
    data_collection = EXCLUDED.data_collection,
    prerequisite_skills = EXCLUDED.prerequisite_skills,
    materials = EXCLUDED.materials,
    sd = EXCLUDED.sd,
    correct_responses = EXCLUDED.correct_responses,
    incorrect_responses = EXCLUDED.incorrect_responses,
    prompting_hierarchy = EXCLUDED.prompting_hierarchy,
    prompting_hierarchy_detail = EXCLUDED.prompting_hierarchy_detail,
    error_correction = EXCLUDED.error_correction,
    transfer_procedure = EXCLUDED.transfer_procedure,
    reinforcement_schedule = EXCLUDED.reinforcement_schedule,
    generalization_plan = EXCLUDED.generalization_plan,
    maintenance_plan = EXCLUDED.maintenance_plan,
    template_origin = EXCLUDED.template_origin;

-- ============================================================
-- INDEPENDENT PLAY (IP-1 through IP-15)
-- ============================================================

INSERT INTO vbmapp_milestone_templates (milestone_code, vbmapp_domain, data_collection, prerequisite_skills, materials, sd, correct_responses, incorrect_responses, prompting_hierarchy, prompting_hierarchy_detail, error_correction, transfer_procedure, reinforcement_schedule, generalization_plan, maintenance_plan) VALUES
('IP-1', 'Independent Play', 'Time-based: record duration of appropriate independent play in 30-min observation. Criterion: 30+ seconds continuous appropriate play across 3 observations.', 'Basic object manipulation; visual attention to objects 30+ seconds; some tolerance for non-adult attention.', '2-3 highly preferred cause-and-effect or manipulative toys (pop-up toy, stacking rings, simple vehicle).', 'Place preferred toys within reach. Withdraw adult attention. Observe silently for 30 seconds.', 'Child independently manipulates 2+ toys appropriately (functional use) for 30+ seconds without adult prompts.', 'Leaves toys, engages in self-stimulatory use, or repeatedly seeks adult attention within 30 seconds.', 'least_to_most', '1. No prompt (observe 30 s) > 2. Gestural (point to toy) > 3. Verbal ("Play with the ___") > 4. Model play then withdraw.', 'Brief neutral redirect toward toy; model appropriate play for 5 seconds; withdraw immediately.', 'Begin 30-second target; increase by 30 seconds every 3 sessions once criterion met.', 'Check-in reinforcement every 30 s initially (brief praise for continued play). Fade to end-of-play.', 'Generalize across 2+ toy types and 2+ settings. Fade adult proximity incrementally.', 'Monthly duration observations. Add new toys to maintain interest and breadth of play.'),
('IP-2', 'Independent Play', 'Record frequency count of different toys engaged appropriately per session. Criterion: 5 different toys at 90%+ across 3 sessions.', 'IP-1 (30+ seconds with 2 toys); expanding toy repertoire; preference assessment identifying 5+ toys.', '5+ different preferred toys representing varied play types (construction, art, vehicles, figures, books).', 'Rotate available toys. Withdraw adult. Observe for appropriate engagement. Note which toys used and for how long.', 'Child engages in appropriate play with 5+ different toys without prompts across the session.', 'Uses only 1-2 toys; engages in stereotyped/repetitive non-functional use; requires prompts to continue.', 'least_to_most', '1. No prompt > 2. Point to new toy > 3. Verbal prompt ("What else can you play with?") > 4. Model use then withdraw.', 'Brief redirect to another available toy; model appropriate use 5 s; withdraw; reinforce continued play.', 'Systematically introduce 1 new toy per week using modeling before independent probe.', 'Check-in reinforcement every 2-3 min. Thin to end-of-session reinforcement.', 'Generalize across 3+ settings (therapy room, home bedroom, classroom). Vary toy availability.', 'Monthly observation counting different toys engaged. Target expanding repertoire breadth.'),
('IP-3', 'Independent Play', 'Record whether 3-step play sequence is completed independently. Criterion: 90%+ across 3 sessions.', 'IP-2 (5 different toys); basic imitation of play sequences; 2-step instruction following.', 'Toys requiring a natural 3-step sequence (tea set: pour, stir, drink; blocks: select, stack, place figure on top).', 'Set up toy with materials available. Withdraw. Observe whether child initiates and completes 3-step sequence.', 'Child independently initiates and completes a 3-step play sequence with a toy without adult prompting.', 'Completes only 1-2 steps, does not initiate sequence, or requires adult to restart the sequence.', 'least_to_most', '1. No prompt > 2. Gestural to next step > 3. Verbal ("And then what?") > 4. Model step 3 and withdraw.', 'Prompt only the missed step; do not restart the full sequence; reinforce completion of full sequence.', 'Teach 1-2 different 3-step sequences per toy type. Rotate toys to build varied sequence repertoire.', 'CRF for completing full 3-step sequence. Praise throughout for each step.', 'Generalize 3-step sequences across multiple different toys and play themes.', 'Monthly probes with novel toy setups requiring 3-step sequences.'),
('IP-4', 'Independent Play', 'Time-based interval recording: mark on-task every 5 min across 30-min observation. Criterion: 3+ continuous minutes without interruption across 3 observations.', 'IP-3 (3-step play sequence); tolerance for sustained activity; some self-regulation skills.', 'Multiple preferred toys arranged in accessible play area. Adult withdraws to far end of room.', 'Set up play area. Withdraw. Begin timing from first independent toy contact. Note any interruptions.', 'Child plays appropriately with toys for 3+ continuous minutes without adult prompts or reinforcement delivery.', 'Stops before 3 minutes, seeks adult attention, engages in off-task behavior, or leaves play area.', 'least_to_most', '1. No prompt (full 3 min observation) > 2. Brief verbal from distance ("Good playing!") > 3. Move closer only if needed.', 'Brief, neutral redirect to play area from a distance. Avoid reinforcing off-task with attention.', 'Increase target duration from 2 min to 5 min by 1-min increments every 3 sessions.', 'End-of-session reinforcement for meeting duration target. Brief distance praise at the 2-min mark initially.', 'Generalize across 3+ settings with adult at varying distances (same room, adjacent room).', 'Monthly duration observations. Track longest continuous play bouts.'),
('IP-5', 'Independent Play', 'Record whether child independently selects and engages with preferred toy during unstructured free time. Criterion: independent toy selection and engagement 80%+ of free-time observations.', 'IP-4 (3+ min continuous play); toy preferences well-established; some autonomous decision-making.', '5-10 toys available and accessible in play area without adult arrangement cues.', 'Structure free-time period (10+ min). Observe whether child selects a toy and engages without adult direction.', 'Child independently selects a preferred toy and engages with it appropriately during free time without adult prompts.', 'Waits for adult direction, becomes dysregulated during free time, or engages only in self-stimulation.', 'least_to_most', '1. No prompt > 2. Environmental cue (point to play area) > 3. Verbal ("You have free time - what do you want to do?")', 'Brief neutral redirect toward play materials if child becomes dysregulated. Avoid directing choice.', 'Ensure play materials are accessible and visually organized to support independent selection.', 'Natural reinforcement (access to preferred toy) is primary. Minimal external reinforcer needed.', 'Generalize free-time independence across home, school, and community settings.', 'Monthly observations of free-time behavior quality and duration across varied settings.'),
('IP-6', 'Independent Play', 'Time-based: record duration of constructive play per session. Criterion: 5+ continuous minutes across 3 sessions.', 'IP-5 (independent toy selection); IP-3 (3-step sequences); fine motor skills for construction tasks.', 'Building and constructive toys: LEGO, wooden blocks, K-Nex, connecting cubes, Marble Run.', 'Set up construction materials. Withdraw. Observe whether child builds or assembles for 5+ minutes.', 'Child engages in constructive play (building or assembling) for 5+ continuous minutes independently.', 'Abandons construction before 5 min, engages in non-constructive stereotyped use, or requires prompts.', 'least_to_most', '1. No prompt > 2. Brief gestural to building materials > 3. Verbal ("What are you making?")', 'Brief neutral re-engagement prompt. Avoid directive commentary that interrupts child-directed construction.', 'Increase duration target from 3 min to 10 min gradually. Introduce new construction toy types.', 'Brief praise at 3-min checkpoint; end-of-session reinforcement for meeting duration.', 'Generalize across 3+ types of constructive toys. Include construction in classroom free-choice time.', 'Monthly duration observations. Track complexity and variety of constructions over time.'),
('IP-7', 'Independent Play', 'Record correct rule-following behaviors during game. Criterion: follows all rules independently 80%+ across 3 games per session.', 'IP-6 (5-min constructive play); basic listener responding; understanding of turn-taking concepts.', 'Simple structured games with clear visual rules: Candy Land, Hi Ho Cherry-O, simple card matching game.', 'Set up game. Review rules once with visuals. Play game with child as partner. Observe rule adherence.', 'Child independently follows all rules of a simple structured game without requiring rule reminders.', 'Breaks rule, requires rule reminder, refuses turn-taking, or needs continuous adult direction.', 'least_to_most', '1. No prompt > 2. Point to rule visual > 3. Verbal rule reminder.', 'State the rule that was broken; re-start that game turn; reinforce correct rule-following.', 'Begin with 2-3 rule games. Progress to more complex rules as mastery develops.', 'Game completion as natural reinforcer. Brief praise for rule-following. Occasional tangible.', 'Generalize to novel simple games. Include game play with familiar peers.', 'Monthly game observation probes with novel games. Track which rule types are hardest to follow.'),
('IP-8', 'Independent Play', 'Record number of novel/varied play scenarios created per session. Criterion: 3+ novel play scenarios per 30-min session across 3 sessions.', 'IP-7 (simple game rules); IP-5 (independent toy selection); symbolic play beginning.', 'Themed play sets (farm, kitchen, garage); figurines; dress-up items; open-ended materials.', 'Set up themed materials. Withdraw. Observe whether child creates varied novel scenarios beyond rote scripts.', 'Child creates 3+ novel and varied play scenarios with toys without adult direction or repetitive scripting.', 'Uses only 1 repetitive script/sequence, requires adult to initiate new scenarios, or engages in object stereotypy.', 'least_to_most', '1. No prompt > 2. Introduce novel prop ("What else can happen?") > 3. Briefly model new scenario then withdraw.', 'Briefly introduce a novel element (new prop or character) if play becomes repetitive; then fully withdraw.', 'Gradually expand themed play sets and introduce new characters and scenarios over time.', 'End-of-session reinforcement for breadth of play; praise novel scenarios as they occur.', 'Generalize to novel play themes and props. Include play with peers for social generalization.', 'Monthly observation: count unique play scenarios created in 30-min session.'),
('IP-9', 'Independent Play', 'Record successful independent transitions between play activities. Criterion: 80%+ independent transitions across 3 sessions.', 'IP-8 (novel play scenarios); IP-5 (free toy selection); tolerance for activity change.', '2-3 different play activity stations set up; visual timer optional.', 'Set up 2 activity stations. Tell child "In 2 minutes, you will switch." Use timer. Observe transition.', 'Child independently transitions between play activities when cued, without prompting or behavioral resistance.', 'Refuses to transition, requires physical guidance, or has behavioral outburst at transition.', 'least_to_most', '1. Timer cue only > 2. Verbal warning ("1 more minute") > 3. Verbal transition instruction > 4. Physical guidance.', 'Provide 1-minute warning; use visual timer; provide brief choice of which activity to go to next.', 'Begin with transitions between 2 highly preferred activities. Gradually include less-preferred activities.', 'Natural reinforcement (access to next preferred activity). Praise smooth independent transitions.', 'Generalize transition independence across home, school, and therapy contexts. Fade timer cue.', 'Monthly probe: transition success rate across varied activity pairs including non-preferred items.'),
('IP-10', 'Independent Play', 'Record number of toy types engaged appropriately per session. Criterion: 10 different toys at 90%+ across 3 sessions.', 'IP-9 (independent transitions); IP-5 (free selection); expanding play repertoire built across all prior IP levels.', '10+ different toys representing all major play types: construction, artistic, fantasy, board games, outdoor.', 'Rotate all 10+ toys across sessions. Withdraw. Observe appropriate functional engagement with each.', 'Child plays with 10+ different toys in developmentally appropriate ways without adult direction.', 'Only uses subset of toys repetitively; needs adult to introduce new toys; non-functional/stereotyped use.', 'least_to_most', '1. No prompt > 2. Environmental arrangement (new toy placed in path) > 3. Brief verbal introduction.', 'Model appropriate use of rarely chosen toy for 20 s; withdraw; observe independent continuation.', 'Add 1 new toy to repertoire per week using structured introduction followed by independent probe.', 'Natural reinforcement of play; occasional praise for trying new toys.', 'Generalize all 10 toy types across home, school, and community settings.', 'Monthly observation counting toy variety used. Target 10 distinct toys per session.'),
('IP-11', 'Independent Play', 'Time-based: record duration of pretend play per session. Criterion: 10+ continuous minutes across 3 sessions.', 'IP-10 (10 toys in appropriate ways); IP-8 (novel play scenarios); symbolic play well established.', 'Elaborate pretend play materials: full kitchen sets, doctor kits, toolboxes, dollhouses, puppet theaters.', 'Set up pretend play environment richly. Withdraw fully. Observe duration and complexity of pretend play.', 'Child engages in complex pretend play for 10+ continuous minutes, independently generating narrative and roles.', 'Abandons pretend play before 10 min, requires adult to sustain narrative, or play degenerates to scripted repetition.', 'least_to_most', '1. No prompt > 2. Novel prop introduction > 3. Verbal narrative prompt ("What happens next?") then withdraw.', 'Introduce 1 novel prop to restart narrative if play degenerates; immediately withdraw.', 'Extend from 5-min to 15-min sessions by 1-minute increments every 3 sessions.', 'Natural reinforcement of play narrative. Minimal external reinforcement needed at this level.', 'Generalize pretend play across novel themes, settings, and materials. Include peer partners.', 'Monthly 30-min observation: record pretend play duration and narrative complexity.'),
('IP-12', 'Independent Play', 'Record appropriate behavior during transitions/waiting periods. Criterion: appropriate independent activity 80%+ of waiting intervals across 3 sessions.', 'IP-11 (10-min pretend play); IP-9 (independent transitions); self-regulation skills.', 'Portable preferred materials (small toys, books, drawing supplies) for waiting contexts.', 'Create natural waiting situation (5-10 min). Do not direct child. Observe whether child self-occupies.', 'Child independently occupies self appropriately during transitions or waiting periods without adult prompting.', 'Becomes dysregulated, seeks adult repeatedly, or engages in interfering behavior during waiting.', 'least_to_most', '1. No prompt > 2. Environmental cue (preferred materials visible) > 3. Brief verbal ("You can play while you wait").', 'Provide preferred material; briefly remind of appropriate waiting activity; fade support over sessions.', 'Begin with 2-min waits with preferred materials present. Gradually increase duration to 10 min.', 'Natural activity access as reinforcement. Brief praise for calm independent waiting.', 'Generalize to waiting in community contexts (waiting room, restaurant, store). Fade materials over time.', 'Monthly probe of waiting behavior across varied contexts. Track duration and material independence.'),
('IP-13', 'Independent Play', 'Record participation in target leisure activity without adult support. Criterion: 80%+ participation across 3 observations.', 'IP-12 (self-occupation during waiting); broad play and leisure repertoire across prior IP levels.', 'Age-appropriate leisure materials matching child interests: board games, sports equipment, art supplies, books.', 'Identify 2-3 age-appropriate leisure activities. Set up environment. Withdraw fully. Observe participation.', 'Child participates in age-appropriate leisure activities for the expected duration without adult support.', 'Requires adult to initiate or maintain activity; cannot manage activity without assistance; refuses participation.', 'least_to_most', '1. No prompt > 2. Environmental setup only > 3. Brief activity introduction then full withdrawal.', 'Briefly re-introduce activity concept; provide one guiding statement; withdraw immediately.', 'Systematically fade adult proximity across sessions. Coordinate with typical peers to co-participate.', 'Natural activity enjoyment as reinforcement. Minimal external reinforcement. Social praise for participation.', 'Generalize to community leisure settings: park, library, sports team, club. Include peer participation.', 'Monthly observations in novel leisure contexts. Track activity duration and independence level.'),
('IP-14', 'Independent Play', 'Record number of self-imposed rules followed per play session. Criterion: creates and follows 2+ self-imposed rules 80%+ of sessions across 3 sessions.', 'IP-13 (leisure activities independently); IP-7 (simple game rules); metacognitive awareness.', 'Open-ended play materials for games or activities that do not come with preset rules (blocks, open space, art).', 'Withdraw from directed instruction. Observe whether child creates personal rules during independent play.', 'Child creates and consistently follows self-imposed rules during independent play activities without prompting.', 'Plays without consistent rules, requires adult rule structure, or abandons self-created rules immediately.', 'least_to_most', '1. No prompt > 2. Ask "What are the rules?" after play begins > 3. Independent rule creation.', 'Ask open-ended question about play rules; reinforce any rule articulation; observe consistency across session.', 'Initially accept any self-imposed rule (even simple ones). Gradually expect rule consistency over time.', 'Social praise for rule articulation and consistency. Natural activity engagement as reinforcement.', 'Generalize to peer play contexts where child can propose and enforce shared rules.', 'Monthly observations: note self-created rules and consistency of rule-following during play.'),
('IP-15', 'Independent Play', 'Record appropriate independent activity in community play settings. Criterion: 80%+ appropriate play across 3 community observations.', 'IP-14 (self-imposed rules); full IP repertoire across Levels 1-3; community behavior skills.', 'Community play environments: playground, park, library activity area, community sports field.', 'Accompany child to community play setting. Withdraw to observation distance. Record behavior.', 'Child independently manages play activities in community settings without adult prompts or assistance.', 'Requires adult redirection, cannot manage transitions in community settings, or needs constant supervision.', 'least_to_most', '1. No prompt > 2. Environmental orientation ("The playground is open - go play") > 3. Brief check-in only.', 'Provide brief orienting instruction only if child is completely disengaged; then withdraw immediately.', 'Begin with familiar community settings; gradually introduce novel community play environments.', 'Natural community play as reinforcement. Occasional brief social praise from distance.', 'Generalize to multiple community play settings: different playgrounds, sports contexts, community events.', 'Monthly community observation. Track independence duration and variety of community play behaviors.')
ON CONFLICT (milestone_code) DO UPDATE
SET vbmapp_domain = EXCLUDED.vbmapp_domain,
    data_collection = EXCLUDED.data_collection,
    prerequisite_skills = EXCLUDED.prerequisite_skills,
    materials = EXCLUDED.materials,
    sd = EXCLUDED.sd,
    correct_responses = EXCLUDED.correct_responses,
    incorrect_responses = EXCLUDED.incorrect_responses,
    prompting_hierarchy = EXCLUDED.prompting_hierarchy,
    prompting_hierarchy_detail = EXCLUDED.prompting_hierarchy_detail,
    error_correction = EXCLUDED.error_correction,
    transfer_procedure = EXCLUDED.transfer_procedure,
    reinforcement_schedule = EXCLUDED.reinforcement_schedule,
    generalization_plan = EXCLUDED.generalization_plan,
    maintenance_plan = EXCLUDED.maintenance_plan,
    template_origin = EXCLUDED.template_origin;

-- ============================================================
-- SOCIAL BEHAVIOR (SOC-1 through SOC-15)
-- ============================================================

INSERT INTO vbmapp_milestone_templates (milestone_code, vbmapp_domain, data_collection, prerequisite_skills, materials, sd, correct_responses, incorrect_responses, prompting_hierarchy, prompting_hierarchy_detail, error_correction, transfer_procedure, reinforcement_schedule, generalization_plan, maintenance_plan) VALUES
('SOC-1', 'Social Behavior', 'Record frequency of spontaneous eye contact during 30-min structured play. Criterion: 5+ spontaneous instances per session across 3 sessions.', 'Basic attending to people; responds to name 50%+; tolerates physical proximity of adults.', 'Preferred toys for parallel engagement; open play space; familiar adult partner.', 'Engage in side-by-side play. Do not demand eye contact. Observe and record spontaneous eye contact.', 'Child makes spontaneous eye contact with peers during social interactions without adult prompting.', 'Avoids eye contact entirely, only looks when physically prompted, or requires name-call first.', 'least_to_most', '1. No prompt > 2. Move into visual field > 3. Call name then reinforce eye contact when given.', 'Reinforce any fleeting eye contact immediately. Do not demand prolonged gaze. Pair eye contact with preferred items.', 'Use preferred activities as natural elicitors. Gradually increase eye contact duration expectation.', 'CRF: reinforce every spontaneous eye contact. Pair with preferred item access or enthusiastic social response.', 'Generalize across familiar adults and familiar peers. Vary settings.', 'Monthly frequency count of spontaneous eye contact in naturalistic 30-min observation.'),
('SOC-2', 'Social Behavior', 'Record latency and rate of responses to social initiations per session. Criterion: responds within 5 s on 80%+ of initiations across 3 sessions.', 'SOC-1 (eye contact); responds to own name; some joint attention behaviors.', 'Natural activity with familiar adult; varied social initiations (greetings, questions, invitations to play).', 'Familiar adult approaches and makes social initiation (says hello, offers item, asks question). Wait 5 s.', 'Child responds to social initiations from familiar adults within 5 seconds, with an appropriate social response.', 'Ignores initiation, responds after 10+ s, turns away, or engages in interfering behavior.', 'least_to_most', '1. No prompt > 2. Repeat initiation with gestural cue > 3. Model appropriate response then re-initiate.', 'Re-initiate; model response; request imitation; reinforce any approximation; re-probe naturally.', 'Expand to varied initiation types. Progress to novel familiar adults and unfamiliar familiar adults.', 'CRF for each social response. Use enthusiastic social reinforcement to build social value.', 'Generalize to 3+ familiar adults and 2+ settings. Include naturally occurring social opportunities.', 'Monthly probe: response rate to varied social initiations from familiar and novel adults.'),
('SOC-3', 'Social Behavior', 'Record frequency of child-initiated proximity to peers. Criterion: 3+ initiations per 30-min session across 3 sessions.', 'SOC-2 (responds to initiations); tolerates peer proximity; some awareness of peers as social partners.', 'Open play area with 1-2 preferred peers available and engaged in preferred activities.', 'Allow free play with peers available. Do not direct social interaction. Observe proximity initiations.', 'Child spontaneously moves near peers in play areas without adult prompting, within 3 feet.', 'Never approaches peers, only plays in isolation, or requires adult to physically facilitate proximity.', 'least_to_most', '1. No prompt > 2. Environmental arrangement (preferred toy near peer) > 3. Verbal ("Go play near ___").', 'Arrange environment so preferred activity is near a peer. Do not direct the interaction itself.', 'Begin with 1 highly familiar peer. Gradually increase number of peer options available.', 'Enthusiastic social praise when child initiates proximity. Ensure peer engagement is rewarding.', 'Generalize across multiple peers and play settings. Include outdoor and classroom contexts.', 'Monthly 30-min observation: count peer proximity initiations and record duration near peers.'),
('SOC-4', 'Social Behavior', 'Record sharing instances (prompted and unprompted) per session. Criterion: shares with peer when prompted 80%+ of prompted opportunities across 3 sessions.', 'SOC-3 (proximity to peers); basic turn-taking understanding; mand repertoire for sharing contexts.', 'Preferred toys or snack items; 1 peer partner; adult facilitator nearby.', 'Set up sharing opportunity (one item, two people). Give sharing prompt once: "Can you share with ___?"', 'Child shares materials with peer when prompted by adult, within 5 seconds of sharing prompt.', 'Refuses to share, requires repeated prompt, or requires physical guidance to hand item over.', 'most_to_least', '1. Physical guidance (guide hand to share) > 2. Gestural (point to peer) > 3. Verbal prompt > 4. Independent.', 'Re-prompt; physically guide if needed; reinforce immediately when item is shared.', 'Begin with high-quantity or less-preferred items. Gradually include more-preferred materials.', 'CRF for sharing: enthusiastic praise + peer access to item creates natural social reinforcement.', 'Generalize to varied materials, multiple peers, and all settings where sharing occurs.', 'Monthly probe: sharing compliance rate across multiple sharing opportunities and peer partners.'),
('SOC-5', 'Social Behavior', 'Record spontaneous greeting frequency per session. Criterion: greets adults and peers without prompting 80%+ of opportunities across 3 sessions.', 'SOC-4 (sharing); SOC-2 (responds to initiations); basic verbal or AAC communication established.', 'Natural entry situations (entering classroom, meeting adult at door); familiar people in environment.', 'Create natural greeting opportunities. Enter room or approach child. Observe whether greeting is initiated.', 'Child greets familiar adults and peers spontaneously without adult prompting across multiple settings.', 'Greets only when prompted, greets inconsistently, or uses inappropriate greeting form.', 'least_to_most', '1. No prompt > 2. Expectant pause > 3. Verbal prompt ("Say hello to ___").', 'Provide expectant pause with eye contact; if no greeting, model greeting and request imitation; re-create opportunity.', 'Teach varied greeting forms (hello, hi, wave, fist bump) and vary based on relationship/context.', 'Natural social reciprocity as primary reinforcer. Enthusiastic response from greeted person.', 'Generalize greeting across all settings and to novel familiar people. Include varied greeting forms.', 'Monthly probe: greeting rate across 10+ naturally occurring greeting opportunities.'),
('SOC-6', 'Social Behavior', 'Time-based: record duration of parallel play with peer. Criterion: 5+ continuous minutes of parallel play across 3 sessions.', 'SOC-5 (spontaneous greetings); IP-4 (3+ min continuous play); tolerates peer in same space.', 'Identical or complementary toy sets for 2 children; open play space; adult observing from distance.', 'Place child and peer in same play space with similar materials. Withdraw adult to distance. Observe.', 'Child initiates and sustains parallel play with a peer for 5+ minutes without adult facilitation.', 'Leaves play space, repeatedly demands adult attention, or interferes with peer play.', 'least_to_most', '1. No prompt > 2. Brief verbal encouragement from distance > 3. Provide novel toy near peer.', 'Briefly re-engage child with a novel toy near the peer from a distance; withdraw immediately.', 'Build from 2-min to 10-min target over multiple sessions. Use highly preferred parallel activities.', 'Check-in reinforcement every 2-3 min initially. Thin to end-of-session. Natural play as reinforcer.', 'Generalize parallel play across multiple peers and varied settings (classroom, playground, home).', 'Monthly 30-min observation: record duration of parallel play and number of parallel play bouts.'),
('SOC-7', 'Social Behavior', 'Record turn-taking accuracy per structured activity session. Criterion: takes turns without prompting 80%+ of turn opportunities across 3 sessions.', 'SOC-6 (5-min parallel play); IP-7 (simple game rules); basic understanding of wait concepts.', 'Simple structured turn-taking games or activities; 1 peer partner; visual turn indicator optional.', 'Set up turn-taking activity. Review rules briefly. Play with peer. Observe turn-taking behavior.', 'Child takes turns with peers during structured activities without adult prompting.', 'Takes multiple turns without waiting, refuses to take turn, or requires adult prompting each time.', 'least_to_most', '1. Visual turn card only > 2. Verbal reminder ("It is ___ turn") > 3. Physical re-direction.', 'Briefly state whose turn it is; redirect to waiting position; reinforce when correct turn-taking occurs.', 'Begin with 2-turn alternation (you/me). Expand to 3+ person games. Fade visual turn supports.', 'Natural game progression as reinforcement. Enthusiastic praise for spontaneous turn-taking.', 'Generalize to varied games, different peers, and all classroom turn-taking contexts.', 'Monthly probe: turn-taking success rate across multiple games and peer partners.'),
('SOC-8', 'Social Behavior', 'Record spontaneous sharing instances (unprompted) per session. Criterion: 3+ spontaneous shares per session across 3 sessions.', 'SOC-4 (prompted sharing at 80%+); SOC-7 (turn-taking); basic empathy and other-awareness.', 'Group activity setting with shared materials; peers available; adult in background.', 'Set up shared activity. Do not prompt sharing. Observe whether child spontaneously shares.', 'Child spontaneously shares materials with peers without adult prompting during activities.', 'Waits for adult prompt to share, hoards materials, or only shares after peer requests.', 'least_to_most', '1. No prompt > 2. Environmental arrangement (fewer items to create sharing context) > 3. Indirect prompt ("I wonder if ___ wants some").', 'Indirect verbal comment about peer need; observe whether child responds; reinforce any spontaneous sharing immediately.', 'Create natural scarcity situations that elicit sharing. Praise sharing effusively.', 'Enthusiastic social praise + natural peer reciprocity as primary reinforcement.', 'Generalize to spontaneous sharing across all activity types and multiple peer partners.', 'Monthly observation: count spontaneous sharing instances across 30-min peer activity session.'),
('SOC-9', 'Social Behavior', 'Record offers of help per session. Criterion: 3+ spontaneous offers of help per session across 3 sessions.', 'SOC-8 (spontaneous sharing); basic empathy and perspective-taking emerging; functional language.', 'Peer partners engaged in activities where help is occasionally needed (dropping items, struggling with task).', 'Create naturalistic peer situations where help could be offered. Observe without prompting.', 'Child spontaneously offers help or assistance to peers during activities without adult prompting.', 'Ignores peers who need help, helps only when asked, or requires adult direction to help.', 'least_to_most', '1. No prompt > 2. Draw attention to peer need ("Look at ___") > 3. Indirect prompt ("I wonder if ___ needs help").', 'Comment on peer situation without directive; observe whether child responds; reinforce any helping behavior.', 'Teach the language of helping ("Can I help you?"). Model helping in natural contexts.', 'Enthusiastic social praise + natural peer gratitude as reinforcement.', 'Generalize helping across multiple peers and varied situations (academic, play, daily living).', 'Monthly probe: frequency of helping behaviors in 30-min naturalistic peer observation.'),
('SOC-10', 'Social Behavior', 'Record on-task interval during group activity. Criterion: participates in group activity 80%+ of 10-min observation across 3 sessions.', 'SOC-9 (helps peers); SOC-7 (turn-taking); Classroom Routines Level 1-2.', 'Group activity materials for 3-4 peers; structured cooperative task; adult facilitating.', 'Set up group activity with 2-3 peers. Minimal adult direction. Observe participation.', 'Child participates in group activities with 2+ peers for 10 minutes, engaging appropriately with group.', 'Withdraws from group, becomes disruptive, refuses to participate, or requires continuous adult support.', 'least_to_most', '1. No prompt > 2. Group verbal cue > 3. Individual verbal prompt > 4. Physical redirect to group.', 'Minimal, least-intrusive redirect; avoid prolonged 1:1 correction in group context; reinforce group participation.', 'Begin with 2-person groups; expand to 3-4 person groups. Increase activity duration incrementally.', 'Group contingency reinforcement (class earns reward). Individual brief praise for participation.', 'Generalize to varied group activity types across classroom, playground, and community.', 'Monthly 15-min group observation: record participation rate and type of social engagement.'),
('SOC-11', 'Social Behavior', 'Record conversation maintenance exchanges per session. Criterion: initiates and maintains conversation 3+ exchanges on preferred topic across 3 sessions.', 'SOC-10 (group participation); Intraverbal Level 2+; basic conversational skills.', 'Natural social settings with familiar peers; shared interest contexts (games, shows, activities).', 'Create natural social opportunity with preferred peer. Withdraw. Observe conversation initiation and maintenance.', 'Child initiates and maintains conversations with peers on preferred topics for 3+ reciprocal exchanges.', 'Initiates but cannot maintain beyond 1 exchange; requires adult facilitation; only talks at peer without reciprocity.', 'least_to_most', '1. No prompt > 2. Conversational bridging comment from adult > 3. Direct conversational prompt.', 'Provide conversational bridge ("Tell ___ about it"); withdraw; reinforce continued peer conversation.', 'Begin with preferred topics. Gradually expand to varied and peer-initiated topics.', 'Natural peer engagement as primary reinforcer. Enthusiastic adult praise for conversation quality.', 'Generalize across varied peers and conversation topics. Include novel peers.', 'Monthly naturalistic conversation probe: record initiation, exchange count, and topic maintenance.'),
('SOC-12', 'Social Behavior', 'Record conflict resolution attempts per conflict situation. Criterion: uses verbal strategies 80%+ of conflicts across 3 sessions.', 'SOC-11 (conversation maintenance); functional language for refusal and negotiation; emotional regulation.', 'Natural peer play settings where conflicts arise organically; adult observing.', 'Allow natural peer play. When conflict arises, observe without immediately intervening.', 'Child resolves peer conflicts using appropriate verbal strategies independently without adult intervention.', 'Immediately escalates to aggression, cries without attempting verbal resolution, or shuts down.', 'least_to_most', '1. No prompt > 2. Presence cue (adult moves closer) > 3. Verbal coaching ("What can you say to ___?")', 'Verbal coaching only if child cannot initiate resolution; withdraw immediately once verbal attempt is made.', 'Teach specific conflict resolution scripts. Role-play common conflict scenarios in advance.', 'Natural conflict resolution (keeping desired item/activity) as reinforcement. Social praise for verbal strategies.', 'Generalize to novel peers and conflict types. Practice in multiple settings where conflicts arise.', 'Monthly conflict observation: record conflict frequency, resolution strategies used, and outcome.'),
('SOC-13', 'Social Behavior', 'Record appropriate cooperative behavior per structured game session. Criterion: demonstrates cooperative play 80%+ of game sessions across 3 sessions.', 'SOC-12 (conflict resolution); SOC-7 (turn-taking); IP-7 (structured game rules).', 'Cooperative or competitive group games with established rules; 2-3 peer partners.', 'Set up group game. Review rules briefly. Play game with peers. Observe rule adherence and cooperative behavior.', 'Child demonstrates cooperative play in group games with established rules, following all rules and cooperating with peers.', 'Breaks rules, refuses to cooperate, argues with rule applications, or requires adult to enforce rules.', 'least_to_most', '1. No prompt > 2. Point to rule visual > 3. Verbal rule reminder.', 'Briefly state the relevant rule; allow child to self-correct; reinforce cooperative behavior.', 'Begin with highly preferred games. Introduce less-preferred games as cooperation skills develop.', 'Natural game participation as reinforcement. Praise cooperative behavior specifically.', 'Generalize to novel games and varied peer groups. Include competitive games that require graceful losing.', 'Monthly game observation: rule adherence rate and quality of cooperation across varied games.'),
('SOC-14', 'Social Behavior', 'Record empathy/perspective-taking responses per session. Criterion: demonstrates empathy 3+ times per session across 3 sessions.', 'SOC-13 (cooperative play); SOC-9 (helping); basic emotional vocabulary and recognition.', 'Natural peer settings; scenarios where peers express emotion; shared storybooks about feelings.', 'Observe natural peer situations. Note when peer expresses emotion or need. Observe child response.', 'Child shows empathy and perspective-taking toward peers in social situations without prompting.', 'Ignores peer emotional expressions, laughs at peer distress, or requires adult to direct empathic response.', 'least_to_most', '1. No prompt > 2. Indirect comment ("I wonder how ___ feels") > 3. Direct perspective-taking prompt.', 'Ask indirect perspective-taking question; allow child to respond; reinforce any empathic response.', 'Teach emotional vocabulary and recognition. Use social stories and role-play for empathy scenarios.', 'Natural social reciprocity as reinforcement. Enthusiastic praise for spontaneous empathic acts.', 'Generalize to varied peer emotional contexts and novel peers. Include community empathy opportunities.', 'Monthly naturalistic observation: count empathic responses and quality of perspective-taking language.'),
('SOC-15', 'Social Behavior', 'Record reciprocal friendship behaviors per week. Criterion: maintains reciprocal friendship behaviors with 1+ peer across 3 weeks of observation.', 'SOC-14 (empathy); SOC-11 (conversation maintenance); full social repertoire across Levels 1-3.', 'Natural school, home, and community peer settings. No structured setup required.', 'Observe child across full school week. Note peer relationship indicators: seeking specific peer, reciprocal play, continued relationship.', 'Child develops and maintains reciprocal friendships with same-age peers across multiple weeks and settings.', 'No peer preferences, purely parallel without reciprocity, or peer relationships that are one-sided.', 'least_to_most', '1. No prompt > 2. Facilitate shared preferred activity with target peer > 3. Coach specific social skills if needed.', 'Support access to shared interests and settings; coach specific conversational or activity skills as needed.', 'Identify potential friendship peers based on shared interests. Create repeated contact opportunities.', 'Natural friendship benefits as reinforcement: shared play, mutual enjoyment, positive peer interactions.', 'Coordinate with family for after-school playdates. Include in community activities with same-age peers.', 'Monthly relationship quality observations: assess reciprocity, seeking behavior, and relationship continuity.')
ON CONFLICT (milestone_code) DO UPDATE
SET vbmapp_domain = EXCLUDED.vbmapp_domain,
    data_collection = EXCLUDED.data_collection,
    prerequisite_skills = EXCLUDED.prerequisite_skills,
