    incorrect_responses = EXCLUDED.incorrect_responses,
    prompting_hierarchy = EXCLUDED.prompting_hierarchy,
    prompting_hierarchy_detail = EXCLUDED.prompting_hierarchy_detail,
    error_correction = EXCLUDED.error_correction,
    transfer_procedure = EXCLUDED.transfer_procedure,
    reinforcement_schedule = EXCLUDED.reinforcement_schedule,
    generalization_plan = EXCLUDED.generalization_plan,
    maintenance_plan = EXCLUDED.maintenance_plan,
    template_origin = EXCLUDED.template_origin;

-- ============================================================
-- MOTOR IMITATION (MI-1 through MI-15)
-- ============================================================

INSERT INTO vbmapp_milestone_templates (milestone_code, vbmapp_domain, data_collection, prerequisite_skills, materials, sd, correct_responses, incorrect_responses, prompting_hierarchy, prompting_hierarchy_detail, error_correction, transfer_procedure, reinforcement_schedule, generalization_plan, maintenance_plan) VALUES
('MI-1', 'Motor Imitation', 'Record C/I/P per imitation trial. Criterion: 80%+ independent across 3 sessions for 2 gross motor actions.', 'Basic visual attention to model; some motor coordination; tolerates proximity of adult demonstrating.', 'Open space; no materials needed for gross motor. Model actions: clap, arms up, stomp, pat head.', 'Therapist says "Do this" and models gross motor action. Ensure child is attending before modeling.', 'Child imitates 2 different gross motor actions immediately after adult model, within 5 seconds.', 'Different motor action from model, no response, or requires physical prompt.', 'most_to_least', '1. Full physical (hand-over-hand during model) > 2. Partial physical > 3. Re-model (repeat action) > 4. Independent.', 'Immediately re-model; provide physical guidance; reinforce correct imitation; re-present same action.', 'Rotate between 2 target actions within sessions. Once 2 mastered, probe 3rd action.', 'CRF for every correct imitation. Enthusiastic praise + tangible. High reinforcement rate.', 'Generalize imitation across 2+ adults and 2 settings. Check for spontaneous imitation of peers.', 'Monthly probes of entire imitation repertoire. Add novel actions regularly.'),
('MI-2', 'Motor Imitation', 'Record C/I/P per imitation trial. Criterion: 80%+ independent across 3 sessions for 5 different gross motor actions.', 'MI-1 (2 gross motor actions); basic motor coordination for varied body movements.', 'Open space; 5 gross motor target actions identified (clap, stomp, turn around, arms out, jump).', 'Therapist says "Do this" and models one gross motor action. Rotate across all 5 within session.', 'Child imitates 5 different gross motor actions with immediate modeling, within 5 seconds, independently.', 'Imitates wrong action, no response, requires physical guidance, or perseverates on a previous action.', 'most_to_least', '1. Full physical > 2. Partial physical > 3. Re-model > 4. Independent. Fade across sessions.', 'Re-model immediately; provide physical guidance; reinforce imitation; re-probe same action.', 'Rotate through all 5 actions within each session. Expand to 10 once 5 mastered.', 'CRF for all correct imitations. Maintain high reinforcement rate throughout.', 'Generalize across 3+ adults and 2+ settings. Include actions in songs (Head, Shoulders).', 'Monthly probe of all mastered gross motor actions. Add novel actions to expand repertoire.'),
('MI-3', 'Motor Imitation', 'Record C/I/P per object imitation trial. Criterion: 80%+ independent across 3 sessions for 2 object actions.', 'MI-2 (5 gross motor actions); basic functional object manipulation; tolerates objects during imitation.', 'Objects: maracas, drum, ball, block stack, stacking rings. One object per trial.', 'Therapist says "Do this" and demonstrates action with object. No additional verbal description.', 'Child imitates 2+ different actions performed with objects within 5 seconds, after a single model.', 'Imitates wrong action with object, manipulates object non-functionally, or requires physical prompt.', 'most_to_least', '1. Full physical (hand-over-hand with object) > 2. Partial physical > 3. Re-model > 4. Independent.', 'Re-model the action with object; provide physical guidance; reinforce; re-probe.', 'Pair object imitation with function teaching. Use high-interest objects.', 'CRF for all correct object imitations. Tangible + enthusiastic praise.', 'Generalize object imitation to 5+ different objects and 2+ adults.', 'Monthly probe of all mastered object imitation actions. Add novel objects gradually.'),
('MI-4', 'Motor Imitation', 'Record C/I/P per imitation trial. Criterion: 80%+ independent across 3 sessions for 10 varied motor actions.', 'MI-2 (5 gross motor); MI-3 (2 object actions); growing imitation repertoire.', 'Open space; objects for object imitation trials; 10 target actions identified across gross and fine motor.', 'Therapist says "Do this" and models one of 10 target actions. Randomize sequence across sessions.', 'Child imitates 10 different gross and fine motor actions across sessions, independently within 5 seconds.', 'Imitates wrong action, perseverates, no response, or requires prompt beyond re-model.', 'most_to_least', '1. Re-model > 2. Partial physical for fine motor only > 3. Independent.', 'Re-model; provide prompt for difficult actions only; reinforce correct imitation; rotate to easy action then re-probe.', 'Rotate all 10 actions. Introduce fine motor actions (finger plays, hand gestures) as skill grows.', 'CRF during acquisition of each new action; VR2 once all 10 mastered.', 'Generalize all 10 actions across 3+ adults and 2+ settings.', 'Monthly probe of all 10 actions. Track which actions remain below 80%; re-teach.'),
('MI-5', 'Motor Imitation', 'Record C/I/P per 2-action sequence imitation trial. Criterion: 80%+ independent across 3 sessions.', 'MI-4 (10 varied motor actions); basic motor sequencing; short-term motor memory for 2 steps.', 'Open space; 2-step action sequences identified: clap then stomp, tap head then arms out.', 'Therapist says "Do this" and models 2 consecutive actions without pause. Ensure full attention before modeling.', 'Child imitates a sequence of 2 motor actions immediately after adult demonstration, in correct order.', 'Imitates only 1 action, reverses order, requires re-model of each step, or no response.', 'most_to_least', '1. Physical guidance through both steps > 2. Physical for step 2 only > 3. Re-model full sequence > 4. Independent.', 'Re-model full 2-action sequence; physically guide if needed; reinforce only if correct order maintained.', 'Begin with actions that naturally link (clap-clap is simpler than clap-stomp). Expand to disparate pairs.', 'CRF for correctly sequenced 2-action imitations. High praise + tangible during acquisition.', 'Generalize 2-action sequences to varied action pairs and across 2+ adults.', 'Monthly probe of all trained 2-action sequences. Add novel action pairs.'),
('MI-6', 'Motor Imitation', 'Record C/I/P per fine motor imitation trial. Criterion: 80%+ independent across 3 sessions for 5 fine motor actions.', 'MI-5 (2-action sequences); adequate fine motor coordination; hand watching during model.', 'Songs with finger plays (Itsy Bitsy Spider, Wheels on the Bus); clapping pattern sequences.', 'Therapist says "Do this" and models fine motor action (specific clapping pattern, finger play). No words.', 'Child imitates fine motor actions such as clapping patterns and finger plays, within 5 seconds, independently.', 'Produces approximation lacking key features, imitates gross motor instead, or no response.', 'most_to_least', '1. Full physical (hand-over-hand for hand position) > 2. Partial physical > 3. Re-model > 4. Independent.', 'Re-model at slow speed; provide partial physical guidance for hand position; reinforce best approximation.', 'Begin with symmetrical clapping patterns; progress to asymmetrical finger plays.', 'CRF for fine motor imitations. Accept and reinforce approximations that are clearly discriminable.', 'Generalize fine motor imitation to songs, classroom activities, art tasks, and music.', 'Monthly probe of all fine motor imitation targets. Track accuracy of key movement features.'),
('MI-7', 'Motor Imitation', 'Record C/I/P per 3-step sequence imitation trial. Criterion: 80%+ independent across 3 sessions.', 'MI-5 (2-action sequences at 80%+); MI-6 (fine motor actions); short-term motor memory for 3 steps.', 'Open space; 3-step sequences identified: clap, stomp, arms up; tap head, snap, clap.', 'Therapist says "Do this" and models 3 consecutive actions fluidly. Wait 5 s after final action.', 'Child imitates 3-step action sequence immediately after a single demonstration, in correct order.', 'Imitates fewer than 3 steps, reverses steps, or needs each step re-modeled individually.', 'most_to_least', '1. Physical for step 3 only > 2. Re-model full sequence > 3. Independent.', 'Re-model; provide step-3 prompt only; reinforce correct 3-step sequences only.', 'Begin with sequences that have rhythm (song-based). Progress to arbitrary non-rhythmic sequences.', 'CRF for correct 3-step sequences. High praise + tangible during acquisition.', 'Generalize to 3-step object sequences and 3-step action + object sequences.', 'Monthly probe of all 3-step sequences. Add novel 3-step combinations.'),
('MI-8', 'Motor Imitation', 'Record C/I/P per novel object imitation trial. Criterion: 80%+ independent across 3 sessions for 5 novel objects.', 'MI-3 (object actions at 80%+); MI-7 (3-step sequences); ability to generalize imitation to novel contexts.', 'Novel or unfamiliar objects child has not previously been taught to use: unusual kitchen tools, art implements, novel toys.', 'Therapist models action with novel object. "Do this." No prior exposure to how the object works.', 'Child imitates actions performed with novel or unfamiliar objects within 5 seconds, independently.', 'Does not attempt imitation with novel object, freezes, or imitates only known/familiar actions.', 'most_to_least', '1. Re-model slowly > 2. Partial physical to initiate movement > 3. Independent.', 'Re-model slowly; provide minimal physical guidance to initiate; reinforce any approximation with novel objects.', 'Use a range of novel objects. Reinforce generalized imitation as a conceptual skill.', 'CRF for novel object imitations. High enthusiasm to build confidence with unfamiliar objects.', 'Probe imitation generalization monthly with brand-new never-seen objects.', 'Monthly probe: imitation accuracy rate with novel (never-seen) objects.'),
('MI-9', 'Motor Imitation', 'Record C/I/P per imitation trial. Criterion: 80%+ independent across 3 sessions for 20+ motor actions.', 'MI-4 (10 actions); MI-7 (3-step sequences); MI-8 (novel objects); expanding imitation repertoire.', 'Varied gross motor, fine motor, and object imitation materials. 20+ target actions documented.', 'Therapist says "Do this" and models any of 20+ target actions. Randomize heavily across sessions.', 'Child imitates 20+ different motor actions accurately across different people within 5 seconds.', 'Errors on actions that were previously mastered; requires prompts for well-established actions.', 'most_to_least', '1. Re-model for missed actions > 2. Independent. Most actions at maintenance level.', 'Re-model and physically guide only for actions below 80%. High-frequency probing of full repertoire.', 'Rotate all 20+ actions. Add 2 new actions per week. Maintain equal probing across all items.', 'VR2-VR3 for established actions; CRF for newly added actions.', 'Generalize all 20+ actions across 3+ adults, 3+ settings, and varied social contexts.', 'Monthly probe of rotating 10-action sample from full repertoire of 20+.'),
('MI-10', 'Motor Imitation', 'Record C/I/P per oral motor imitation trial. Criterion: 80%+ independent across 3 sessions for 5 oral motor actions.', 'MI-9 (20+ motor actions); adequate oral motor awareness; willing to watch and imitate mouth movements.', 'Mirror optional; oral motor targets: open mouth wide, stick out tongue, blow air, press lips together, click tongue.', 'Therapist says "Do this" and models oral motor movement clearly at face level. Child watches face.', 'Child imitates oral motor movements including mouth and tongue positions within 5 seconds, independently.', 'Does not attend to mouth, imitates body instead of mouth, or produces random oral movements.', 'most_to_least', '1. Tactile cue (touch near mouth area) > 2. Re-model with exaggerated facial expression > 3. Independent.', 'Re-model with exaggeration; use mirror for self-monitoring; reinforce any correct approximation.', 'Begin with most visible movements (wide open mouth, tongue out). Progress to subtle positions.', 'CRF for oral motor imitations. High enthusiasm. Connect to echoic training where appropriate.', 'Generalize oral motor imitation to speech-relevant positions across speech therapy contexts.', 'Monthly probe of all 5+ oral motor actions. Coordinate with SLP for echoic/speech implications.'),
('MI-11', 'Motor Imitation', 'Record C/I/P per complex sequence imitation trial. Criterion: 80%+ independent across 3 sessions.', 'MI-9 (20+ motor actions); MI-7 (3-step sequences); rhythm and pattern processing.', 'Video or live model of simple dance routine (4-8 step); music optional; open space.', 'Therapist models 4-8 step dance or movement sequence once. "Do this." Child imitates full sequence.', 'Child imitates complex sequential behaviors such as a simple dance routine, in correct order, independently.', 'Imitates partial sequence only, requires step-by-step re-modeling, or cannot remember sequence.', 'most_to_least', '1. Step-by-step model with pauses > 2. Model full sequence twice > 3. Single model, independent.', 'Re-model full sequence; allow extra practice before requiring independent performance; reinforce attempts.', 'Begin with 4-step routines; expand to 8-step. Use music to support rhythm and sequence recall.', 'CRF for completing full complex sequence. High enthusiasm + tangible during acquisition.', 'Generalize to varied dance/movement styles. Include in music class and group activities.', 'Monthly probe of complex sequences. Add new routines regularly to maintain skill breadth.'),
('MI-12', 'Motor Imitation', 'Record instances of deferred imitation per session. Criterion: 3+ deferred imitation instances per session across 3 sessions.', 'MI-11 (complex sequences); full imitation repertoire; observation and delayed recall skills.', 'Natural peer play settings; varied peer activity contexts; no structured imitation setup needed.', 'Observe child in peer settings over the following 30-60 minutes after peer modeled behaviors. No instruction given.', 'Child demonstrates deferred imitation of peer behaviors after a delay, without direct instruction.', 'Only imitates immediately with model present; does not generalize peer behaviors to later independent play.', 'least_to_most', '1. No prompt > 2. "Remember what ___ was doing?" > 3. Re-expose to model then allow time to elapse.', 'Comment on deferred imitation when observed; reinforce the behavior socially.', 'Arrange peer activities that model behaviors the child would benefit from imitating.', 'Natural social learning as reinforcement. Deferred imitation supports learning from observation.', 'Generalize deferred imitation to varied peer models and varied time delays.', 'Monthly observation: record instances of deferred peer imitation in natural settings.'),
('MI-13', 'Motor Imitation', 'Record spontaneous peer imitation instances per session. Criterion: 3+ spontaneous instances per 30-min peer session across 3 sessions.', 'MI-12 (deferred imitation); full imitation repertoire; peer observation skills.', 'Natural peer play environments; varied peer activities; adult observing from distance.', 'Observe child during natural peer play. Do not instruct or prompt imitation of peers.', 'Child spontaneously imitates peer play actions without adult instruction during natural play.', 'Only imitates when instructed, imitates adults but not peers, or imitates own prior behaviors only.', 'least_to_most', '1. No prompt > 2. Draw attention to peer activity ("Look what ___ is doing") > 3. Independent.', 'Comment on peer activity to draw attention; allow child to imitate spontaneously; reinforce observed imitation.', 'Ensure access to variety of peer models in preferred activities. Build peer observation habits.', 'Natural peer integration and social belonging as reinforcement for spontaneous peer imitation.', 'Generalize to multiple peer models and varied play settings.', 'Monthly 30-min peer observation: count spontaneous peer imitation instances.'),
('MI-14', 'Motor Imitation', 'Record subtle social behavior imitation instances per session. Criterion: accurately imitates subtle social behaviors 3+ times per session across 3 sessions.', 'MI-13 (spontaneous peer imitation); full imitation repertoire; social awareness of subtle cues.', 'Natural social settings; peers and adults demonstrating facial expressions, gestures, prosody.', 'Observe child in natural social interactions. Note whether child imitates subtle social cues from others.', 'Child imitates subtle social behaviors such as facial expressions, head nods, and social gestures spontaneously.', 'Imitates only gross motor behaviors; misses subtle facial/gestural cues; shows flat affect in social contexts.', 'least_to_most', '1. No prompt > 2. "Did you see what ___ did?" > 3. Direct modeling of target social behavior.', 'Draw attention to subtle behavior; model explicitly; request imitation; reinforce in natural context.', 'Use social stories and video modeling to highlight subtle social behaviors worth imitating.', 'Natural social reciprocity and approval as reinforcement for subtle social imitation.', 'Generalize to varied social contexts and novel social partners.', 'Monthly social observation: record subtle social imitation across varied natural settings.'),
('MI-15', 'Motor Imitation', 'Record spontaneous imitation across settings per weekly observation. Criterion: spontaneous peer imitation observed in 3+ distinct settings across 3 weeks.', 'MI-14 (subtle social behaviors); full imitation repertoire across Levels 1-3; self-monitoring skills.', 'Varied natural settings: classroom, playground, home, community. No structured setup needed.', 'Observe child across full week in multiple settings. Note spontaneous imitation of peers without adult instigation.', 'Child spontaneously imitates peer behavior across multiple settings and people without adult instruction.', 'Spontaneous imitation confined to one setting only; requires adult to prompt imitation in new contexts.', 'least_to_most', '1. No prompt > 2. Environmental priming (arrange for peer model to be visible) > 3. Independent.', 'Arrange for high-quality peer models in new settings. Fade adult facilitation as imitation generalizes.', 'Support access to varied peer contexts. Identify natural imitation-facilitating environments.', 'Natural social learning and peer integration as reinforcement.', 'Continue monitoring generalization across novel settings and novel peer models.', 'Monthly multi-setting observation log: record settings where spontaneous peer imitation occurred.')
ON CONFLICT (milestone_code) DO UPDATE
SET vbmapp_domain = EXCLUDED.vbmapp_domain,
    data_collection = EXCLUDED.data_collection,
    prerequisite_skills = EXCLUDED.prerequisite_skills,
    materials = EXCLUDED.materials,
    sd = EXCLUDED.sd,
    correct_responses = EXCLUDED.correct_responses,
    incorrect_responses = EXCLUDED.incorrect_responses,
    prompting_hierarchy = EXCLUDED.prompting_hierarchy,
    prompting_hierarchy_detail = EXCLUDED.prompting_hierarchy_detail,
    error_correction = EXCLUDED.error_correction,
    transfer_procedure = EXCLUDED.transfer_procedure,
    reinforcement_schedule = EXCLUDED.reinforcement_schedule,
    generalization_plan = EXCLUDED.generalization_plan,
    maintenance_plan = EXCLUDED.maintenance_plan,
    template_origin = EXCLUDED.template_origin;

-- ============================================================
-- ECHOIC (ECH-1 through ECH-15)
-- ============================================================

INSERT INTO vbmapp_milestone_templates (milestone_code, vbmapp_domain, data_collection, prerequisite_skills, materials, sd, correct_responses, incorrect_responses, prompting_hierarchy, prompting_hierarchy_detail, error_correction, transfer_procedure, reinforcement_schedule, generalization_plan, maintenance_plan) VALUES
('ECH-1', 'Echoic', 'Record each vocal response to verbal stimuli. Criterion: vocalizes in response to verbal stimulus 80%+ of trials across 3 sessions.', 'Basic vocal behavior present (any vocalizations); attends to speaker voice briefly; not completely non-vocal.', 'No physical materials needed. Quiet room. High-preference reinforcers for vocal behavior.', 'Therapist vocalizes a sound or word. Pause 5 seconds. Reinforce any vocal response from child.', 'Child vocalizes any sound in response to verbal stimuli within 5 seconds, regardless of accuracy.', 'Complete silence with no vocal response; required physical prompt; or only non-vocal (pointing) response.', 'least_to_most', '1. Wait 5 s for any vocalization > 2. Exaggerated vocal model > 3. Physical prompt near mouth (if safe).', 'Accept and reinforce any vocalization. Do not demand accuracy at this level. Build vocal behavior first.', 'Use highly preferred items to pair with vocal behavior. High reinforcement rate for any vocal output.', 'CRF: reinforce every vocalization immediately. Use preferred tangibles to build vocal motivation.', 'Elicit vocalizations in varied contexts (snack, play, transition). Pair with all daily reinforcers.', 'Weekly vocal behavior rate probes. Track increase in vocal attempts over time.'),
('ECH-2', 'Echoic', 'Record C/I/P per echoic trial for 5 target syllables. Criterion: 80%+ correct across 3 sessions.', 'ECH-1 (vocalizes to stimuli); some differentiated sounds present; basic oral motor readiness.', 'No physical materials. Target CV/CVC syllables: ba, ma, da, cup, go.', 'Therapist says "Say ___" and models target syllable once at normal rate. Wait 3 seconds.', 'Child echoes 5 different CV or CVC syllables with intelligible, recognizable sounds within 3 seconds.', 'Vocalizes unrelated sound, no response, or requires more than 1 model.', 'most_to_least', '1. Repeat model with exaggeration > 2. Slow down model rate > 3. Use visual articulation cue > 4. Independent.', 'Re-model immediately; reinforce any correct approximation; accept shaping toward target phoneme.', 'Start with bilabial sounds (ba, ma, pa). Build from single phoneme to CV to CVC progression.', 'CRF for all correct echoic responses. Maintain very high reinforcement rate to build echoic behavior.', 'Vary vocal volume and rate of model. Generalize echoic responses across 2+ adults.', 'Monthly EESA progress monitoring. Track phoneme repertoire breadth.'),
('ECH-3', 'Echoic', 'Record C/I/P per 2-syllable word echoic trial. Criterion: 80%+ intelligible and recognizable across 3 sessions.', 'ECH-2 (5 CV/CVC syllables at 80%+); oral motor coordination for 2-syllable production.', 'No physical materials. 2-syllable target words: cookie, baby, bottle, daddy, mommy.', 'Therapist says "Say [2-syllable word]" and models at normal rate. Wait 3 seconds.', 'Child echoes 2-syllable words with intelligible and recognizable sounds within 3 seconds.', 'Echoes only one syllable, produces unintelligible output, or requires repeated model.', 'most_to_least', '1. Segment syllables (say each separately then together) > 2. Slow model > 3. Independent.', 'Re-model with syllable segmentation; reinforce best approximation; shape toward target word.', 'Build from words with repeated syllables (mama, papa) to distinct 2-syllable words.', 'CRF for all recognizable 2-syllable echoics. Shape approximations toward target.', 'Generalize 2-syllable echoics across varied vocabulary. Connect to tact training.', 'Monthly probe of 2-syllable word echoic accuracy across trained and novel words.'),
('ECH-4', 'Echoic', 'Record C/I/P per single word echoic trial. Criterion: 80%+ with 50%+ accuracy across 3 sessions for 10 words.', 'ECH-3 (2-syllable words); growing phoneme repertoire; oral motor coordination for single words.', 'No physical materials. 10 high-frequency target words relevant to daily routines and reinforcers.', 'Therapist says "Say ___" and models target word once. Wait 3 seconds.', 'Child echoes 10 different single words with 50% or greater phonemic accuracy within 3 seconds.', 'No response, completely unintelligible output, or requires multiple models.', 'most_to_least', '1. Partial echoic (first syllable model) > 2. Full model at slow rate > 3. Independent.', 'Re-model; accept and reinforce 50%+ accuracy approximations; shape toward target word over sessions.', 'Select target words that are relevant to preferred items and daily activities. Connect to mand training.', 'CRF for all acceptable echoic responses. Shape accuracy criteria gradually.', 'Generalize echoic accuracy across 10+ words in varied contexts with multiple adults.', 'Monthly probe: accuracy rate for all 10 target words across multiple echoic trials.'),
('ECH-5', 'Echoic', 'Record C/I/P per 2-word phrase echoic trial. Criterion: 80%+ immediately following model across 3 sessions.', 'ECH-4 (10 single words at 50%+ accuracy); emerging multi-word output; short-term auditory memory for 2 words.', 'No physical materials. Target 2-word phrases: "more please," "all done," "want cookie," "help me."', 'Therapist says "Say [2-word phrase]" and models once. Wait 3 seconds.', 'Child echoes simple 2-word phrases immediately after they are modeled, within 3 seconds.', 'Echoes only one word, reverses word order, produces unintelligible output, or no response.', 'most_to_least', '1. Model each word separately then together > 2. Full phrase model > 3. Independent.', 'Re-model with word-by-word then combined approach; reinforce any 2-word attempt; shape order.', 'Select 2-word phrases that are functional mands or social phrases. Transfer to mand training.', 'CRF for all 2-word echoic attempts. High enthusiasm for 2-word output.', 'Generalize 2-word echoics to functional mand and tact contexts.', 'Monthly probe of 2-word phrase echoics across trained phrases and novel combinations.'),
('ECH-6', 'Echoic', 'Record C/I/P per 3-word phrase echoic trial. Criterion: 80%+ with 80%+ intelligibility across 3 sessions.', 'ECH-5 (2-word phrases at 80%+); improving articulation; auditory memory for 3 words.', 'No physical materials. 3-word target phrases: "I want juice," "sit down please," "more of that."', 'Therapist says "Say [3-word phrase]" and models at natural pace. Wait 5 seconds.', 'Child echoes 3-word phrases with 80% or greater intelligibility within 5 seconds.', 'Echoes only 1-2 words, poor intelligibility, word reversals, or no response.', 'most_to_least', '1. Model each word separately then combined > 2. Full phrase model > 3. Independent.', 'Re-model with segmentation if needed; reinforce 80%+ intelligible 3-word output; shape.', 'Select 3-word functional phrases for manding and social use. Connect to spontaneous speech targets.', 'CRF for 3-word phrase echoics at criterion. High praise + preferred item for functional phrases.', 'Generalize 3-word echoics to varied conversational contexts. Build bridge to spontaneous 3-word output.', 'Monthly probe: 3-word phrase intelligibility rate across trained and novel phrases.'),
('ECH-7', 'Echoic', 'Record C/I/P per novel word echoic trial. Criterion: 80%+ accurate on first trial for 10 novel words across 3 sessions.', 'ECH-6 (3-word phrases); strong phoneme repertoire; phonological processing adequate for novel words.', 'No physical materials. Novel low-frequency words never previously taught: exotic animal names, unusual objects.', 'Therapist says "Say [novel word]" and models once. Provide NO prior exposure to this word.', 'Child echoes novel words accurately on first trial without prior exposure, within 3 seconds.', 'Requires multiple models, produces inaccurate novel word, or refuses to attempt.', 'most_to_least', '1. Slow model of novel word > 2. Syllable-by-syllable model > 3. Single model, independent.', 'Re-model with syllable segmentation; reinforce any accurate attempt; shape toward target.', 'Use novel words that test phoneme generalization. Rotate novel word pools to prevent memorization.', 'CRF for novel word echoics. High enthusiasm for first-trial accuracy.', 'Monthly probes with brand-new novel words not previously heard.', 'Monthly novel word echoic accuracy rate on first-trial probe.'),
('ECH-8', 'Echoic', 'Record C/I/P per 4+-word sentence echoic trial. Criterion: 80%+ with accurate content and word order across 3 sessions.', 'ECH-7 (novel words at 80%+); auditory memory for 4+ words; improving sentence-level articulation.', 'No physical materials. 4-5 word target sentences: "I want to go outside," "the dog is running fast."', 'Therapist says "Say [4-word sentence]" and models at conversational pace. Wait 5 seconds.', 'Child echoes sentences of 4+ words with accurate content and word order within 5 seconds.', 'Omits words, reverses order, inserts wrong words, or echoes only 2-3 words.', 'most_to_least', '1. Chunk sentence into 2-word pairs then combine > 2. Full model > 3. Independent.', 'Re-model with chunking; reinforce accurate 4-word echo; address word-order errors specifically.', 'Increase sentence complexity gradually (4 words > 5 words > 6 words). Connect to intraverbal targets.', 'CRF for accurate 4+ word sentence echoics. High praise for word-order accuracy.', 'Generalize long-sentence echoics across varied sentence structures and topic areas.', 'Monthly probe: accuracy of 4+ word sentence echoics across trained and novel sentences.'),
('ECH-9', 'Echoic', 'Record C/I/P per minimal pair trial. Criterion: 80%+ accurate discrimination across 3 sessions for 10 pairs.', 'ECH-8 (4+ word sentences); refined phoneme discrimination; auditory processing for minimal differences.', 'No physical materials. Minimal pair word sets: bat/pat, bin/pin, sip/zip, hat/hot.', 'Therapist says "Say ___" for one word of a minimal pair. Rotate between pair members each trial.', 'Child echoes minimal pair words accurately, demonstrating phonemic discrimination within 3 seconds.', 'Produces the wrong member of the pair, cannot distinguish phonemes, or produces a blend.', 'most_to_least', '1. Exaggerate contrasting phoneme in model > 2. Standard model > 3. Independent.', 'Re-model with exaggerated contrasting phoneme; reinforce accurate minimal pair discrimination.', 'Begin with maximally distinct pairs; progress to acoustically similar pairs. Connect to reading/spelling.', 'CRF for accurate minimal pair echoics. High praise for phonemic precision.', 'Generalize to varied minimal pair types: vowel contrasts, voiced/voiceless, place-of-articulation.', 'Monthly probe: minimal pair discrimination accuracy across all 10 trained pairs and novel pairs.'),
('ECH-10', 'Echoic', 'Record C/I/P per complex sentence echoic trial. Criterion: 80%+ across 3 sessions for varied complex sentences.', 'ECH-9 (minimal pairs); ECH-8 (4+ word sentences); strong auditory memory for complex structure.', 'No physical materials. Complex sentences with embedded clauses: "The dog that is big ran away."', 'Therapist models complex sentence with embedded clause once at normal pace. Wait 5 seconds.', 'Child echoes complex sentences with embedded clauses across multiple examples within 5 seconds.', 'Omits clause, simplifies structure, or cannot recall full complex sentence.', 'most_to_least', '1. Model clause-by-clause then combined > 2. Full model > 3. Independent.', 'Re-model with clausal segmentation; reinforce accurate complex structure echo; shape word order.', 'Progress from simple relative clauses to more complex embedded structures.', 'CRF for accurate complex sentence echoics. Connect to linguistic structure training.', 'Generalize complex sentence echoics to varied grammatical structures used in conversation.', 'Monthly probe: accuracy of complex sentence echoics across varied clause types.'),
('ECH-11', 'Echoic', 'Record phoneme-level accuracy per word produced. Criterion: all phonemes correct 80%+ within words across 3 sessions.', 'ECH-10 (complex sentences); ECH-9 (minimal pairs); near-complete phoneme repertoire established.', 'No physical materials. Varied word list covering all English phonemes in varied word positions.', 'Therapist models target word. Child echoes. Analyze each phoneme for accuracy.', 'Child echoes and produces all phonemes correctly within words across multiple contexts.', 'Phoneme substitutions, deletions, or distortions on specific phonemes across word positions.', 'most_to_least', '1. Exaggerate target phoneme in model > 2. Standard model > 3. Independent.', 'Re-model problematic phoneme; use articulation cue; reinforce correct production; re-probe.', 'Coordinate with SLP for articulation assessment. Target phonemes in error systematically.', 'CRF for phoneme-accurate productions. Shape approximations toward accurate phoneme production.', 'Generalize accurate phoneme production to spontaneous speech across all contexts. Coordinate with SLP.', 'Monthly articulation probe across all phonemes in varied word positions. Track error patterns.'),
('ECH-12', 'Echoic', 'Record accuracy of multisyllabic word and tongue twister echoics. Criterion: 80%+ across 3 sessions.', 'ECH-11 (all phonemes at 80%+); fluent word-level articulation; motor sequencing for multisyllabic words.', 'No physical materials. Multisyllabic targets: "refrigerator," "elementary," "caterpillar." Tongue twisters: "red lorry, yellow lorry."', 'Therapist models multisyllabic word or tongue twister once at natural rate. Wait 5 seconds.', 'Child echoes multisyllabic words and tongue twisters with accurate articulation within 5 seconds.', 'Simplifies syllable structure, reverses syllables, or cannot produce tongue twister accurately.', 'most_to_least', '1. Syllable-by-syllable then combined > 2. Slow full model > 3. Natural-rate model, independent.', 'Re-model with syllable segmentation; shape toward accurate full word; reinforce best production.', 'Build from 3-syllable to 5-syllable to tongue twister difficulty. Monitor for fatigue.', 'CRF for accurate multisyllabic echoics. Social praise for tongue twister accuracy.', 'Generalize multisyllabic accuracy to naturalistic speech. Monitor in conversation samples.', 'Monthly probe: multisyllabic word accuracy across trained and novel long words.'),
('ECH-13', 'Echoic', 'Record prosody and intonation accuracy per sentence. Criterion: appropriate prosody on 80%+ of sentence echoics across 3 sessions.', 'ECH-12 (multisyllabic words); ECH-10 (complex sentences); awareness of intonation patterns.', 'No physical materials. Varied sentence types: declarative, interrogative, exclamatory for prosody targets.', 'Therapist models sentence with clear prosody and intonation. Child echoes with matched prosody.', 'Child echoes sentences while maintaining appropriate prosody, stress, and intonation patterns.', 'Flat/robotic intonation, misplaced stress, or inappropriate prosody pattern for sentence type.', 'most_to_least', '1. Exaggerate prosody in model > 2. Standard prosodic model > 3. Independent.', 'Re-model with exaggerated prosody; reinforce any prosodic improvement; fade exaggeration.', 'Teach declarative vs. interrogative intonation first. Progress to emotional prosody and emphasis.', 'CRF for appropriate prosody. Social praise for natural-sounding intonation.', 'Generalize prosody to conversational speech. Coordinate with SLP for prosody assessment.', 'Monthly prosody probe: rate naturalness of sentence prosody across varied sentence types.'),
('ECH-14', 'Echoic', 'Record grammatical structure accuracy per sentence echoic. Criterion: 80%+ across 3 sessions for varied sentence structures.', 'ECH-13 (prosody); ECH-10 (complex sentences); strong grammatical knowledge.', 'No physical materials. Novel sentences with correct grammatical structure across varied types.', 'Therapist models a novel sentence with specific grammatical structure. Child echoes.', 'Child echoes and repeats novel sentences with correct grammatical structure within 5 seconds.', 'Grammatical errors in echo (tense, agreement, structure), omissions, or substitutions.', 'most_to_least', '1. Stress grammatical morpheme in model > 2. Standard model > 3. Independent.', 'Re-model with grammatical morpheme emphasized; reinforce structurally accurate echo.', 'Target specific grammatical structures: past tense, plural, possessive, passive voice.', 'CRF for grammatically accurate sentence echoics. Connect to linguistic structure training.', 'Generalize grammatical echoics to spontaneous speech production. Coordinate with SLP.', 'Monthly probe: grammatical accuracy in sentence echoics across varied structure types.'),
('ECH-15', 'Echoic', 'Record content accuracy per paragraph echoic trial. Criterion: 80%+ content recall across 3 sessions.', 'ECH-14 (novel sentences); strong working memory; narrative processing ability.', 'No physical materials. 3-sentence paragraph targets on varied topics.', 'Therapist reads 3-sentence paragraph at natural rate. "Say what I said." Wait 5 seconds.', 'Child echoes paragraphs of 3+ sentences with accurate content recall within 10 seconds.', 'Recalls fewer than 2 sentences, adds content not in paragraph, or inverts sentence order.', 'most_to_least', '1. Echo sentence by sentence > 2. Echo 2 sentences then 3 > 3. Full paragraph, independent.', 'Re-model with sentence-by-sentence chunking; shape toward full paragraph recall.', 'Build from 2-sentence to 4-sentence paragraphs. Use narratively coherent content for easier recall.', 'CRF for accurate paragraph echoing. High praise for content accuracy.', 'Generalize to conversational paraphrasing and story retelling.', 'Monthly probe: paragraph content accuracy across varied topic areas and paragraph lengths.')
ON CONFLICT (milestone_code) DO UPDATE
SET vbmapp_domain = EXCLUDED.vbmapp_domain,
    data_collection = EXCLUDED.data_collection,
    prerequisite_skills = EXCLUDED.prerequisite_skills,
    materials = EXCLUDED.materials,
    sd = EXCLUDED.sd,
    correct_responses = EXCLUDED.correct_responses,
    incorrect_responses = EXCLUDED.incorrect_responses,
    prompting_hierarchy = EXCLUDED.prompting_hierarchy,
    prompting_hierarchy_detail = EXCLUDED.prompting_hierarchy_detail,
    error_correction = EXCLUDED.error_correction,
    transfer_procedure = EXCLUDED.transfer_procedure,
    reinforcement_schedule = EXCLUDED.reinforcement_schedule,
    generalization_plan = EXCLUDED.generalization_plan,
    maintenance_plan = EXCLUDED.maintenance_plan,
    template_origin = EXCLUDED.template_origin;

-- ============================================================
-- LRFFC (LFF-1 through LFF-15)
-- ============================================================

INSERT INTO vbmapp_milestone_templates (milestone_code, vbmapp_domain, data_collection, prerequisite_skills, materials, sd, correct_responses, incorrect_responses, prompting_hierarchy, prompting_hierarchy_detail, error_correction, transfer_procedure, reinforcement_schedule, generalization_plan, maintenance_plan) VALUES
('LFF-1', 'LRFFC', 'Record C/I/P per LRFFC trial. Criterion: 90%+ independent across 3 sessions.', 'Basic listener responding (array of 2); basic category exposure; tact repertoire emerging.', 'Array of 3 items from 1 category plus 2 distractors. Function cues prepared.', 'Present array of 3 items. SD: "Find something you eat" or "Find something you write with." Wait 5 s.', 'Child selects correct item from array of 3 when given a function cue, within 5 seconds independently.', 'Selects distractor, no response, or requires gestural prompt.', 'most_to_least', '1. Gestural (point to correct item) > 2. Partial verbal cue > 3. Independent.', 'Point to correct item; briefly explain function; re-probe after known trial.', 'Begin with highly distinctive function cues for familiar items. Rotate cue types.', 'CRF during acquisition. VR2 after mastery.', 'Generalize across 3+ function cues for varied items. Practice in naturalistic functional contexts.', 'Monthly probes with novel function cues for trained items.'),
('LFF-2', 'LRFFC', 'Record C/I/P per LRFFC trial for 5 items. Criterion: 90%+ across 3 sessions.', 'LFF-1 (function cue from array of 3); basic receptive vocabulary; some functional object knowledge.', 'Arrays of 3 items for each of 5 target function cues. Rotate arrays across trials.', 'Present array of 3. SD: "Find something that ___" [function]. One cue per trial.', 'Child identifies 5 different items by function from a field of 3 items, independently.', 'Identifies fewer than 5 items consistently; requires prompts for some items; position-bound responding.', 'most_to_least', '1. Gestural for missed items > 2. Independent. Most items at criterion level.', 'Re-probe missed items with gestural prompt; add to active teaching rotation; re-probe.', 'Expand from 5 to 10 items once 5 mastered. Rotate which items are in the active teaching set.', 'CRF for new items; VR2 for mastered items.', 'Generalize each of the 5 items across varied distractors and settings.', 'Monthly probes across all 5 items. Track accuracy per item type (function/feature/class).'),
('LFF-3', 'LRFFC', 'Record C/I/P per feature cue trial. Criterion: 90%+ across 3 sessions for 5+ feature attributes.', 'LFF-2 (5 items by function); tact of attributes (color, size, shape) emerging; LR-12 emerging.', 'Arrays of items varying on target feature (red item among non-red; round item among non-round).', 'SD: "Find the red one" / "Find the round one" / "Find the big one." Array of 3-4 items.', 'Child selects items from array based on feature cue (color, size, shape) without the item name, independently.', 'Selects by item identity not feature, requires feature cue repeated, or no response.', 'most_to_least', '1. Gestural (point to feature on sample then array) > 2. Re-state feature cue > 3. Independent.', 'Point to target feature on correct item; re-probe after brief distractor; reinforce correct selection.', 'Begin with maximally distinctive feature cues (red vs. not red). Progress to size and shape.', 'CRF during acquisition; VR2 once all feature types established.', 'Generalize feature-based selection to varied items and categories. Connect to tact of attributes.', 'Monthly probes across all feature cue types: color, size, shape, texture.'),
('LFF-4', 'LRFFC', 'Record C/I/P per class cue trial. Criterion: 90%+ across 3 sessions for 5+ category classes.', 'LFF-3 (feature cues); VP-8 (5-category sort); basic categorical knowledge.', 'Arrays including items from target class and non-class distractors. 5+ target classes prepared.', 'SD: "Find a fruit" / "Find an animal" / "Find a vehicle." Array of 3-4 items. One SD per trial.', 'Child selects items by class membership from an array without item name in SD, independently.', 'Selects non-class item, cannot identify class membership, or requires prompt.', 'most_to_least', '1. Gestural > 2. Partial class definition ("It is a kind of ___") > 3. Independent.', 'Point to correct class member; briefly define class membership; re-probe.', 'Begin with most familiar classes (animals, food, vehicles). Progress to subcategories.', 'CRF during acquisition; VR2 once all 5 classes mastered.', 'Generalize to novel members of each class. Practice in naturalistic categorization contexts.', 'Monthly probes with novel class members as distractors and targets.'),
('LFF-5', 'LRFFC', 'Record C/I/P per LRFFC trial. Criterion: 90%+ across 3 sessions for 10 items across function/feature/class.', 'LFF-4 (class cues); LFF-3 (feature cues); LFF-2 (5 items by function). Combined FFC repertoire.', 'Arrays of 3 items for each of 10 targets. Mix function, feature, and class cues across trials.', 'Present array of 3. SD varies: function, feature, or class cue. Rotate all 3 types.', 'Child identifies 10 items by function, feature, or class from an array of 3, independently.', 'Performs well on function but not class cues (or vice versa); below 90% on some cue types.', 'most_to_least', '1. Gestural for missed items/cue types > 2. Independent.', 'Re-probe missed items with gestural prompt; identify which cue type is weakest; add targeted practice.', 'Ensure equal probing of all 3 cue types across sessions. Expand to 15 items once 10 mastered.', 'CRF for new items; VR2 for mastered items.', 'Vary arrays to include novel distractors. Generalize across 3+ settings.', 'Monthly probe of all 10 items with mixed FFC cues. Track accuracy per cue type.'),
('LFF-6', 'LRFFC', 'Record C/I/P per LRFFC trial. Criterion: 90%+ across 3 sessions for 25 items from arrays of 5+.', 'LFF-5 (10 items from array of 3); expanding LRFFC repertoire; listener responding for 25+ items.', 'Arrays of 5+ items for each target LRFFC trial. Large pool of 25+ items organized by category.', 'Present array of 5+. SD: function, feature, or class cue. Rotate all items across sessions.', 'Child identifies 25 items by function, feature, or class from a field of 5+ items, independently.', 'Errors on items that were 90%+ in smaller arrays; position-based errors; requires prompt.', 'most_to_least', '1. Gestural for individual missed items > 2. Independent.', 'Re-probe missed items; rotate array composition to reduce position bias.', 'Expand array from 5 to 8 items as accuracy builds. Increase item pool from 25 to 50.', 'VR2-VR3 for established items; CRF for newly added items.', 'Generalize across novel distractors and novel examples of each item.', 'Monthly rotating probe of 25-item pool. Track which items fall below 80%.'),
('LFF-7', 'LRFFC', 'Record C/I/P per 2-component LRFFC trial. Criterion: 80%+ across 3 sessions.', 'LFF-6 (25 items from field of 5+); attribute tacting established; basic logical AND processing.', 'Arrays of 5+ items varying on 2 attributes simultaneously (big vs. small red ball; red vs. blue big ball).', 'SD: "Find the big red ball" / "Find the small blue cup." Two attributes specified per SD. Array of 5+.', 'Child correctly responds to 2-component LRFFC cues specifying 2 simultaneous attributes, independently.', 'Selects item matching only 1 attribute, requires prompt, or cannot process 2-component cue.', 'most_to_least', '1. Re-state each component separately, then together > 2. Gestural > 3. Independent.', 'Re-state components one at a time; point to attribute; re-present combined cue; reinforce.', 'Begin with attribute pairs that are easily discriminated. Progress to more subtle combinations.', 'CRF during acquisition; VR2 once 2-component LRFFC is reliable across 10+ combinations.', 'Generalize to varied 2-attribute combinations across different categories.', 'Monthly probes with novel 2-component cue combinations. Track error patterns per attribute pair.'),
('LFF-8', 'LRFFC', 'Record C/I/P per category member identification trial. Criterion: 80%+ across 3 sessions for 10 categories.', 'LFF-7 (2-component LRFFC); LFF-4 (5 class cues); broad categorical knowledge.', 'Verbal descriptions of category membership across 10 distinct categories. No visual materials during SD.', 'SD: "Name something that lives in the ocean" or presented as array with verbal description cue.', 'Child identifies category members from verbal descriptions across 10 different categories.', 'Cannot identify category members, names items from wrong category, or requires visual support.', 'most_to_least', '1. Category visual (photo array) > 2. Partial verbal hint > 3. Verbal SD only, independent.', 'Provide category visual if needed; fade to verbal-only; re-probe without visual.', 'Expand from 10 to 20 categories. Include subcategory descriptions.', 'CRF during acquisition; VR2 once all 10 categories reliable.', 'Generalize to novel category members within trained categories. Practice in conversational contexts.', 'Monthly probe: category member identification across all 10 categories without visual support.'),
('LFF-9', 'LRFFC', 'Record C/I/P per no-visual LRFFC trial. Criterion: 80%+ across 3 sessions.', 'LFF-8 (category members); LFF-7 (2-component LRFFC); strong categorical and functional knowledge.', 'No physical materials during SD. Child responds verbally or points to mental image. May use small array.', 'SD given verbally with no visual array: "Think of something you would use to cut paper." Verbal response expected.', 'Child selects or names items from verbal descriptions alone, without visual cues or pictures, independently.', 'Cannot respond without visual support, gives unrelated answer, or requires visual array.', 'most_to_least', '1. Provide visual array initially, then fade > 2. Verbal SD only, independent.', 'Re-introduce visual briefly; fade array items one at a time across sessions until no visual needed.', 'Build this skill after strong visual LRFFC is established. Use as a bridge to intraverbal training.', 'CRF for verbal-only LRFFC responses; VR2 once reliable across 10+ items.', 'Generalize to novel items and descriptions. Practice in conversational contexts.', 'Monthly probe: verbal-only LRFFC accuracy across varied function, feature, class descriptions.'),
('LFF-10', 'LRFFC', 'Record C/I/P per in-context LRFFC trial. Criterion: 80%+ across 3 sessions.', 'LFF-9 (no-visual LRFFC); LFF-8 (10 categories); emerging narrative comprehension.', 'Storybooks, conversational scripts, or verbal stories. No specific materials needed.', 'Embed LRFFC cues in a story or conversation: "In the story, he used something to cut - what was it?"', 'Child responds to LRFFC cues embedded in stories and conversational contexts without explicit framing.', 'Loses LRFFC meaning when embedded in narrative; requires the cue to be restated in isolation.', 'most_to_least', '1. Restate LRFFC cue in isolation > 2. Re-read sentence with LRFFC cue highlighted > 3. Independent.', 'Restate the LRFFC cue clearly; re-embed in simpler context; re-probe in full narrative.', 'Build from simple 2-sentence stories to complex narrative LRFFC contexts.', 'CRF for in-context LRFFC responses. Natural reading/conversation as reinforcement.', 'Generalize to varied story genres and conversational topics. Bridge to reading comprehension.', 'Monthly probe: LRFFC accuracy when embedded in narrative vs. isolated presentation.'),
('LFF-11', 'LRFFC', 'Record accuracy per session across 100-item LRFFC pool. Criterion: 90%+ from varied arrays across 3 sessions.', 'LFF-10 (in-context LRFFC); full FFC repertoire built across Levels 1-2; broad categorical knowledge.', 'Large rotating pool of pictures across 15+ categories; arrays of 5-8 items; varied FFC cue types.', 'Present LRFFC cue from full array. Rotate through all 100 items across sessions.', 'Child identifies 100+ items by function, feature, or class from varied arrays, independently.', 'Errors on previously mastered items; position-based responding; cue-type weaknesses.', 'most_to_least', '1. Gestural for individual missed items > 2. Independent. Most items at maintenance.', 'Re-teach individual items below 80% with focused acquisition block.', 'Rotate arrays and cue types to prevent habituation. Probe all items monthly.', 'VR3 for established items; CRF for newly added items.', 'Generalize to novel exemplars and novel category members. Test in community contexts.', 'Monthly rotating 25-item probe sampling across all 100 items.'),
('LFF-12', 'LRFFC', 'Record C/I/P per complex 3-component LRFFC trial. Criterion: 80%+ across 3 sessions.', 'LFF-11 (100 items); LFF-7 (2-component LRFFC); advanced attribute processing.', 'Arrays of 6+ items varying on 3 attributes. Complex descriptor sets prepared.', 'SD: "Find the big, red, round one" or "Find the small thing you use to write that is blue."', 'Child responds to LRFFC cues with 3 or more component descriptors, independently.', 'Selects item matching only 1-2 components; cannot hold 3 attributes simultaneously.', 'most_to_least', '1. Restate each component > 2. Gestural after re-stating all 3 > 3. Independent.', 'Restate components one at a time; provide gestural; re-present 3-component cue; reinforce.', 'Build from 2-component to 3-component gradually. Use items where all 3 attributes are salient.', 'CRF during acquisition; VR2 once 3-component LRFFC is reliable.', 'Generalize to novel 3-component cue combinations. Connect to academic task descriptions.', 'Monthly probes with novel 3-component combinations. Track accuracy per number of attributes.'),
('LFF-13', 'LRFFC', 'Record C/I/P per relationship-based LRFFC trial. Criterion: 80%+ across 3 sessions.', 'LFF-12 (3-component LRFFC); LFF-9 (verbal-only LRFFC); relational reasoning.', 'Paired items where relationship must be inferred: lock/key, needle/thread, puzzle/piece.', 'SD: "Find the thing that goes with a lock" or "Find what you need to thread a needle." Verbal only.', 'Child identifies relationships between items based on verbal descriptions alone, independently.', 'Identifies one item without inferring the relationship, requires visual prompt, or guesses randomly.', 'most_to_least', '1. Visual pair shown first > 2. Verbal-only SD > 3. Independent.', 'Show the related pair briefly; fade visual; re-present verbal-only relationship SD; reinforce.', 'Begin with high-familiarity complementary pairs. Progress to functional and part-whole relationships.', 'CRF during acquisition; VR2 once relational LRFFC is reliable across 10+ pairs.', 'Generalize to novel item relationships and abstract relationships.', 'Monthly probes with novel relationship pairs. Track relational reasoning development.'),
('LFF-14', 'LRFFC', 'Record LRFFC accuracy in community/naturalistic settings. Criterion: 80%+ across 3 community observations.', 'LFF-13 (relationship-based LRFFC); full LRFFC repertoire; generalization to naturalistic contexts.', 'Community and naturalistic settings: grocery store, kitchen, classroom, playground.', 'Embed LRFFC tasks naturally: "Find something we use to pay" at store; "Find a vegetable" at grocery.', 'Child completes LRFFC tasks in community and naturalistic settings without contrived setup or prompts.', 'Requires contrived table setup; cannot identify items in naturalistic context; needs explicit LRFFC framing.', 'least_to_most', '1. No prompt > 2. Informal verbal cue embedded in conversation > 3. Explicit LRFFC SD.', 'Provide explicit SD only if informal cue fails; fade back to naturalistic embedding as soon as possible.', 'Plan community outings with embedded LRFFC opportunities. Coordinate with family for home practice.', 'Natural activity access as reinforcement (buying the identified item at the store).', 'Generalize across multiple community settings and novel naturalistic contexts.', 'Monthly community LRFFC observation. Track accuracy and need for explicit vs. naturalistic prompting.'),
('LFF-15', 'LRFFC', 'Record use of LRFFC skills in academic and social contexts. Criterion: independently applies LRFFC reasoning 80%+ of academic/social opportunities across 3 sessions.', 'LFF-14 (community LRFFC); full LRFFC repertoire across Levels 1-3; academic language skills.', 'Academic materials (science textbooks, math word problems); social conversation contexts.', 'Naturally occurring academic or social task requiring LRFFC reasoning: "Which tool would you use?" in science.', 'Child uses LRFFC skills to follow complex directions and understand descriptions in academic and social settings.', 'Cannot apply LRFFC reasoning to academic content; requires explicit LRFFC framing outside of teaching context.', 'least_to_most', '1. No prompt > 2. Draw attention to key descriptor > 3. Explicit LRFFC question.', 'Reframe academic task as explicit LRFFC question; re-present in context; reinforce correct application.', 'Coordinate with teachers to identify academic LRFFC opportunities. Embed in all subject areas.', 'Natural academic success as reinforcement. Social praise for LRFFC-based reasoning.', 'Monitor LRFFC application across all academic subjects and social contexts.', 'Monthly academic LRFFC observation: track unprompted application of LRFFC reasoning.')
ON CONFLICT (milestone_code) DO UPDATE
SET vbmapp_domain = EXCLUDED.vbmapp_domain,
    data_collection = EXCLUDED.data_collection,
    prerequisite_skills = EXCLUDED.prerequisite_skills,
    materials = EXCLUDED.materials,
    sd = EXCLUDED.sd,
    correct_responses = EXCLUDED.correct_responses,
    incorrect_responses = EXCLUDED.incorrect_responses,
    prompting_hierarchy = EXCLUDED.prompting_hierarchy,
    prompting_hierarchy_detail = EXCLUDED.prompting_hierarchy_detail,
    error_correction = EXCLUDED.error_correction,
    transfer_procedure = EXCLUDED.transfer_procedure,
    reinforcement_schedule = EXCLUDED.reinforcement_schedule,
    generalization_plan = EXCLUDED.generalization_plan,
    maintenance_plan = EXCLUDED.maintenance_plan,
    template_origin = EXCLUDED.template_origin;

-- ============================================================
-- INTRAVERBAL (IV-1 through IV-15)
-- ============================================================

INSERT INTO vbmapp_milestone_templates (milestone_code, vbmapp_domain, data_collection, prerequisite_skills, materials, sd, correct_responses, incorrect_responses, prompting_hierarchy, prompting_hierarchy_detail, error_correction, transfer_procedure, reinforcement_schedule, generalization_plan, maintenance_plan) VALUES
('IV-1', 'Intraverbal', 'Record C/I/P per fill-in trial. Criterion: 80%+ across 3 sessions for 2 different fill-ins.', 'Basic vocal or AAC communication; some echoic ability; exposure to repetitive phrases and songs.', 'Common fill-in phrases from routines: "Ready, set, ___", "One, two, ___", "Ready or ___?"', 'Therapist states the phrase and pauses at the blank with expectant look. Wait 5 s.', 'Child completes 2 different fill-in-the-blank phrases spontaneously within 5 seconds.', 'No response in 5 s, echoes the entire phrase including the last word, or produces unrelated vocalization.', 'least_to_most', '1. Wait 5 s (expectant pause) > 2. Partial verbal prompt (first sound of answer) > 3. Full model.', 'Re-state phrase; provide partial verbal prompt; reinforce any completion attempt; re-probe.', 'Use highly familiar routine phrases. Embed in songs and daily transitions for natural context.', 'CRF for any fill-in completion. Thin to VR2 once both fill-ins reliable.', 'Generalize fill-ins to 3+ different adults and contexts where the phrase naturally occurs.', 'Monthly probes: fill-in accuracy for trained and novel routine phrases.'),
('IV-2', 'Intraverbal', 'Record C/I/P per personal question trial. Criterion: 80%+ across 3 sessions for name and age.', 'IV-1 (2 fill-ins); basic vocal or AAC; knows own name in some context.', 'No materials. Conversational setting. Target questions: "What is your name?" "How old are you?"', 'Therapist asks "What is your name?" or "How old are you?" once at natural rate. Wait 5 s.', 'Child answers questions about own name and age with accurate information within 5 seconds.', 'Echoes the question, gives unrelated answer, or no response in 5 s.', 'most_to_least', '1. Full verbal model of correct answer > 2. Partial model (first sound/syllable) > 3. Independent.', 'Model correct answer; request imitation; easy fill-in trial; re-probe original question.', 'Expand to other personal facts (last name, birthday, address) once name and age are reliable.', 'CRF for correct personal information responses. Natural social reinforcement.', 'Generalize to novel adults in varied settings (school, community, home).', 'Monthly probe: accuracy of personal information across varied questioners and settings.'),
('IV-3', 'Intraverbal', 'Record C/I/P per fill-in trial. Criterion: 80%+ across 3 sessions for 5 different fill-in phrases.', 'IV-1 (2 fill-ins at 80%+); IV-2 (name and age); growing repertoire of familiar routine phrases.', '5 target fill-in phrases from routines, songs, and daily activities. Rotate across sessions.', 'Therapist states each of 5 target phrases with expectant pause. Vary phrase order each session.', 'Child completes 5 different fill-in phrases from familiar routines within 5 seconds, independently.', 'Completes fewer than 5 different fill-ins; requires verbal prompt for some phrases.', 'least_to_most', '1. Expectant pause > 2. First sound prompt > 3. Full model.', 'Re-state phrase with expectant pause; partial prompt; reinforce any completion; re-probe.', 'Add 2 new fill-in phrases per week. Include songs (Wheels on the Bus), routines, and greetings.', 'CRF during acquisition of each phrase; VR2 once all 5 stable.', 'Generalize to 3+ adults and varied settings where each routine phrase occurs naturally.', 'Monthly probe of all 5 fill-in phrases. Track accuracy and speed of completion.'),
('IV-4', 'Intraverbal', 'Record C/I/P per yes/no question trial. Criterion: 80%+ across 3 sessions for 10 varied questions.', 'IV-3 (5 fill-ins); basic preference awareness; some social communication motivation.', 'No materials. Yes/no questions about clear preferences: "Do you want juice?" "Is this a ball?"', 'Therapist asks yes/no question about child preference or known fact. Wait 5 s for answer.', 'Child answers yes or no questions about own preferences or feelings accurately within 5 seconds.', 'Echoes question, answers yes for everything, answers no for everything, or no response.', 'most_to_least', '1. Model yes or no based on context > 2. Choice prompt ("Yes or no?") > 3. Independent.', 'Model correct yes/no; request imitation; re-probe same question; reinforce correct answer.', 'Use clear preference items (loves vs. dislikes) to establish yes/no discrimination first.', 'CRF for accurate yes/no. Deliver or withhold item based on answer to build meaning.', 'Generalize to varied yes/no questions across personal preferences, facts, and social questions.', 'Monthly probe: yes/no accuracy across preference, factual, and social question types.'),
('IV-5', 'Intraverbal', 'Record C/I/P per greeting reply trial. Criterion: 80%+ appropriate reply across 3 sessions.', 'IV-4 (yes/no questions); SOC-5 (spontaneous greetings); basic conversational awareness.', 'Natural greeting contexts. Target: "Hi/Hello," "How are you?", "Goodbye."', 'Therapist or peer initiates greeting. Observe whether child provides appropriate intraverbal reply.', 'Child responds to greetings with appropriate intraverbal replies without adult prompting.', 'Echoes the greeting exactly, no response, or gives unrelated verbal response.', 'least_to_most', '1. No prompt (expectant wait) > 2. Partial verbal ("Say ___") > 3. Full model of reply.', 'Model appropriate reply; request imitation; re-create greeting opportunity; reinforce natural reply.', 'Teach varied greeting exchanges. Progress from scripted to spontaneous greeting replies.', 'CRF for appropriate greeting replies. Natural social reciprocity as primary reinforcement.', 'Generalize greeting intraverbals to novel adults, peers, and all natural greeting contexts.', 'Monthly probe: greeting reply accuracy across varied greeting types and social partners.'),
('IV-6', 'Intraverbal', 'Record C/I/P per wh-question trial. Criterion: 80%+ across 3 sessions for 10 different wh-questions.', 'IV-5 (greeting replies); IV-3 (5 fill-ins); tact repertoire of 50+; basic vocabulary for topics.', 'Question cards optional. Target wh-questions: who, what, where, when, which for familiar topics.', 'Therapist asks 1 wh-question about a familiar topic. "What do you eat for breakfast?" Wait 5 s.', 'Child answers 10 different wh-questions about familiar and known topics within 5 seconds.', 'Echoes the question, gives unrelated answer, or cannot answer more than 5 different questions.', 'most_to_less', '1. Visual support (picture of topic) > 2. Partial verbal prompt > 3. Independent.', 'Provide picture if needed; fade visual; give partial answer prompt; re-probe full question.', 'Rotate question types (who, what, where) within sessions. Expand to abstract/temporal questions.', 'CRF during acquisition; VR2 once 10 questions stable.', 'Generalize to novel topics and varied questioners across home, school, and community.', 'Monthly probe: wh-question accuracy across all question types and varied topics.'),
('IV-7', 'Intraverbal', 'Record C/I/P per fill-in trial. Criterion: 80%+ across 3 sessions for 20 fill-in phrases.', 'IV-6 (10 wh-questions); IV-3 (5 fill-ins); growing repertoire of songs and routines.', '20+ target fill-in phrases from songs, routines, and common expressions. Organized by source.', 'Rotate through all 20 target phrases across sessions. Expectant pause at blank position.', 'Child completes 20 fill-in phrases from songs and familiar routines within 5 seconds, independently.', 'Completes fewer than 15 phrases; requires prompts for songs not practiced recently.', 'least_to_most', '1. Expectant pause > 2. First word/sound > 3. Full model.', 'Partial prompt for less-practiced phrases; re-probe; reinforce; rotate practice frequency.', 'Include songs from music class, home, and therapy. Target fill-ins with strong MOs (favorite songs).', 'VR2 for well-established phrases; CRF for newly added ones.', 'Generalize to fill-ins with novel adults and in varied group/individual contexts.', 'Monthly probe of rotating 10-phrase sample from full 20-phrase pool.'),
('IV-8', 'Intraverbal', 'Record C/I/P per category naming trial. Criterion: 80%+ across 3 sessions for 5 categories (3+ items each).', 'IV-7 (20 fill-ins); IV-6 (10 wh-questions); tact repertoire organized by category.', 'Category cards optional. 5 target categories: animals, food, vehicles, clothing, furniture.', 'Therapist asks "Name some animals" or "Tell me some foods." Wait for 3+ different items.', 'Child names 3 or more items in a category when asked, for 5 different categories, independently.', 'Names fewer than 3 items, perseverates on same item, or names items from wrong category.', 'most_to_least', '1. Partial list prompt ("One is a dog, name more") > 2. Category visual > 3. Independent.', 'Provide first item as prompt; reinforce each additional item named; re-probe independently.', 'Expand from 5 to 10 categories. Include subcategories and semantic categories.', 'CRF per additional category item named. Social praise for fluent category naming.', 'Generalize to novel categories and novel questioners across settings.', 'Monthly probe: category naming fluency (number of items per minute per category).'),
('IV-9', 'Intraverbal', 'Record C/I/P per story/event comprehension question trial. Criterion: 80%+ across 3 sessions.', 'IV-8 (category naming); IV-6 (10 wh-questions); basic narrative comprehension.', 'Picture books read aloud or short verbal stories. Comprehension questions prepared.', 'Therapist reads story aloud, then asks wh-questions about story content. "What did the dog do?"', 'Child answers questions about stories and events that have been read aloud, accurately within 5 s.', 'Cannot recall story content, answers based on pictures only, or gives unrelated responses.', 'most_to_least', '1. Re-read relevant sentence > 2. Point to picture cue > 3. Independent.', 'Re-read target sentence; provide picture support; re-ask question; fade support gradually.', 'Begin with simple 3-sentence stories. Progress to longer narratives with more complex questions.', 'CRF during initial story comprehension acquisition; VR2 once skill is reliable.', 'Generalize to varied story types and to retelling events from child own daily life.', 'Monthly probe: story comprehension accuracy across new unfamiliar books.'),
('IV-10', 'Intraverbal', 'Record exchange count per conversation topic. Criterion: maintains 3-exchange conversation on 3 different topics across 3 sessions.', 'IV-9 (story comprehension); IV-6 (10 wh-questions); basic turn-taking in conversation.', 'Preferred topics identified. Conversational contexts: free time, snack, transitions.', 'Therapist initiates conversation on preferred topic. Observe whether child maintains 3 exchanges.', 'Child maintains a topic during 3-exchange conversations with familiar partners, independently.', 'Only 1-2 exchanges before topic drops; requires continuous prompts to maintain topic.', 'least_to_most', '1. No prompt > 2. Conversational bridge ("Tell me more about that") > 3. Direct question to continue.', 'Provide bridging question; reinforce continuation of topic; fade prompts across conversations.', 'Begin with highly motivating topics. Gradually expand to less-preferred conversation topics.', 'Natural social reciprocity as reinforcement. Social praise for on-topic maintenance.', 'Generalize to varied familiar adults and varied conversation topics.', 'Monthly probe: average exchange count per conversation across varied topics.'),
('IV-11', 'Intraverbal', 'Record accuracy of past/future event responses. Criterion: 80%+ accurate with appropriate detail across 3 sessions.', 'IV-10 (3-exchange conversations); IV-9 (story comprehension); temporal language understanding.', 'No materials. Questions about past events (yesterday, this morning) and future events (tomorrow, later).', 'Therapist asks: "What did you do this morning?" "What will you do after school?" Wait 5 s.', 'Child answers questions about past and future events with accurate and relevant detail.', 'Speaks only about present, confuses past/future, gives generic answer, or no response.', 'most_to_least', '1. Provide contextual cue ("You had breakfast, what did you eat?") > 2. Open-ended > 3. Independent.', 'Provide contextual support for specific memory; fade to open-ended; reinforce accurate recall.', 'Begin with very recent past (5 minutes ago). Extend to yesterday, last week. Build future tense similarly.', 'CRF for temporally accurate responses with relevant detail.', 'Generalize to varied past and future topics with multiple communication partners.', 'Monthly probe: temporal accuracy across past, future, and hypothetical event questions.'),
('IV-12', 'Intraverbal', 'Record exchange count per conversation session. Criterion: maintains 5+ reciprocal exchanges on varied topics across 3 sessions.', 'IV-11 (past/future events); IV-10 (3-exchange conversations); expanding conversational vocabulary.', 'Natural conversational contexts across varied topics (interests, events, opinions).', 'Observe natural conversations. Count reciprocal exchanges per topic. No specific setup.', 'Child engages in reciprocal conversations on varied topics for 5 or more exchanges, independently.', 'Conversations end after 2-3 exchanges; requires continuous adult support; only talks without listening.', 'least_to_most', '1. No prompt > 2. Conversational question to re-engage > 3. Direct prompt.', 'Re-engage with open-ended question; reinforce topic-linked responses; fade prompts.', 'Expand from preferred to neutral to novel conversation topics. Practice with multiple partners.', 'Natural social engagement as primary reinforcement. Enthusiastic social responses.', 'Generalize to novel partners, varied settings, and varied topic domains.', 'Monthly probe: average exchanges per conversation and topic variety across naturalistic observation.'),
('IV-13', 'Intraverbal', 'Record C/I/P per word definition or concept explanation trial. Criterion: 80%+ accurate explanations across 3 sessions.', 'IV-12 (5+ exchange conversations); strong intraverbal repertoire; advanced vocabulary.', 'No materials. Target words and concepts from child vocabulary repertoire.', 'Therapist asks "What is a ___?" or "What does ___ mean?" Wait 10 s for verbal response.', 'Child defines words and explains concepts verbally without visual supports, with relevant information.', 'Gives single-feature definition (only a category label), cannot explain, or requires visual prompt.', 'most_to_least', '1. Accept partial definition, prompt for more ("Tell me more") > 2. Independent full definition.', 'Accept partial definitions; prompt for elaboration; reinforce multi-feature explanations.', 'Begin with concrete familiar words (apple, chair). Progress to abstract concepts (fair, brave).', 'CRF for complete definitions with 2+ relevant features. Social praise for elaborate explanations.', 'Generalize to novel vocabulary from academic contexts and social situations.', 'Monthly probe: definition quality (number of relevant features per definition) across varied words.'),
('IV-14', 'Intraverbal', 'Record accuracy and sequencing of story/event retell. Criterion: 80%+ sequenced accurate retelling across 3 sessions.', 'IV-13 (word definitions); IV-11 (past/future events); narrative sequencing skills.', 'Recent stories or daily events. May use pictures initially then fade.', 'Therapist says "Tell me what happened in the story" or "Tell me about your morning." No cues.', 'Child retells stories and events with sequenced and accurate details without visual supports.', 'Cannot sequence events, omits major story elements, requires prompting for each event.', 'most_to_less', '1. Picture sequence support > 2. First event prompt only > 3. Independent retelling.', 'Provide first-event prompt; reinforce each subsequent correctly sequenced event.', 'Begin with familiar simple 3-event stories. Progress to longer personal narratives and novel stories.', 'CRF for complete sequenced retelling. Social reinforcement for engaging narrative content.', 'Generalize to novel stories, personal events, and formal retelling contexts (school report).', 'Monthly probe: story retelling completeness and sequencing accuracy across new stories.'),
('IV-15', 'Intraverbal', 'Record quality of debates, discussions, and perspective expressions. Criterion: 3+ occasions per session where child discusses/debates with perspective support across 3 sessions.', 'IV-14 (story retelling); IV-13 (word definitions); full intraverbal repertoire across Levels 1-3.', 'Discussion topics, debate prompts, or opinion questions. No materials otherwise.', 'Therapist introduces topic: "What do you think is the best pet and why?" Wait for elaborated response.', 'Child debates, discusses, and explains personal perspectives on varied topics with supporting reasoning.', 'States opinion with no reasoning; cannot elaborate beyond one sentence; requires continuous adult questions.', 'least_to_most', '1. No prompt > 2. "Why do you think that?" > 3. Specific elaboration question.', 'Prompt for reasoning once; allow child to elaborate; reinforce perspective + reason combinations.', 'Begin with concrete opinion topics (favorite foods). Progress to abstract social topics.', 'Natural conversation engagement as reinforcement. Social interest in child perspective.', 'Generalize to academic debate, peer discussions, and community conversations.', 'Monthly probe: perspective elaboration quality across varied opinion and debate topics.')
ON CONFLICT (milestone_code) DO UPDATE
SET vbmapp_domain = EXCLUDED.vbmapp_domain,
    data_collection = EXCLUDED.data_collection,
    prerequisite_skills = EXCLUDED.prerequisite_skills,
    materials = EXCLUDED.materials,
    sd = EXCLUDED.sd,
    correct_responses = EXCLUDED.correct_responses,
    incorrect_responses = EXCLUDED.incorrect_responses,
    prompting_hierarchy = EXCLUDED.prompting_hierarchy,
    prompting_hierarchy_detail = EXCLUDED.prompting_hierarchy_detail,
    error_correction = EXCLUDED.error_correction,
    transfer_procedure = EXCLUDED.transfer_procedure,
    reinforcement_schedule = EXCLUDED.reinforcement_schedule,
    generalization_plan = EXCLUDED.generalization_plan,
    maintenance_plan = EXCLUDED.maintenance_plan,
    template_origin = EXCLUDED.template_origin;

-- ============================================================
-- CLASSROOM ROUTINES (CR-1 through CR-15)
-- ============================================================

INSERT INTO vbmapp_milestone_templates (milestone_code, vbmapp_domain, data_collection, prerequisite_skills, materials, sd, correct_responses, incorrect_responses, prompting_hierarchy, prompting_hierarchy_detail, error_correction, transfer_procedure, reinforcement_schedule, generalization_plan, maintenance_plan) VALUES
('CR-1', 'Classroom Routines', 'Record duration of group sitting per session. Criterion: sits in group for 1+ minute without prompts across 3 sessions.', 'Basic sitting tolerance with adult; some environmental awareness; no severely disruptive competing behaviors.', 'Classroom group area (carpet, chairs); preferred group activity (story, music); adjacent reinforcers.', 'Child joins group activity. No individual prompts. Observe whether child remains seated for 1+ minute.', 'Child sits in a group setting for 1 or more minutes without adult prompts or redirection.', 'Leaves group before 1 minute, requires physical guidance to remain, or is highly disruptive.', 'least_to_most', '1. No prompt > 2. Proximity (stand near child) > 3. Gestural (tap seat) > 4. Verbal prompt.', 'Brief calm proximity without drawing attention to child; tap seat if leaving; reinforce return.', 'Build from 30 s to 2 min to 5 min incrementally. Use highly preferred group activities.', 'Token reinforcement at end of group sitting period. Peer activity as natural reinforcement.', 'Generalize to varied group settings: circle time, storytime, snack group, classroom.', 'Monthly group observation: duration of appropriate group sitting without prompts.'),
('CR-2', 'Classroom Routines', 'Record successful transitions per session. Criterion: transitions with single verbal prompt 80%+ across 3 sessions.', 'CR-1 (1-min group sitting); basic listener responding; tolerates activity change.', 'Visual schedule or first-then board optional. Natural classroom transition materials.', 'Give single verbal transition instruction: "Time to go to the table." Wait 5 s. Do not repeat.', 'Child transitions between 2 activities with a single verbal prompt from staff, within 5 seconds.', 'Does not move, requires repeated instruction, needs physical guidance, or has behavioral outburst.', 'most_to_least', '1. Physical guidance > 2. Gestural + verbal > 3. Single verbal only > 4. Visual schedule cue only.', 'Provide physical guidance; reinforce initiation of movement; fade to single verbal over sessions.', 'Use visual first-then board initially. Pair transitions with preferred destinations.', 'CRF for smooth transitions. Access to preferred next activity as natural reinforcement.', 'Generalize to all daily classroom transitions. Fade visual supports as verbal prompt suffices.', 'Monthly transition observation: proportion of transitions completed on first verbal prompt.'),
('CR-3', 'Classroom Routines', 'Record steps completed independently per classroom routine. Criterion: follows 2-step routine 80%+ without prompts across 3 sessions.', 'CR-2 (transition with 1 prompt); LR-6 (2-step instructions); basic classroom orientation.', 'Natural classroom materials for target routine (backpack rack, cubbies, seat materials).', 'Give single verbal instruction for 2-step routine. Wait. Observe whether both steps are completed.', 'Child follows a 2-step classroom routine such as hang backpack then sit down, independently.', 'Completes only 1 step, requires a second prompt, or needs physical guidance.', 'most_to_least', '1. Visual 2-step prompt card > 2. Verbal reminder for step 2 only > 3. Independent.', 'Provide step-2 verbal reminder only; reinforce full 2-step completion; fade reminder.', 'Use natural 2-step classroom routines. Embed in morning arrival and daily transitions.', 'CRF for complete 2-step routine completion. Natural activity access as reinforcement.', 'Generalize to novel 2-step routines in varied classroom contexts.', 'Monthly probe: 2-step routine completion rate across varied classroom routines.'),
('CR-4', 'Classroom Routines', 'Record on-task interval during structured activity. Criterion: stays on task 80%+ of 5-min session across 3 sessions.', 'CR-3 (2-step routine); basic attention to tasks; some interest in structured activities.', 'Structured activity materials (worksheet, puzzle, matching task); preferred activities available.', 'Set up structured activity. Seat child at table. Withdraw continuous adult attention. Observe.', 'Child stays on task for 5 minutes during structured activities with adult nearby.', 'Leaves task, is distracted, requires continuous adult attention, or refuses to engage.', 'least_to_most', '1. No prompt > 2. Brief re-direction to task > 3. Verbal prompt > 4. Proximity support.', 'Brief calm redirect to task; reinforce return to task; avoid extended adult interaction off-task.', 'Build from 2 min to 5 min by 1-min increments. Use preferred structured activities initially.', 'Check-in reinforcement at 2-min mark; end-of-task reinforcement. Token system optional.', 'Generalize on-task behavior to varied structured tasks and varied proximity of adults.', 'Monthly on-task interval recording across varied structured activity types.'),
('CR-5', 'Classroom Routines', 'Record whether child follows group instruction at same rate as individual instruction. Criterion: 80%+ group compliance matching individual compliance across 3 sessions.', 'CR-4 (5-min on-task); CR-2 (transition with 1 prompt); LR-4 (10 one-step instructions).', 'Natural classroom group settings. Group instructions prepared.', 'Give same instruction to group that has been mastered individually. Observe whether child responds.', 'Child responds to group instructions with the same compliance rate as individual instructions.', 'Responds to individual but not group instructions; requires name before following group SD.', 'most_to_least', '1. Individual name + group instruction > 2. Group instruction only > 3. Fade name-calling.', 'Add child name to group instruction; reinforce response; fade name over subsequent sessions.', 'Build a strong history of compliance to individual instructions before introducing group format.', 'Group contingency reinforcement. Natural group activity access. Peer-match praise.', 'Generalize to varied group instruction types and varied group sizes.', 'Monthly comparison: individual vs. group compliance rate for same instructions.'),
('CR-6', 'Classroom Routines', 'Record steps completed in morning routine. Criterion: completes 5-step routine independently 80%+ across 3 sessions.', 'CR-5 (group instructions); CR-3 (2-step routine); expanding routine independence.', 'Natural morning arrival materials: backpack, coat hook, sign-in sheet, desk, morning folder.', 'Arrive at school. No verbal prompts. Observe whether child completes full morning routine independently.', 'Child independently follows a 5-step morning arrival routine without prompts.', 'Skips steps, waits for prompts at each step, or completes steps in wrong order.', 'most_to_less', '1. Visual 5-step checklist > 2. Checklist + single verbal reminder > 3. Visual only > 4. Independent.', 'Prompt only missed step; fade systematic prompts; reinforce self-checking behavior.', 'Teach routine backward-chain or use visual checklist faded over weeks.', 'Natural activity access (start preferred activity when routine is complete) as reinforcement.', 'Generalize to novel morning routine variations (different classroom, substitute teacher).', 'Monthly morning routine observation: proportion of steps completed independently and in order.'),
('CR-7', 'Classroom Routines', 'Record instances of hand-raising and waiting before speaking. Criterion: 80%+ appropriate hand-raising across 3 group sessions.', 'CR-6 (5-step routine); CR-5 (group instructions); basic impulse control skills.', 'Natural classroom group instruction setting; hand-raising opportunity must be present.', 'Observe during group instruction. Do not individually prompt. Note hand-raising vs. blurting out.', 'Child raises hand and waits to be called on before speaking in group settings, without prompts.', 'Blurts out answer, raises hand but calls out name, or does not raise hand at all.', 'most_to_least', '1. Visual rule reminder (hand-raise icon visible) > 2. Gestural (point to raised hand icon) > 3. Independent.', 'Privately redirect to hand-raise rule; reinforce next hand-raising behavior immediately; do not call on blurt-outs.', 'Use group token economy to reinforce hand-raising across all students. Fade visual over time.', 'Group contingency reinforcement. Natural participation opportunities as reinforcement.', 'Generalize hand-raising to all group instruction settings and novel teachers.', 'Monthly observation: hand-raising rate as proportion of total participation opportunities.'),
('CR-8', 'Classroom Routines', 'Record successful independent transitions triggered by schedule cue. Criterion: 80%+ independent transitions across 3 sessions.', 'CR-7 (hand-raising); CR-6 (5-step routine); visual schedule understanding.', 'Visual daily schedule prominently displayed. All transition destinations familiar.', 'Present visual schedule cue (schedule check, timer) without verbal instruction. Observe transition.', 'Child transitions between activities independently when given a schedule cue, without verbal instruction.', 'Requires verbal reminder, asks adult what to do next, or ignores schedule cue.', 'most_to_least', '1. Verbal + schedule cue > 2. Schedule cue + gestural > 3. Schedule cue only > 4. Independent.', 'Point to schedule cue; provide gestural; reinforce independent schedule-directed transitions.', 'Teach how to check visual schedule. Practice schedule-checking as its own routine step.', 'Natural activity access as reinforcement for schedule-directed transitions.', 'Generalize to varied schedule formats (paper, digital, picture-based).', 'Monthly observation: proportion of transitions initiated by schedule cue without verbal prompt.'),
('CR-9', 'Classroom Routines', 'Record independent management of materials across school day. Criterion: manages materials independently 80%+ of opportunities across 3 days.', 'CR-8 (schedule-directed transitions); CR-6 (5-step routine); organization skills emerging.', 'Personal materials: backpack, binder, pencil case, lunch box. All items labeled.', 'Natural classroom context. Observe whether child independently locates, uses, and replaces materials.', 'Child manages personal materials and belongings independently throughout the day.', 'Loses materials, requires adult to locate items, cannot organize belongings without support.', 'least_to_most', '1. No prompt > 2. Environmental cue (labeled spaces) > 3. Verbal reminder.', 'Provide environmental cues (labeled bins, visual organizers); reinforce independent material management.', 'Teach material organization as explicit skill. Use labeled bins and backpack organization system.', 'Natural task completion as reinforcement. Praise for independent material management.', 'Generalize to varied material types and novel classroom environments.', 'Monthly observation: proportion of material management episodes completed without adult support.'),
('CR-10', 'Classroom Routines', 'Record on-task interval during group instruction. Criterion: 80%+ on-task in 15-min group session across 3 sessions.', 'CR-9 (materials management); CR-7 (hand-raising); CR-5 (group instructions at 80%+).', 'Classroom group instruction materials. Group instruction lasting 15+ minutes.', 'Observe child during 15-min group instruction. No individual prompting. Record on-task intervals.', 'Child participates in group instruction for 15 or more minutes without individual prompting.', 'Requires individual prompts, is off-task >20% of intervals, or disrupts group instruction.', 'least_to_most', '1. No prompt > 2. Proximity > 3. Gestural redirect > 4. Minimal verbal redirect.', 'Minimal, least-intrusive redirect; reinforce on-task behavior at next opportunity; avoid disrupting group.', 'Build from 5 min to 15 min by 5-min increments. Use preferred group activities.', 'Token system for sustained group participation. Natural learning opportunities as reinforcement.', 'Generalize to varied group instruction formats (lecture, small group, whole class).', 'Monthly group observation: proportion of 1-min intervals on-task during 15-min group instruction.'),
('CR-11', 'Classroom Routines', 'Record self-management behaviors per session. Criterion: accurately uses visual schedule or checklist 80%+ independently across 3 sessions.', 'CR-10 (15-min group participation); CR-8 (schedule-directed transitions); self-monitoring skills.', 'Personal visual schedule or checklist; self-management tool tailored to child.', 'Child provided with personal checklist. No adult prompting. Observe whether child self-manages.', 'Child self-manages behavior using visual schedules or personal checklists independently.', 'Requires adult to direct use of checklist; does not check items; needs prompting at each step.', 'most_to_least', '1. Adult models checklist use > 2. Adult prompts each check > 3. Independent use.', 'Re-model checklist use; provide step-specific prompts; fade to independent self-management.', 'Teach checklist use explicitly before expecting independence. Individualize checklist content.', 'Brief adult check-in reinforcement; fade to self-monitoring as primary reinforcement.', 'Generalize self-management tools to home and community settings.', 'Monthly probe: proportion of checklist items self-managed without adult prompting.'),
('CR-12', 'Classroom Routines', 'Record task completion independence per academic work session. Criterion: completes multi-step academic task independently 80%+ across 3 sessions.', 'CR-11 (self-management tools); CR-10 (15-min group participation); academic task stamina.', 'Grade-level academic tasks with clear completion criteria (worksheets, reading assignments, math problems).', 'Assign multi-step academic task. Withdraw continuous adult support. Observe completion.', 'Child completes multi-step academic tasks independently until finished, without prompting.', 'Stops mid-task, requires adult prompting to continue, or abandons task before completion.', 'least_to_most', '1. No prompt > 2. Gestural to task materials > 3. Verbal reminder ("Keep working").', 'Brief verbal reminder only; reinforce task continuation; avoid extended adult interaction.', 'Build task length incrementally. Use preferred academic topics initially. Break long tasks into chunks.', 'Natural task completion (access to preferred activity) as primary reinforcement.', 'Generalize to varied academic subjects and novel assignment formats.', 'Monthly probe: task completion rate across varied multi-step academic tasks.'),
('CR-13', 'Classroom Routines', 'Record appropriate help-seeking behaviors per session. Criterion: appropriately seeks help 80%+ of needed-help opportunities across 3 sessions.', 'CR-12 (multi-step task completion); CR-7 (hand-raising); basic self-advocacy awareness.', 'Natural academic task settings where help may be needed. Hand-raising and verbal requesting established.', 'Create naturally challenging task. Do not pre-emptively help. Observe whether child seeks help.', 'Child seeks help appropriately from adults when stuck on a task, using appropriate manner.', 'Struggles silently until frustrated, cries without requesting help, or demands help inappropriately.', 'least_to_most', '1. No prompt > 2. Environmental cue ("If you need help, raise your hand") > 3. Direct prompt.', 'Brief reminder of help-seeking procedure; reinforce any appropriate help-seeking attempt.', 'Teach explicit help-seeking language and procedure: raise hand, wait, ask "Can you help me?"', 'Natural task completion support as reinforcement for appropriate help-seeking.', 'Generalize to varied academic subjects, novel teachers, and community help-seeking contexts.', 'Monthly probe: appropriate help-seeking rate across challenging academic and daily tasks.'),
('CR-14', 'Classroom Routines', 'Record rule and routine compliance across all school settings. Criterion: follows school-wide rules consistently 80%+ across 3 weeks of observation.', 'CR-13 (help-seeking); full Classroom Routines repertoire across Levels 1-3.', 'Natural school settings: hallway, cafeteria, bathroom, gym, library, classroom.', 'Observe child across varied school settings throughout the week. Note rule compliance.', 'Child follows school-wide rules and routines consistently across all settings without individual prompting.', 'Requires individual reminders in some settings, inconsistent rule-following, or setting-specific problems.', 'least_to_most', '1. No prompt > 2. Proximity in challenging settings > 3. Private verbal reminder.', 'Private brief reminder; reinforce compliance; fade proximity over sessions.', 'Coordinate with all school staff for consistent expectations across all settings.', 'Natural school participation as reinforcement. Peer modeling and group contingencies.', 'Generalize rules to novel school settings and community public behavior contexts.', 'Weekly multi-setting observation: rule compliance rate across all school environments.'),
('CR-15', 'Classroom Routines', 'Record homework and material management independence per week. Criterion: manages homework independently 80%+ of days across 3 weeks.', 'CR-14 (school-wide rules); CR-11 (self-management); CR-12 (task completion); planning skills.', 'Homework folder, planner or assignment notebook, home communication system.', 'Track daily homework completion and return. Parent report + teacher verification.', 'Child manages homework and take-home materials independently without adult reminders.', 'Forgets homework, needs parent to remind for every assignment, loses materials regularly.', 'most_to_least', '1. Daily parent check-in > 2. Written planner use > 3. Independent planning > 4. Self-directed.', 'Parent check-in as a fading support; reinforce independent planner use; thin parent prompting.', 'Teach homework management as explicit skill. Use planner/homework folder system consistently.', 'Natural grade-level success as reinforcement. Intrinsic motivation + social praise.', 'Generalize homework management across all subjects and across the full school year.', 'Monthly review of homework completion rates and material management consistency.')
ON CONFLICT (milestone_code) DO UPDATE
SET vbmapp_domain = EXCLUDED.vbmapp_domain,
    data_collection = EXCLUDED.data_collection,
    prerequisite_skills = EXCLUDED.prerequisite_skills,
    materials = EXCLUDED.materials,
    sd = EXCLUDED.sd,
    correct_responses = EXCLUDED.correct_responses,
    incorrect_responses = EXCLUDED.incorrect_responses,
    prompting_hierarchy = EXCLUDED.prompting_hierarchy,
    prompting_hierarchy_detail = EXCLUDED.prompting_hierarchy_detail,
    error_correction = EXCLUDED.error_correction,
    transfer_procedure = EXCLUDED.transfer_procedure,
    reinforcement_schedule = EXCLUDED.reinforcement_schedule,
    generalization_plan = EXCLUDED.generalization_plan,
    maintenance_plan = EXCLUDED.maintenance_plan,
    template_origin = EXCLUDED.template_origin;

-- ============================================================
-- LINGUISTIC STRUCTURE (LS-1 through LS-15)
-- ============================================================

INSERT INTO vbmapp_milestone_templates (milestone_code, vbmapp_domain, data_collection, prerequisite_skills, materials, sd, correct_responses, incorrect_responses, prompting_hierarchy, prompting_hierarchy_detail, error_correction, transfer_procedure, reinforcement_schedule, generalization_plan, maintenance_plan) VALUES
('LS-1', 'Linguistic Structure', 'Record C/I/P per spontaneous utterance in 50-utterance sample. Criterion: 80%+ of spontaneous 2-word utterances follow noun-verb pattern across 3 samples.', 'Basic tact repertoire (20+ items); some mand combinations; 1-word utterances established.', 'Natural play and daily activities. 50-utterance language sample collected during preferred activities.', 'Arrange natural play with toys that elicit action comments (car goes, dog runs). No structured SD.', 'Child produces 2-word noun-verb combinations spontaneously across activities (doggy run, daddy eat).', 'Only 1-word utterances, random word combinations, or prompted phrase repetition only.', 'least_to_most', '1. Model 2-word combo in context > 2. Cloze prompt ("The dog ___") > 3. Independent.', 'Model the 2-word combo; request imitation; create same context; probe spontaneous use.', 'Use action toys and daily routines that naturally elicit noun-verb combinations. Avoid drilling.', 'CRF for spontaneous 2-word noun-verb combinations. Natural communicative success as reinforcement.', 'Generalize to varied nouns and varied verbs in naturalistic settings.', 'Monthly 50-utterance sample: MLU and proportion of 2-word noun-verb utterances.'),
('LS-2', 'Linguistic Structure', 'Record proportion of correct pronoun use per language sample. Criterion: correct I/you use 80%+ across 3 samples.', 'LS-1 (2-word noun-verb); basic personal pronoun exposure; some self/other distinction.', 'Natural conversational contexts. Play and daily activity language samples.', 'Create contexts eliciting I statements ("I want," "I see") and you ("your turn," "do you want?")', 'Child uses pronouns I and you appropriately in spontaneous speech without confusion.', 'Reverses I/you, avoids pronouns and uses names instead, or omits pronouns entirely.', 'least_to_most', '1. Recast incorrect pronoun > 2. Fill-in prompt ("You mean, I ___?") > 3. Independent.', 'Recast: repeat child utterance with correct pronoun naturally. Do not explicitly correct.', 'Begin with I in mand context ("I want ___"). Build you in social context. Fade echoic prompts.', 'Natural communicative success as reinforcement. Conversational recast is primary teaching strategy.', 'Generalize to he/she/they as I/you mastered. Use recasting in all natural contexts.', 'Monthly language sample: pronoun use accuracy and variety across I, you, he, she.'),
('LS-3', 'Linguistic Structure', 'Record proportion of correct plural marking in language sample. Criterion: 80%+ correct regular plural marking across 3 samples.', 'LS-2 (I/you pronouns); tact repertoire including plurals (cats, dogs, books); basic plural concept.', 'Natural activities involving multiple objects: picture books, play with multiple toys.', 'Elicit plural tacts in natural context: show multiple items, ask "What are these?" No explicit drill.', 'Child uses regular plural forms of nouns (cats, dogs, books) spontaneously in speech.', 'Omits plural -s, overgeneralizes to irregular nouns (mouses instead of mice), or uses always/never.', 'least_to_most', '1. Recast with plural form > 2. Fill-in ("These are ___") > 3. Independent.', 'Recast: "Yes, two cats!" Include plural practice in tact and LRFFC contexts.', 'Avoid introducing irregular plurals until regular plurals are 80%+.', 'Natural communicative success as reinforcement. Modeling in naturalistic contexts.', 'Generalize plural marking to novel nouns and varied grammatical positions.', 'Monthly language sample: regular plural accuracy and overextension error rate.'),
('LS-4', 'Linguistic Structure', 'Record proportion of present progressive use in language sample. Criterion: 80%+ correct -ing marking across 3 samples.', 'LS-3 (regular plurals); action tact vocabulary; some understanding of ongoing action.', 'Action pictures, video of ongoing actions, or live physical actions as elicitors.', 'Show ongoing action: person running, dog eating. Ask "What is he doing?" Observe spontaneous use.', 'Child uses present progressive verb tense (running, jumping) spontaneously and correctly.', 'Omits -ing, uses bare infinitive (he run), or only produces -ing with prompting.', 'least_to_most', '1. Recast with -ing form > 2. Fill-in ("He is ___ing") > 3. Independent.', 'Recast: "Yes, he is running!" Model -ing in naturalistic tact contexts throughout.', 'Build -ing in tact repertoire first. Then transfer to spontaneous narrative and conversational use.', 'Natural communicative success. Modeling and recasting as primary strategies.', 'Generalize present progressive to varied verbs and varied spontaneous contexts.', 'Monthly language sample: present progressive -ing accuracy across varied verbs.'),
('LS-5', 'Linguistic Structure', 'Record proportion of adjective+noun utterances in language sample. Criterion: 80%+ adjective-before-noun order across 3 samples.', 'LS-4 (present progressive); tact of attributes (color, size); 3-word utterance emerging.', 'Natural activities with varied objects (big ball, red cup, little dog). No explicit drill.', 'Arrange naturalistic contexts eliciting attribute + noun descriptions. Observe spontaneous production.', 'Child uses adjectives before nouns in spontaneous speech (big ball, red car) without prompting.', 'Uses noun without adjective, reverses order (ball big), or only produces adjectives when asked.', 'least_to_most', '1. Model adjective+noun in context > 2. Expansion ("Yes, the BIG ball!") > 3. Independent.', 'Expand child utterance to include adjective: "A ball? Yes, the big ball!" Recast naturally.', 'Build adjective+noun in tact context first. Transfer to mands and conversational speech.', 'Natural communicative success and semantic expansion as reinforcement.', 'Generalize to varied adjective types: color, size, shape, texture.', 'Monthly language sample: adjective+noun combination frequency and adjective variety.'),
('LS-6', 'Linguistic Structure', 'Record proportion of correct regular past tense in language sample. Criterion: 80%+ correct regular past tense marking across 3 samples.', 'LS-5 (adjective+noun); temporal language emerging; narrative and retelling skills.', 'Activity sequences, completed events, picture stories showing past events.', 'Elicit past tense through event retelling: "What happened?" "What did you do?" after an action.', 'Child uses regular past tense verbs correctly (walked, jumped, played) in spontaneous speech.', 'Omits -ed marker, uses present tense for past events, or produces uninflected verb form.', 'least_to_most', '1. Recast with past tense > 2. Fill-in ("Yesterday she ___ed") > 3. Independent.', 'Recast past tense naturally in narrative context. Model consistently in storytelling.', 'Begin with regular -ed verbs. Do not introduce irregular past tense until regular is 80%+.', 'Natural communicative success. Conversational storytelling and retelling as contexts.', 'Generalize to novel regular verbs in varied past-tense narrative contexts.', 'Monthly language sample: regular past tense accuracy and omission rate.'),
('LS-7', 'Linguistic Structure', 'Record proportion of correct possessive and pronoun use in sample. Criterion: 80%+ across 3 samples.', 'LS-6 (regular past tense); LS-2 (I/you pronouns); basic possession concept.', 'Natural possessive contexts: ownership during play, daily objects belonging to specific people.', 'Elicit naturally: "Whose shoe is this?" "Who has the red one?" Observe spontaneous possessive use.', 'Child uses possessive forms and pronouns correctly in spontaneous speech (mine, his, her, John ball becomes John''s ball).', 'Omits possessive -s marker, uses wrong pronoun form, or uses name only without possessive.', 'least_to_most', '1. Recast with possessive > 2. Fill-in ("It is ___''s ball") > 3. Independent.', 'Recast possessive form naturally: "Yes, that is Daddy''s shoe!" Model consistently.', 'Build possessive in tact context. Transfer to pronoun forms (his, her, my, your, their).', 'Natural communicative accuracy as reinforcement. Modeling and recasting.', 'Generalize possessive marking to varied possessors and varied possessed items.', 'Monthly language sample: possessive accuracy across noun possessors and pronoun forms.'),
('LS-8', 'Linguistic Structure', 'Record proportion of correct preposition use in language sample. Criterion: 80%+ across 3 samples.', 'LS-7 (possessives); LR-10 (prepositions receptively); spatial vocabulary established.', 'Natural spatial contexts: play with containers, daily object placement activities.', 'Elicit prepositions naturally in play and daily activities. Observe spontaneous production.', 'Child uses prepositions accurately in spontaneous speech (on, under, in, next to, behind).', 'Omits prepositions, substitutes wrong preposition, or only uses in and on.', 'least_to_most', '1. Recast with correct preposition > 2. Fill-in ("It is ___ the box") > 3. Independent.', 'Recast: "Yes, it is ON the box!" Model prepositions in tact context throughout day.', 'Sequence: teach on/in first, then under/next to, then behind/in front of/between.', 'Natural spatial language accuracy as reinforcement. Modeling and recasting.', 'Generalize to varied prepositions across naturalistic spatial and directional contexts.', 'Monthly language sample: preposition accuracy and variety across production contexts.'),
('LS-9', 'Linguistic Structure', 'Record proportion of correct article use in language sample. Criterion: 80%+ appropriate a/the use across 3 samples.', 'LS-8 (prepositions); LS-7 (possessives); noun phrase structure established.', 'Natural conversational contexts with varied referential situations (new vs. known referents).', 'Observe naturalistic article use. Elicit through descriptions of new vs. familiar objects.', 'Child uses articles a and the correctly in spontaneous utterances distinguishing new vs. known referents.', 'Omits articles, uses the for new referents, uses a for known referents, or uses always one form.', 'least_to_most', '1. Recast with correct article > 2. Cloze prompt > 3. Independent.', 'Recast: "Yes, A dog! Look, THE dog is sleeping now." Model distinction naturally.', 'Teach new/known referent distinction conceptually through varied examples.', 'Natural communicative accuracy as reinforcement. SLP consultation recommended.', 'Generalize article use to novel referential contexts in conversation and narrative.', 'Monthly language sample: article accuracy distinguishing a/the in context.'),
('LS-10', 'Linguistic Structure', 'Record proportion of correct conjunction use in language sample. Criterion: 80%+ appropriate conjunction use across 3 samples.', 'LS-9 (articles); LS-6 (past tense); compound sentence production emerging.', 'Natural conversation and narrative contexts. Storybook discussions, event retelling.', 'Observe spontaneous conjunction use. Elicit through causal and contrast questions.', 'Child uses conjunctions to combine clauses (and, but, because) in spontaneous speech.', 'Produces only simple sentences without conjunctions; uses and only; cannot use because or but.', 'least_to_most', '1. Model conjunction use in context > 2. Cloze prompt ("He was sad ___ he lost his toy") > 3. Independent.', 'Model conjunction use in narrative context; expand child sentences to include conjunction.', 'Begin with and (additive). Progress to but (adversative) and because (causal).', 'Natural communicative sophistication as reinforcement. Conversational expansion and modeling.', 'Generalize to varied conjunctions (so, if, when, while) as base conjunctions mastered.', 'Monthly language sample: conjunction variety and accuracy in spontaneous speech.'),
('LS-11', 'Linguistic Structure', 'Record proportion of correct irregular past tense in language sample. Criterion: 80%+ correct irregular past tense across 3 samples.', 'LS-10 (conjunctions); LS-6 (regular past tense at 80%+); broad verb vocabulary.', 'Narrative and retelling contexts involving irregular verb targets (ran, ate, went, saw, fell, broke).', 'Elicit through event retelling and storybook discussion. Observe spontaneous irregular past use.', 'Child uses irregular past tense verbs correctly (ran, ate, went) in spontaneous speech.', 'Overregularizes irregular verbs (goed, eated, runned), omits past marking, or uses present tense.', 'least_to_most', '1. Recast with correct irregular > 2. Contrast regular vs. irregular > 3. Independent.', 'Recast: "Yes, he RAN!" Model irregular forms consistently in naturalistic contexts.', 'Teach high-frequency irregular verbs first: went, ate, ran, said, made, came, saw.', 'Natural narrative accuracy as reinforcement. SLP consultation for persistent errors.', 'Generalize to novel irregular verbs as high-frequency forms are mastered.', 'Monthly language sample: irregular past tense accuracy and overregularization rate.'),
('LS-12', 'Linguistic Structure', 'Record proportion of complex sentences in language sample. Criterion: 80%+ of utterances contain embedded/dependent clauses in 3 samples.', 'LS-11 (irregular past tense); LS-10 (conjunctions); MLU of 4+ morphemes.', 'Complex narrative and conversational contexts. Storybook discussions, explanations, retelling.', 'Elicit complex sentences through story discussion and explanation tasks. Observe spontaneous use.', 'Child uses complex sentence structures with embedded and dependent clauses in spontaneous speech.', 'Only simple sentences; no embedded clauses; avoids subordinating conjunctions (when, because, that).', 'least_to_most', '1. Model complex sentence > 2. Expansion of child utterance > 3. Independent.', 'Expand child simple sentence: "Yes, the dog was hungry BECAUSE he had not eaten." Model.', 'Build from compound sentences (and/but) to complex (because/when) to embedded relative clauses.', 'Natural communicative sophistication as reinforcement. SLP consultation recommended.', 'Generalize complex structures to academic language, writing, and formal communication.', 'Monthly language sample: proportion of complex sentences and clause type variety.'),
('LS-13', 'Linguistic Structure', 'Record proportion of correct future tense constructions in language sample. Criterion: 80%+ correct future tense across 3 samples.', 'LS-12 (complex sentences); IV-11 (future event questions); temporal language well-established.', 'Planning and prediction contexts: "What will you do?" "What is going to happen next?"', 'Elicit future tense through planning questions and prediction tasks. Observe spontaneous use.', 'Child uses future tense constructions (will, going to) appropriately in spontaneous speech.', 'Uses present tense for future events, only responds to future questions without spontaneous use.', 'least_to_most', '1. Model future construction > 2. Cloze prompt > 3. Independent.', 'Model future tense in planning contexts: "Tomorrow we WILL go to the park." Recast.', 'Build will and going to forms. Include conditional future (if we go, then we will).', 'Natural planning success as reinforcement. Conversational modeling.', 'Generalize future tense to varied temporal distances (tomorrow, next week, someday).', 'Monthly language sample: future tense accuracy and spontaneous production frequency.'),
('LS-14', 'Linguistic Structure', 'Record proportion of correct conditional sentences in language sample. Criterion: 80%+ correct if-then structure across 3 samples.', 'LS-13 (future tense); LR-14 (conditional instructions receptively); logical reasoning skills.', 'Natural conditional reasoning contexts: problem-solving, rule explanation, hypothetical scenarios.', 'Elicit conditional sentences through: "What would you do if ___?" "If it rains, what will happen?"', 'Child uses conditional sentences (if-then constructions) correctly in spontaneous speech.', 'Avoids conditional structure, uses simple declarative instead, or cannot express conditional logic.', 'least_to_most', '1. Model conditional structure > 2. Fill-in ("If it rains, then ___") > 3. Independent.', 'Model conditional construction; provide cloze; build from concrete to hypothetical conditionals.', 'Begin with real/likely conditionals. Progress to hypothetical (if I were a bird...) conditionals.', 'Natural logical communication success as reinforcement. Academic context embedding.', 'Generalize to academic conditional reasoning in science, math, and social studies contexts.', 'Monthly language sample: conditional sentence production frequency and accuracy.'),
('LS-15', 'Linguistic Structure', 'Record spontaneous speech sample quality. Criterion: no systematic grammatical errors in 50-utterance sample across 3 samples.', 'LS-14 (conditional sentences); full LS repertoire across Levels 1-3; conversational fluency.', 'Natural conversational contexts across varied topics, interlocutors, and settings.', 'Collect 50-utterance spontaneous speech sample across varied daily contexts. Analyze for errors.', 'Child demonstrates full grammatical competence in spontaneous conversational speech across all structures.', 'Systematic errors in any grammatical category trained across LS Levels 1-3.', 'least_to_most', '1. Monitor and recast residual errors > 2. Targeted practice for specific error patterns > 3. Independent.', 'Identify specific remaining error patterns; provide targeted naturalistic teaching; recast consistently.', 'Coordinate with SLP for comprehensive grammatical assessment and targeted teaching.', 'Natural communicative success across all contexts as primary reinforcement.', 'Monitor grammatical accuracy in academic writing and formal speech as well as conversation.', 'Monthly 50-utterance language sample: MLU, grammatical accuracy, and grammatical complexity measures.')
ON CONFLICT (milestone_code) DO UPDATE
SET vbmapp_domain = EXCLUDED.vbmapp_domain,
    data_collection = EXCLUDED.data_collection,
    prerequisite_skills = EXCLUDED.prerequisite_skills,
    materials = EXCLUDED.materials,
    sd = EXCLUDED.sd,
    correct_responses = EXCLUDED.correct_responses,
    incorrect_responses = EXCLUDED.incorrect_responses,
    prompting_hierarchy = EXCLUDED.prompting_hierarchy,
    prompting_hierarchy_detail = EXCLUDED.prompting_hierarchy_detail,
    error_correction = EXCLUDED.error_correction,
    transfer_procedure = EXCLUDED.transfer_procedure,
    reinforcement_schedule = EXCLUDED.reinforcement_schedule,
    generalization_plan = EXCLUDED.generalization_plan,
    maintenance_plan = EXCLUDED.maintenance_plan,
    template_origin = EXCLUDED.template_origin;

-- ============================================================
-- READING (RDG-1 through RDG-15)
-- ============================================================

INSERT INTO vbmapp_milestone_templates (milestone_code, vbmapp_domain, data_collection, prerequisite_skills, materials, sd, correct_responses, incorrect_responses, prompting_hierarchy, prompting_hierarchy_detail, error_correction, transfer_procedure, reinforcement_schedule, generalization_plan, maintenance_plan) VALUES
('RDG-1', 'Reading', 'Record C/I/P per word-to-picture matching trial. Criterion: 90%+ across 3 sessions for 5+ words.', 'VP-3 (object-to-picture matching); LR-7 (25+ items receptively); emerging print awareness.', 'Printed word cards matched to picture cards for 5 common items (cat, dog, cup, ball, book).', 'Present printed word card. Place 3-4 picture cards. "Match" or "Find the picture for this word."', 'Child matches a printed word card to the corresponding picture or object within 5 seconds.', 'Matches word to wrong picture, matches by position, or requires prompt.', 'most_to_least', '1. Gestural (point to correct picture) > 2. Positional cue > 3. Independent.', 'Remove array; re-present with gestural prompt; easy known word; re-probe.', 'Begin with 5 clearly different word-picture pairs. Expand to 10+ words once 5 mastered.', 'CRF during acquisition; VR2 after mastery.', 'Generalize to varied picture styles and fonts. Practice in naturalistic print contexts.', 'Monthly probe with novel word-picture pairs. Track accuracy across varied print formats.'),
('RDG-2', 'Reading', 'Record C/I/P per name identification trial. Criterion: 90%+ across 3 sessions in varied formats.', 'RDG-1 (word-to-picture matching); LR-9 (identifies own name); emerging print awareness.', 'Child first name printed in varied fonts: block, lowercase, mixed case. Place among 2 distractors.', '"Find your name" or "Which one says [name]?" from array of 3 printed name cards.', 'Child identifies own first name in print across multiple formats and fonts, independently.', 'Selects wrong name, requires prompting, or only identifies in one specific font.', 'most_to_least', '1. Gestural (point to correct name) > 2. Positional cue > 3. Independent.', 'Re-present with gestural prompt; rotate fonts; re-probe; reinforce.', 'Vary fonts, sizes, and colors of own name. Expand to identifying name in naturalistic contexts.', 'CRF during acquisition; VR2 after mastery.', 'Generalize to name on backpack, cubby, written work, and in various print environments.', 'Monthly probe: name identification accuracy across 5+ varied formats.'),
('RDG-3', 'Reading', 'Record C/I/P per functional sight word reading trial. Criterion: 90%+ across 3 sessions for 5 words.', 'RDG-2 (own name); LR-7 (25+ receptive items); basic print-speech mapping.', 'Printed functional sight word cards: stop, exit, go, men, women (or localized equivalents).', 'Present individual sight word card. "Read this" or "What does this say?" Wait 5 seconds.', 'Child reads 5 functional sight words correctly within 5 seconds, independently.', 'Reads wrong word, no response, or requires gestural prompt.', 'most_to_least', '1. Full echoic model > 2. Partial echoic (first sound) > 3. 5-second time delay > 4. Independent.', 'Re-model; reinforce any approximation; easy known word; re-probe target.', 'Teach in context: show stop sign in environment while presenting word card.', 'CRF for functional sight word reading. Connect to real-world utility.', 'Generalize to environmental print in community settings (actual signs).', 'Monthly probe with 5 functional sight words in varied print formats.'),
('RDG-4', 'Reading', 'Record C/I/P per letter identification trial. Criterion: 90%+ across 3 sessions for all 26 uppercase and 26 lowercase.', 'RDG-3 (5 functional sight words); VP-9 (letter matching); basic print awareness.', 'Alphabet cards in uppercase and lowercase; varied fonts; letter books.', 'Present individual letter card. "What letter is this?" Wait 5 seconds.', 'Child identifies all 26 letters in uppercase and lowercase correctly within 5 seconds.', 'Names wrong letter, confuses visually similar letters (b/d), or requires more than 1 prompt.', 'most_to_least', '1. Full echoic model > 2. Partial echoic > 3. 5-second time delay > 4. Independent.', 'Re-model; easy known letter; re-probe confusable pairs with targeted teaching.', 'Teach letters in groups (A-E) before adding more. Separate easily confused letters.', 'CRF during letter acquisition; VR2 once all 52 letters mastered.', 'Generalize to varied fonts, sizes, and handwritten letter forms.', 'Monthly probe of rotating letter sample. Track error patterns for confusable letters.'),
('RDG-5', 'Reading', 'Record C/I/P per environmental sight word trial. Criterion: 90%+ for 10 words across 3 sessions.', 'RDG-4 (all 26 letters); RDG-3 (5 functional sight words); expanding sight word repertoire.', '10 functional and environmental sight word cards: stop, exit, go, open, closed, push, pull, walk, danger, hot.', 'Present individual word card from 10-word set. "What does this say?" Rotate all 10 within session.', 'Child reads 10 functional and environmental sight words across settings within 5 seconds.', 'Reads fewer than 10 consistently, requires prompts for some words, or cannot generalize to environment.', 'most_to_least', '1. Full echoic model > 2. Partial echoic > 3. Time delay > 4. Independent.', 'Re-model; easy known word; re-probe target; rotate teaching priority to weaker words.', 'Expand from 10 to 20 functional words. Practice in actual community environments.', 'CRF for sight word reading; VR2 once all 10 mastered.', 'Generalize to actual environmental print in school, home, and community.', 'Monthly probe of all 10 sight words in varied print formats and naturalistic contexts.'),
('RDG-6', 'Reading', 'Record C/I/P per high-frequency word reading trial. Criterion: 90%+ across 3 sessions for 20 sight words.', 'RDG-5 (10 environmental sight words); RDG-4 (all letters); beginning reading instruction.', '20 high-frequency words from Dolch/Fry list (the, and, is, it, in, was, for, on, are, at, be, this, with, he, from, or, one, had, by, but).', 'Present individual sight word card. "What word is this?" Rotate all 20 within each session.', 'Child reads 20 sight words from a common high-frequency word list within 5 seconds, independently.', 'Reads fewer than 15 words consistently; requires prompts; confuses similar sight words.', 'most_to_least', '1. Full echoic model > 2. Partial echoic > 3. Time delay > 4. Independent.', 'Re-model target word; easy known word; re-probe; prioritize teaching for weaker words.', 'Expand from 20 to 50 to 100 sight words progressively. Use in short phrases and sentences.', 'CRF during acquisition; VR2 for established words.', 'Generalize to sight words in books, worksheets, and environmental print.', 'Monthly probe of rotating 10-word sample from full 20-word set. Track individual word accuracy.'),
('RDG-7', 'Reading', 'Record C/I/P per CVC decoding trial. Criterion: 80%+ accurate decoding across 3 sessions for 10 CVC words.', 'RDG-6 (20 sight words); RDG-4 (all letters); phonological awareness; basic phonics instruction.', 'CVC word list (cat, dog, sit, hot, cup, pin, big, run, top, mud); phonics teaching materials.', 'Present individual CVC word card. "Sound it out. What word is this?" Allow 10 seconds.', 'Child decodes simple 3-letter CVC words using phonics knowledge within 10 seconds, independently.', 'Cannot blend sounds, produces wrong vowel sound, or reads as sight word only without phonics strategy.', 'most_to_least', '1. Sound-by-sound blending prompt > 2. First phoneme prompt > 3. Independent.', 'Model phoneme-by-phoneme blending; blend together with child; reinforce correct decoding.', 'Teach each vowel sound set (short-a, short-e, etc.) before mixing vowels. Use decodable books.', 'CRF for each correctly decoded CVC word; VR2 once 10 words reliably decoded.', 'Generalize CVC decoding to decodable books and novel CVC words never seen before.', 'Monthly probe: CVC decoding accuracy on novel words not previously taught.'),
('RDG-8', 'Reading', 'Record C/I/P per phrase reading trial. Criterion: 80%+ accurate per phrase across 3 sessions.', 'RDG-7 (CVC words); RDG-6 (20 sight words); fluent word-level reading.', 'Simple 2-3 word phrase cards combining known sight words and decodable words (the cat, a big dog, sit down).', 'Present printed phrase. "Read this phrase." Allow 10 seconds.', 'Child reads simple 2-3 word phrases with correct word identification within 10 seconds.', 'Cannot read one of the words, substitutes wrong word, or requires phonics prompt for known sight words.', 'most_to_least', '1. Read each word separately then together > 2. Prompt for unknown word only > 3. Independent.', 'Provide prompt for the specific unknown word; re-present full phrase; reinforce accurate phrase reading.', 'Build phrases from mastered sight words and decodable CVC words only. Expand to 4-word phrases.', 'CRF for accurate phrase reading; VR2 once reliable.', 'Generalize to phrases in decodable books and classroom print materials.', 'Monthly probe: phrase reading accuracy across novel phrase combinations.'),
('RDG-9', 'Reading', 'Record C/I/P per sentence reading trial. Criterion: 80%+ accurate with comprehension across 3 sessions.', 'RDG-8 (phrase reading); RDG-7 (CVC decoding); basic reading comprehension.', 'Simple sentence cards (4-5 words): "The cat sat on the mat." "A big dog ran away."', 'Present printed sentence. "Read this sentence." Then "What did it say?" for comprehension check.', 'Child reads simple sentences of 4-5 words with full comprehension within reasonable reading time.', 'Cannot read the sentence accurately, reads accurately but cannot answer comprehension question.', 'most_to_least', '1. Word-by-word reading support > 2. Prompt for unknown word > 3. Independent sentence reading.', 'Provide support for specific unknown word; re-read sentence; re-ask comprehension question.', 'Build from 3-word to 5-word sentences. Use sentences with decodable words + known sight words.', 'CRF for accurate sentence reading + correct comprehension response.', 'Generalize to sentences in early reader books and classroom print.', 'Monthly probe: sentence reading accuracy and comprehension across varied sentence structures.'),
('RDG-10', 'Reading', 'Record C/I/P per comprehension question per paragraph. Criterion: 80%+ comprehension accuracy across 3 sessions.', 'RDG-9 (simple sentences); IV-9 (story comprehension); expanding reading vocabulary.', 'Short paragraphs (3-5 sentences) at decodable reading level; comprehension questions prepared.', 'Child reads short paragraph aloud or silently. Therapist then asks comprehension questions.', 'Child reads short paragraphs and correctly answers comprehension questions about content.', 'Reads accurately but cannot answer questions; guesses randomly; needs to re-read with support.', 'most_to_least', '1. Re-read relevant sentence before answering > 2. Point to answer location > 3. Independent answer.', 'Re-read relevant section; point to key information; re-ask question; reinforce.', 'Build from 3-sentence to 5-sentence paragraphs. Increase comprehension question complexity.', 'CRF for accurate comprehension responses. Reading success as natural reinforcement.', 'Generalize to varied paragraph topics and text types. Bridge to school reading curriculum.', 'Monthly probe: comprehension accuracy across new unfamiliar paragraphs at level.'),
('RDG-11', 'Reading', 'Record comprehension accuracy per grade-level passage. Criterion: 80%+ comprehension across 3 passages.', 'RDG-10 (paragraph comprehension); full early reading skills; grade-level reading instruction.', 'Grade-level reading passages from school curriculum; comprehension questions at varied levels.', 'Child reads grade-level passage independently. Then answers comprehension questions.', 'Child reads grade-level passages with 80% or greater comprehension across literal and inferential questions.', 'Reads below grade level, cannot answer questions without re-reading, or below 80% comprehension.', 'most_to_least', '1. Chunked reading with pause for comprehension > 2. Guiding questions during reading > 3. Independent.', 'Provide guided reading support; focus on specific comprehension strategies; re-teach as needed.', 'Implement explicit comprehension strategy instruction: summarizing, questioning, making predictions.', 'Academic success and grade-level participation as reinforcement.', 'Generalize to all academic reading subjects. Coordinate with classroom reading teacher.', 'Monthly curriculum-based reading assessment: fluency rate and comprehension accuracy.'),
('RDG-12', 'Reading', 'Record accuracy of inferential question responses per passage. Criterion: 80%+ accurate inferential responses across 3 sessions.', 'RDG-11 (grade-level comprehension at 80%+); critical thinking skills; vocabulary breadth.', 'Grade-level or slightly challenging texts; inferential questions targeting implied meaning.', 'Child reads passage. Therapist asks inferential questions ("Why do you think...?" "What might happen next?")', 'Child answers inferential and higher-order questions about reading material independently.', 'Can only answer literal questions; cannot make inferences; gives random guesses for inferential.', 'most_to_least', '1. "Find evidence in the text" prompt > 2. Guided prediction question > 3. Independent.', 'Teach text-evidence strategy: "Show me where it says..." Scaffold inferential reasoning.', 'Teach common inference types: predict, infer character motivation, identify theme.', 'Academic discussion success and reading engagement as reinforcement.', 'Generalize inferential comprehension to all academic reading tasks.', 'Monthly probe: accuracy and depth of inferential responses across varied text types.'),
('RDG-13', 'Reading', 'Record words per minute and prosody rating during oral reading. Criterion: fluency rate at grade-level norms with appropriate prosody across 3 passages.', 'RDG-12 (inferential comprehension); RDG-11 (grade-level accuracy); fluency instruction.', 'Grade-level decodable passages; timer for fluency measurement; prosody rubric.', 'Child reads passage aloud for 1 minute. Record words correct per minute and prosody quality.', 'Child reads aloud with appropriate fluency rate (words per minute at grade-level norm), prosody, and expression.', 'Rate significantly below grade-level norms, robotic/flat prosody, or frequent self-corrections.', 'least_to_most', '1. Repeated reading of same passage > 2. Echo reading with model > 3. Independent oral reading.', 'Use repeated reading: child reads same passage multiple times to build fluency. Track WCPM progress.', 'Implement repeated reading and partner reading strategies. Target prosody through modeling.', 'Natural reading engagement and academic participation as reinforcement.', 'Generalize fluency to varied text types and genres. Monitor in classroom read-aloud contexts.', 'Monthly fluency probe: WCPM and prosody rating on grade-level passage.'),
('RDG-14', 'Reading', 'Record independent reading duration and genre variety per week. Criterion: reads independently for pleasure/information 80%+ of independent reading periods across 3 weeks.', 'RDG-13 (oral reading fluency); RDG-12 (inferential comprehension); broad reading interests.', 'Varied genre books at and slightly below reading level: fiction, non-fiction, poetry, biography, graphic novel.', 'Provide independent reading period with book access. Observe whether child reads independently.', 'Child reads independently for pleasure or information across varied genres without adult direction.', 'Only reads when required; reads same book repeatedly; cannot sustain independent reading for target period.', 'least_to_most', '1. No prompt > 2. Environmental setup (comfortable reading space, visible book choices) > 3. Brief encouragement.', 'Provide access to highly motivating books in preferred topics. Avoid directing specific book choices.', 'Build from 5-min to 20-min independent reading periods. Include preferred genre books.', 'Natural reading enjoyment as reinforcement. Connect reading to preferred topics and interests.', 'Generalize independent reading across school, home, and community (library) settings.', 'Weekly independent reading log: duration, genre variety, and self-selected book titles.'),
('RDG-15', 'Reading', 'Record quality of text analysis responses per reading. Criterion: demonstrates critical reading on 80%+ of analysis tasks across 3 sessions.', 'RDG-14 (independent reading); RDG-12 (inferential comprehension); full reading repertoire across all levels.', 'Varied genre texts at grade level; literary analysis tasks; critical response prompts.', 'After reading, present critical analysis task: "What is the author''s purpose?" "What is the theme?"', 'Child demonstrates critical reading and text analysis skills (author purpose, theme, bias, evidence) independently.', 'Can comprehend but not analyze; identifies plot but cannot identify theme or author purpose.', 'least_to_most', '1. Explicit analysis framework (graphic organizer) > 2. Guiding analysis question > 3. Independent.', 'Provide analysis framework; guide through each component; fade scaffold as skill develops.', 'Teach specific analysis skills: identify author purpose, evaluate evidence, recognize bias, analyze theme.', 'Academic success in ELA class and critical discussion engagement as reinforcement.', 'Generalize critical reading across all academic subjects and everyday information media.', 'Monthly critical reading probe: accuracy and depth of text analysis across varied genres.')
ON CONFLICT (milestone_code) DO UPDATE
SET vbmapp_domain = EXCLUDED.vbmapp_domain,
    data_collection = EXCLUDED.data_collection,
    prerequisite_skills = EXCLUDED.prerequisite_skills,
    materials = EXCLUDED.materials,
    sd = EXCLUDED.sd,
    correct_responses = EXCLUDED.correct_responses,
    incorrect_responses = EXCLUDED.incorrect_responses,
    prompting_hierarchy = EXCLUDED.prompting_hierarchy,
    prompting_hierarchy_detail = EXCLUDED.prompting_hierarchy_detail,
    error_correction = EXCLUDED.error_correction,
    transfer_procedure = EXCLUDED.transfer_procedure,
    reinforcement_schedule = EXCLUDED.reinforcement_schedule,
    generalization_plan = EXCLUDED.generalization_plan,
    maintenance_plan = EXCLUDED.maintenance_plan,
    template_origin = EXCLUDED.template_origin;

-- ============================================================
-- WRITING (WRT-1 through WRT-15)
-- ============================================================

INSERT INTO vbmapp_milestone_templates (milestone_code, vbmapp_domain, data_collection, prerequisite_skills, materials, sd, correct_responses, incorrect_responses, prompting_hierarchy, prompting_hierarchy_detail, error_correction, transfer_procedure, reinforcement_schedule, generalization_plan, maintenance_plan) VALUES
('WRT-1', 'Writing', 'Record accuracy of vertical and horizontal stroke imitation. Criterion: 80%+ accurate imitation across 3 sessions.', 'Basic fine motor skills; able to hold a writing implement; visual attention to demonstration.', 'Thick markers or crayons; large paper; vertical and horizontal stroke models.', 'Therapist draws vertical stroke on paper. "Do this" or "Copy this." Pause. Observe child imitation.', 'Child imitates vertical and horizontal pencil strokes after a single model, independently.', 'Strokes in wrong direction, cannot reproduce orientation, or requires physical guidance.', 'most_to_least', '1. Full physical (hand-over-hand) > 2. Partial physical > 3. Tracing dotted model > 4. Independent copy.', 'Guide hand through stroke; reinforce attempt; re-present model; re-probe.', 'Begin with thick implements on large paper. Progress to pencil on standard paper gradually.', 'CRF for stroke imitation attempts; VR2 once accurate across both orientations.', 'Generalize to varied writing implements, paper sizes, and surfaces.', 'Monthly probe: stroke imitation accuracy across vertical, horizontal, and diagonal orientations.'),
('WRT-2', 'Writing', 'Record C/I/P per shape copying trial. Criterion: 80%+ legible production across 3 sessions.', 'WRT-1 (vertical/horizontal strokes); basic fine motor coordination; shape discrimination.', 'Pencil/crayon; paper with printed shape models; circle, square, triangle target shapes.', 'Therapist shows printed shape model. "Copy this shape" or "Draw this." One shape per trial.', 'Child copies simple shapes (circle, square, triangle) with recognizable and legible form independently.', 'Unrecognizable shape production, requires physical guidance, or cannot produce closed shapes.', 'most_to_least', '1. Full physical > 2. Tracing dotted shape > 3. Copy from near model > 4. Copy from board model.', 'Provide tracing template; fade to copy; fade model proximity; reinforce legible shapes.', 'Sequence: circle (easiest), square (corners), triangle (diagonal). Build motor sequencing.', 'CRF for recognizable shape productions. Reinforce legibility, not perfection.', 'Generalize to shape drawing in art, math geometry, and functional drawing contexts.', 'Monthly probe: shape copying accuracy across circle, square, triangle, and additional shapes.'),
('WRT-3', 'Writing', 'Record legibility per name-writing attempt. Criterion: 80%+ legible letter formation across 3 sessions without model.', 'WRT-2 (shapes); letter formation instruction; letter imitation in own name.', 'Pencil; lined paper; no name model visible during target trials.', 'Say "Write your name." Observe whether child writes name legibly without a model to copy.', 'Child writes own first name legibly without a model present, with recognizable letter formation.', 'Requires model to copy from; produces illegible letter forms; reverses or omits letters.', 'most_to_least', '1. Trace dotted name > 2. Copy from visible model > 3. Copy from removed model > 4. Independent recall.', 'Return to previous prompt level; fade support; reinforce legible letter production.', 'Teach name writing from most-to-least prompting. Use name card as fading support.', 'CRF for legible name production without model; VR2 once reliable.', 'Generalize name writing to varied writing surfaces, implements, and orientations.', 'Monthly probe: name writing legibility from memory on varied writing surfaces.'),
('WRT-4', 'Writing', 'Record C/I/P per letter copying trial. Criterion: 80%+ legible letter formation across 3 sessions for all letters.', 'WRT-3 (own name writing); WRT-2 (shapes); all 26 letter names known.', 'Letter formation guide with directional arrows; lined paper; pencil.', 'Present printed letter model. "Copy this letter" or "Write this letter." Model visible during trial.', 'Child copies individual letters accurately from a printed model with legible formation and correct orientation.', 'Produces wrong letter, significant reversal (b/d), requires physical guidance, or unrecognizable form.', 'most_to_least', '1. Trace dotted letter > 2. Copy letter directly > 3. Copy from slightly removed model > 4. Independent.', 'Return to tracing level for specific problem letters; fade to copy; reinforce legible production.', 'Teach letters that are most similar to already-mastered shapes first. Separate easily confused letters.', 'CRF for legible letter copies; VR2 once all letters reliable.', 'Generalize letter copying to varied paper types and writing tools.', 'Monthly probe: letter copying legibility across all 26 letters including problem letters.'),
('WRT-5', 'Writing', 'Record C/I/P per dictation trial. Criterion: 80%+ legible from dictation across 3 sessions for all 26 letters.', 'WRT-4 (letter copying at 80%+); letter names known; letter formation from memory developing.', 'Pencil; lined paper; no visual model. Verbal dictation only.', 'Therapist says "Write the letter ___." One letter per trial. No visual model provided.', 'Child writes all letters of the alphabet legibly from dictation without a visual model, independently.', 'Cannot recall letter form from verbal name only; requires visual model; produces illegible or wrong letter.', 'most_to_least', '1. Provide letter model (return to copy) > 2. Partial model (top half of letter visible) > 3. No model.', 'Return to copy level for specific letters; fade model; reinforce legible from-memory production.', 'Separate letter naming from letter writing. Ensure letter-name-to-form mapping is established.', 'CRF for legible dictation writing; VR2 once all 26 letters reliable from dictation.', 'Generalize letter writing from dictation to spelling tasks and classroom dictation activities.', 'Monthly probe: dictation accuracy for all 26 letters, noting persistent reversals or errors.'),
('WRT-6', 'Writing', 'Record C/I/P per number writing trial. Criterion: 80%+ legible number production across 3 sessions for 1-10.', 'WRT-5 (letters from dictation); MTH-4 (numeral identification); number-form mapping established.', 'Pencil; lined paper; numeral models available as references initially.', 'Therapist says "Write the number ___" or child copies from a model. One number per trial.', 'Child writes numbers 1 through 10 legibly and independently from dictation or independently.', 'Produces wrong numeral form, significant reversal (6/9), or cannot write from memory.', 'most_to_least', '1. Trace dotted number > 2. Copy from model > 3. From dictation > 4. Independent.', 'Return to copying for specific problem numerals; fade; reinforce legible number production.', 'Teach numerals 1-5 first, then 6-10. Address reversals (5, 6, 9) with targeted practice.', 'CRF for legible number writing; VR2 once all 10 numerals reliable.', 'Generalize to number writing in math worksheets, date writing, and functional contexts.', 'Monthly probe: legibility of numerals 1-10 from dictation on lined paper.'),
('WRT-7', 'Writing', 'Record accuracy of sentence copying per session. Criterion: 80%+ accurate word-for-word with proper spacing across 3 sessions.', 'WRT-6 (numbers 1-10); WRT-5 (letters from dictation); basic word formation.', 'Printed sentence models; lined paper; pencil. Sentences 5-8 words using known vocabulary.', 'Present printed sentence. "Copy this sentence." Model visible throughout. One sentence per trial.', 'Child copies full sentences from a printed model with accurate letters, words, and spacing.', 'Omits words, substitutes words, merges words, or produces illegible letters within words.', 'most_to_least', '1. Word-by-word copying (mask rest) > 2. Full sentence visible > 3. From slightly removed model.', 'Return to word-by-word masking; fade; reinforce accurate word-accurate spacing production.', 'Use short sentences containing only known vocabulary. Increase sentence length gradually.', 'CRF for accurate complete sentence copying; VR2 once reliable.', 'Generalize to copying from board, book, and varied distances from model.', 'Monthly probe: sentence copying accuracy including word spacing and letter legibility.'),
('WRT-8', 'Writing', 'Record C/I/P per dictated word trial. Criterion: 80%+ accurate from dictation across 3 sessions for 10 words.', 'WRT-7 (sentence copying); WRT-5 (all letters from dictation); phonics/spelling knowledge.', 'Pencil; lined paper; no visual model. Verbal dictation of target words.', 'Therapist says "Write the word ___." One word per trial. No visual available.', 'Child writes simple words from dictation without a visual model, with accurate spelling.', 'Incorrect spelling, letter substitutions or omissions, or requires visual model.', 'most_to_least', '1. Spell each letter aloud while child writes > 2. First letter cue > 3. Word dictation only.', 'Spell word letter by letter; fade to initial letter cue; fade to dictation only; reinforce.', 'Select target words matching phonics level (CVC, CCVC). Use functional vocabulary.', 'CRF for accurate word writing from dictation; VR2 once 10 words reliable.', 'Generalize to spelling words in varied writing tasks (labeling, copying, independent composition).', 'Monthly probe: dictated word spelling accuracy on 10-word list, including novel words.'),
('WRT-9', 'Writing', 'Record quality of independently written sentences per session. Criterion: 80%+ contain complete thought with correct capitalization across 3 sessions.', 'WRT-8 (words from dictation); IV-10 (conversational intraverbal); basic sentence structure knowledge.', 'Pencil; lined paper; sentence starters optional as scaffold.', 'Therapist provides a verbal prompt: "Write a sentence about ___." One sentence per trial.', 'Child writes simple sentences independently in response to a verbal prompt, with complete thought.', 'Cannot produce sentence independently, writes only a word or phrase, or omits capitalization/punctuation.', 'most_to_least', '1. Sentence starter provided > 2. Topic word given > 3. Verbal topic prompt only > 4. Independent.', 'Provide sentence starter; fade support word by word; reinforce independent sentence construction.', 'Begin with highly familiar and preferred topics. Gradually introduce novel writing prompts.', 'CRF for complete independent sentences; VR2 once reliable.', 'Generalize to writing sentences across academic subjects and personal journaling.', 'Monthly probe: independent sentence writing quality across 3 varied prompts.'),
('WRT-10', 'Writing', 'Record proportion of sentences with correct capitalization, spacing, and end punctuation. Criterion: 80%+ of sentences correct across 3 sessions.', 'WRT-9 (independent sentences); basic grammar rules for capitalization and punctuation.', 'Pencil; lined paper; editing checklist optional.', 'Child writes sentences independently or in response to prompt. Check for mechanical elements.', 'Child uses correct spacing, capitalization at sentence start, and ending punctuation consistently.', 'Omits capital letters, missing end punctuation, or inconsistent word spacing.', 'most_to_least', '1. Editing checklist to self-correct > 2. Specific verbal reminder > 3. Independent.', 'Teach editing process with checklist; fade to self-monitoring; reinforce complete mechanical accuracy.', 'Teach one mechanical skill at a time: capitalization, then end punctuation, then spacing.', 'CRF for mechanically complete sentences; VR2 once all 3 elements reliable.', 'Generalize to all writing tasks across subjects. Build editing as a habit.', 'Monthly probe: mechanical accuracy across 10 independently written sentences.'),
('WRT-11', 'Writing', 'Record paragraph quality per writing task. Criterion: 80%+ of paragraphs contain 3+ sentences on topic across 3 sessions.', 'WRT-10 (sentence mechanics); LS-12 (complex sentences); basic paragraph structure understanding.', 'Writing paper or lined paper; paragraph writing prompts.', 'Provide writing prompt. "Write a paragraph about ___." Set timer for age-appropriate duration.', 'Child writes multi-sentence paragraphs on a given topic independently with 3+ sentences on topic.', 'Writes only 1-2 sentences, drifts off topic, or cannot generate ideas without extensive adult support.', 'most_to_least', '1. Paragraph outline/planner > 2. First sentence starter > 3. Topic word only > 4. Prompt only.', 'Provide graphic organizer; fade support; reinforce on-topic multi-sentence production.', 'Teach paragraph structure explicitly: topic sentence, supporting sentences, closing.', 'Natural writing success as reinforcement. Peer sharing of written work as social motivation.', 'Generalize to varied paragraph topics across academic subjects.', 'Monthly probe: paragraph writing quality (sentence count, topic focus, organization).'),
('WRT-12', 'Writing', 'Record organizational quality of written work per assignment. Criterion: 80%+ of written work has clear beginning, middle, end across 3 samples.', 'WRT-11 (multi-sentence paragraphs); IV-14 (story retelling); narrative organization skills.', 'Varied writing prompts requiring narrative or expository organization. Graphic organizers available.', 'Provide extended writing prompt. "Write about a time when..." or "Explain how to..." Allow independent work.', 'Child organizes written work with a clear beginning, middle, and end independently.', 'Random ordering of ideas, no clear structure, or all information in one unorganized paragraph.', 'most_to_least', '1. Written outline with B/M/E > 2. Graphic organizer > 3. Written prompts only > 4. Independent.', 'Pre-writing planning with graphic organizer; fade scaffold; reinforce clear organizational structure.', 'Teach pre-writing planning as an explicit skill. Use think-aloud to model organization decisions.', 'Academic writing success and teacher feedback as reinforcement.', 'Generalize organizational structure to narrative, informational, and opinion writing.', 'Monthly writing sample: score organization on B/M/E rubric across varied writing types.'),
('WRT-13', 'Writing', 'Record editing accuracy per writing sample. Criterion: identifies and corrects 80%+ of mechanical errors when editing own work across 3 samples.', 'WRT-12 (organized paragraphs); WRT-10 (sentence mechanics); self-monitoring skills.', 'Own written work; editing checklist; pencil or colored marking pen.', 'Child writes a paragraph or longer piece. Then: "Edit your work. Find and fix any mistakes."', 'Child edits own writing to identify and correct mechanical errors (capitalization, punctuation, spelling) independently.', 'Does not identify errors, only fixes errors when they are pointed out, or edits superficially.', 'most_to_least', '1. Editing checklist for each error type > 2. Checklist item by item > 3. Independent editing pass.', 'Walk through checklist with child; reinforce each error found and corrected; fade adult guidance.', 'Teach editing as a separate skill from writing. Use color-coding to mark error types.', 'Natural improvement in written work quality as reinforcement.', 'Generalize editing to all academic writing. Build editing as a habitual final step.', 'Monthly editing probe: proportion of errors identified and corrected in own writing.'),
('WRT-14', 'Writing', 'Record genre variety across writing samples per month. Criterion: produces legible, on-genre writing in 3+ different genres across 3 samples.', 'WRT-13 (self-editing); WRT-12 (organized writing); IV-15 (debates/discussions).', 'Varied genre prompts: personal narrative, informational, persuasive/opinion writing templates.', 'Provide genre-specific writing prompt. Review genre features. Allow independent writing.', 'Child writes in different genres (narrative, informational, opinion) with genre-appropriate features.', 'Only writes in one genre; does not use genre-specific features; cannot adapt writing style to genre.', 'most_to_least', '1. Genre example text to analyze > 2. Genre feature checklist > 3. Genre prompt only > 4. Independent.', 'Analyze mentor texts for genre features; provide checklist; fade support; reinforce genre-accurate writing.', 'Teach each genre explicitly with mentor text examples before independent production.', 'Academic writing success across subjects. Genre-specific assignments as natural writing contexts.', 'Generalize genre writing to all academic writing contexts.', 'Monthly writing samples: assess genre accuracy for narrative, informational, and opinion writing.'),
('WRT-15', 'Writing', 'Record quality of extended writing per assignment. Criterion: produces coherent extended writing (5+ paragraphs) independently across 3 assignments.', 'WRT-14 (genre writing); WRT-12 (organized writing); full writing repertoire across all levels.', 'Extended writing prompts; graphic organizers optional; writing process framework.', 'Provide extended writing assignment (5+ paragraph requirement). Allow sustained independent work.', 'Child produces extended written work with coherent and organized structure independently.', 'Cannot sustain extended writing independently; loses organizational coherence across paragraphs; requires continuous support.', 'least_to_most', '1. No prompt > 2. Structural outline > 3. Paragraph-by-paragraph check-in.', 'Provide structural outline if needed; check in after each paragraph; reinforce continued independent work.', 'Teach full writing process: prewriting, drafting, revising, editing, publishing.', 'Natural academic success and authentic writing purposes as reinforcement.', 'Generalize extended writing to all academic report, essay, and project contexts.', 'Monthly extended writing assignment: assess organization, coherence, length, and genre accuracy.')
ON CONFLICT (milestone_code) DO UPDATE
SET vbmapp_domain = EXCLUDED.vbmapp_domain,
    data_collection = EXCLUDED.data_collection,
    prerequisite_skills = EXCLUDED.prerequisite_skills,
    materials = EXCLUDED.materials,
    sd = EXCLUDED.sd,
    correct_responses = EXCLUDED.correct_responses,
    incorrect_responses = EXCLUDED.incorrect_responses,
    prompting_hierarchy = EXCLUDED.prompting_hierarchy,
    prompting_hierarchy_detail = EXCLUDED.prompting_hierarchy_detail,
    error_correction = EXCLUDED.error_correction,
    transfer_procedure = EXCLUDED.transfer_procedure,
    reinforcement_schedule = EXCLUDED.reinforcement_schedule,
    generalization_plan = EXCLUDED.generalization_plan,
    maintenance_plan = EXCLUDED.maintenance_plan,
    template_origin = EXCLUDED.template_origin;

-- ============================================================
-- MATH (MTH-1 through MTH-15)
-- ============================================================

INSERT INTO vbmapp_milestone_templates (milestone_code, vbmapp_domain, data_collection, prerequisite_skills, materials, sd, correct_responses, incorrect_responses, prompting_hierarchy, prompting_hierarchy_detail, error_correction, transfer_procedure, reinforcement_schedule, generalization_plan, maintenance_plan) VALUES
('MTH-1', 'Math', 'Record C/I/P per counting trial. Criterion: 80%+ accurate 1-to-1 correspondence for 3 objects across 3 sessions.', 'Basic visual attention to objects; fine motor skills to point; some number word knowledge.', '3 small identical objects (blocks, chips); flat surface. 3 is the target count.', 'Place 3 objects. "Count these" or "How many?" Wait 10 seconds.', 'Child counts 3 objects with accurate one-to-one correspondence and states final count.', 'Skips objects, counts same object twice, does not say number words, or does not state final count.', 'most_to_least', '1. Physical guidance (move each object as counted) > 2. Gestural (point to each object) > 3. Independent.', 'Guide hand to touch each object sequentially while counting; fade; reinforce accurate correspondence.', 'Use consistent object sets initially. Teach to line objects up or move counted objects to one side.', 'CRF for accurate 3-object count; VR2 once reliable.', 'Generalize counting to varied objects, settings, and 3 objects in different arrangements.', 'Monthly probe: 1-to-1 correspondence accuracy with 3 objects in varied arrangements.'),
('MTH-2', 'Math', 'Record C/I/P per numeral identification trial. Criterion: 90%+ across 3 sessions for numerals 1-5.', 'MTH-1 (counts 3 objects); basic number word vocabulary; number-symbol association beginning.', 'Numeral cards 1-5; presented individually or from array of 3.', 'Present individual numeral card. "What number is this?" Wait 5 s.', 'Child identifies and names numerals 1 through 5 correctly when shown, within 5 seconds.', 'Names wrong numeral, confuses similar numerals (6/9 at later stages), or no response.', 'most_to_least', '1. Full echoic model > 2. Partial echoic > 3. 5-second time delay > 4. Independent.', 'Re-model; easy known numeral; re-probe target.', 'Teach numerals in sequence (1, 2, 3 then 4, 5). Connect to corresponding quantities.', 'CRF during acquisition; VR2 once all 5 numerals mastered.', 'Generalize to varied numeral fonts, sizes, and contexts (digital, handwritten, book).', 'Monthly probe: numeral identification accuracy for 1-5 in varied formats.'),
('MTH-3', 'Math', 'Record C/I/P per counting trial. Criterion: 80%+ accurate 1-to-1 correspondence for 10 objects across 3 sessions.', 'MTH-2 (numerals 1-5); MTH-1 (counts 3 accurately); number words 1-10 known.', '10 small countable objects; organized counting area. Varied object types across sessions.', 'Place 10 objects. "Count these." Or present varying quantities up to 10.', 'Child counts 10 objects with accurate one-to-one correspondence and states correct final count.', 'Loses track after 5-7 objects, skips or double-counts objects, or errors on number words 7-10.', 'most_to_least', '1. Gesture to each object as child counts > 2. Visual line (count row) > 3. Independent.', 'Guide to move objects to counted side; reinforce systematic counting strategy.', 'Teach to move objects from one group to another while counting. Practice with 5 before 10.', 'CRF for accurate 10-object count; VR2 once reliable.', 'Generalize to varied objects, arrays, and counting in functional contexts (snack, classroom).', 'Monthly probe: 1-to-1 correspondence accuracy for sets of 7, 8, 9, 10 objects.'),
('MTH-4', 'Math', 'Record C/I/P per numeral identification trial. Criterion: 90%+ across 3 sessions for numerals 1-10.', 'MTH-3 (counts 10 objects); MTH-2 (numerals 1-5 at 90%+); expanding numeral recognition.', 'Numeral cards 1-10; arrays of 3 numerals. Rotate presentation format.', 'Present individual numeral or array. "What number is this?" Wait 5 seconds.', 'Child identifies and names numerals 1 through 10 correctly when shown, independently.', 'Names wrong numeral, confuses 6/9 or 1/7, or errors on numerals 6-10.', 'most_to_least', '1. Full echoic model > 2. Partial echoic > 3. 5-second time delay > 4. Independent.', 'Re-model target numeral; easy known numeral; re-probe; address confusable pairs with targeted practice.', 'Sequence: teach 6-10 as new group once 1-5 is mastered. Address confusable numerals separately.', 'CRF during acquisition of 6-10; VR2 once all 10 mastered.', 'Generalize to varied numeral fonts, sizes, digital displays, and classroom number lines.', 'Monthly probe: identification accuracy for all 10 numerals in mixed presentation.'),
('MTH-5', 'Math', 'Record C/I/P per quantity-numeral matching trial. Criterion: 80%+ across 3 sessions for quantities 1-5.', 'MTH-4 (numerals 1-10); MTH-1 (counts 3 objects); basic cardinality concept.', 'Sets of objects (1-5 quantities); corresponding numeral cards 1-5. Both present during trial.', 'Present a set of objects. "Find the number that tells how many." Array of numeral cards 1-5.', 'Child matches quantities 1-5 to the corresponding written numeral, independently.', 'Counts incorrectly, selects wrong numeral, or cannot connect quantity to symbol.', 'most_to_least', '1. Count together then gestural to numeral > 2. Child counts independently then gestural to numeral > 3. Independent.', 'Count with child; point to correct numeral; re-probe full task independently.', 'Begin with 1 vs. 5 (maximally distinct). Progress to adjacent quantities (3 vs. 4).', 'CRF for accurate quantity-numeral matching; VR2 once all 5 quantities reliable.', 'Generalize to varied object types, arrangements, and settings. Connect to functional counting.', 'Monthly probe: quantity-numeral matching for 1-5 with varied object sets.'),
('MTH-6', 'Math', 'Record C/I/P per addition trial. Criterion: 80%+ accurate across 3 sessions for addition sums to 10.', 'MTH-5 (quantities 1-5 matched to numerals); MTH-3 (counts 10 objects); cardinality established.', 'Manipulatives (blocks, counters); pencil and paper for recording; addition task cards.', '"3 plus 2 is how many?" Child may use fingers or manipulatives. Written equation shown.', 'Child performs addition with sums to 10 using manipulatives or fingers, accurately.', 'Adds incorrectly, cannot use manipulatives effectively, or gives up without attempting.', 'most_to_least', '1. Count all manipulatives together > 2. Count on strategy (start with larger number) > 3. Independent.', 'Model count-all strategy with manipulatives; guide count-on strategy; reinforce accurate sum.', 'Begin with +1 and +2 additions. Progress to larger addends as simpler problems mastered.', 'CRF for accurate addition; VR2 once reliable across varied sums to 10.', 'Generalize to addition in functional contexts (counting items in store, sharing snacks).', 'Monthly probe: addition accuracy across varied problems with sums to 10.'),
('MTH-7', 'Math', 'Record C/I/P per subtraction trial. Criterion: 80%+ accurate across 3 sessions for subtraction within 10.', 'MTH-6 (addition to 10); MTH-3 (counts 10 objects); basic subtraction concept.', 'Manipulatives; subtraction task cards; pencil and paper for recording.', '"5 minus 2 is how many?" Child starts with 5 manipulatives, removes 2, counts remaining.', 'Child performs subtraction within 10 using manipulatives or fingers, accurately.', 'Cannot remove correct quantity, counts all objects instead of remainder, or gives wrong answer.', 'most_to_least', '1. Physical guidance (remove objects together) > 2. Gestural to objects to remove > 3. Independent.', 'Model subtraction with manipulatives; guide removal; reinforce accurate count of remainder.', 'Begin with -1 and -2. Progress to larger subtrahends. Connect to addition as inverse.', 'CRF for accurate subtraction; VR2 once reliable across varied problems within 10.', 'Generalize to subtraction in functional contexts (food items eaten, objects given away).', 'Monthly probe: subtraction accuracy across varied problems within 10.'),
('MTH-8', 'Math', 'Record C/I/P per coin identification trial. Criterion: 80%+ coin and value identification across 3 sessions for 4 coins.', 'MTH-7 (subtraction within 10); MTH-4 (numerals 1-10); basic money concept introduction.', 'Real or realistic coins: penny, nickel, dime, quarter. Value labels available.', 'Present individual coin. "What coin is this?" and "How much is it worth?" Two questions per trial.', 'Child identifies common coins (penny, nickel, dime, quarter) and states their monetary values correctly.', 'Confuses dime and penny (size), names coin but not value, or names value but not coin name.', 'most_to_least', '1. Echoic model for name and value > 2. Partial model > 3. 5-s time delay > 4. Independent.', 'Re-model; address confusable pairs (dime vs. penny) with targeted discrimination training.', 'Teach coin name and value together. Use real coins and coin-value songs to build memory.', 'CRF for correct coin identification + value; VR2 once all 4 coins mastered.', 'Generalize to coins in functional contexts: school store, vending machine, real purchase.', 'Monthly probe: coin name and value accuracy across all 4 coins in mixed presentation.'),
('MTH-9', 'Math', 'Record C/I/P per word problem trial. Criterion: 80%+ accurate across 3 sessions for 10 varied problems.', 'MTH-7 (subtraction); MTH-6 (addition); reading/listening comprehension at sentence level.', 'Word problem cards with simple scenarios using addition or subtraction within 10.', 'Read word problem aloud or present written. "How many are there now?" Allow manipulatives.', 'Child solves simple word problems using addition or subtraction within 10 with manipulatives.', 'Cannot identify operation needed, misunderstands the scenario, or arithmetic error.', 'most_to_least', '1. Identify operation together > 2. Represent with manipulatives > 3. Independent solution.', 'Guide operation identification; represent with manipulatives; reinforce correct computation.', 'Begin with addition word problems then subtraction. Use familiar real-world contexts.', 'CRF for correct word problem solutions; VR2 once reliable across varied scenarios.', 'Generalize to real-life math situations: buying items, sharing food, counting groups.', 'Monthly probe: word problem accuracy across 10 varied addition and subtraction scenarios.'),
('MTH-10', 'Math', 'Record C/I/P per pattern continuation trial. Criterion: 80%+ accurate across 3 sessions for 5 different patterns.', 'MTH-9 (word problems); VP-10 (visual pattern completion); number sequence awareness.', 'Pattern cards or manipulatives arranged in simple number patterns (1, 2, 1, 2; 1, 3, 5...).', 'Present number pattern with gap: "1, 2, 1, 2, ___. What comes next?" Wait 10 s.', 'Child identifies and continues simple repeating number patterns correctly.', 'Cannot identify pattern rule, extends with wrong number, or needs pattern re-explained.', 'most_to_least', '1. Verbalize pattern rule together > 2. "What comes after ___?" cue > 3. Independent.', 'Verbalize pattern together; point to next position; reinforce correct extension.', 'Begin with AB patterns (1,2,1,2). Progress to ABB, then arithmetic skip-counting patterns.', 'CRF during pattern acquisition; VR2 once 5 pattern types mastered.', 'Generalize to calendar patterns, skip counting, and classroom math pattern activities.', 'Monthly probe: pattern continuation accuracy across varied simple and complex patterns.'),
('MTH-11', 'Math', 'Record C/I/P per multi-digit computation trial. Criterion: 80%+ accurate across 3 sessions for addition and subtraction with regrouping.', 'MTH-10 (number patterns); MTH-6/7 (single-digit operations); place value understanding.', 'Place value blocks (base-10 manipulatives); computation worksheets; pencil.', 'Present multi-digit addition or subtraction problem requiring regrouping. Allow manipulatives.', 'Child performs multi-digit addition and subtraction with regrouping accurately.', 'Adds/subtracts digits without regrouping, reverses regrouping direction, or computational errors throughout.', 'most_to_least', '1. Base-10 blocks manipulation > 2. Written algorithm with guided steps > 3. Independent algorithm.', 'Guide through regrouping procedure step by step; fade to algorithm; reinforce accurate computation.', 'Teach place value deeply before multi-digit computation. Use base-10 blocks consistently.', 'CRF for accurate multi-digit computation; VR2 once reliable with and without manipulatives.', 'Generalize to classroom computation worksheets, real-world addition/subtraction contexts.', 'Monthly probe: multi-digit addition and subtraction accuracy on varied problems with regrouping.'),
('MTH-12', 'Math', 'Record C/I/P per multiplication and division trial. Criterion: 80%+ accurate across 3 sessions within 100.', 'MTH-11 (multi-digit addition/subtraction); skip counting; basic multiplication concept.', 'Multiplication table reference; manipulative arrays; computation worksheets.', 'Present multiplication or division problem within 100. Allow manipulative use initially.', 'Child multiplies and divides within 100 with accuracy using any reliable strategy.', 'Cannot recall or compute multiplication facts, confuses multiplication and division procedures.', 'most_to_least', '1. Array model > 2. Repeated addition bridge > 3. Multiplication table reference > 4. Independent recall.', 'Use arrays and repeated addition to build multiplication meaning; then memorization strategies.', 'Teach multiplication tables by family (x2, x5, x10 first). Connect multiplication to division.', 'CRF for accurate multiplication and division facts; VR2 once reliable.', 'Generalize to multi-digit multiplication and division. Include in real-world math problems.', 'Monthly probe: multiplication and division accuracy within 100 across fact families.'),
('MTH-13', 'Math', 'Record accurate calculator use per functional task. Criterion: 80%+ accurate calculator operation across 3 sessions.', 'MTH-12 (multiplication/division); MTH-6/7 (basic operations); basic calculator orientation.', 'Standard calculator (or phone calculator); real-life math task cards requiring calculator use.', '"Figure out the total cost of these 3 items using the calculator." Provide real-world task.', 'Child uses a calculator accurately for functional and real-life math tasks independently.', 'Presses wrong keys, cannot clear calculator between problems, or cannot interpret calculator result.', 'most_to_least', '1. Model key sequence > 2. Written key sequence guide > 3. Verbal prompt > 4. Independent.', 'Model key sequence; provide written guide; fade to independent operation.', 'Teach calculator buttons (clear, equals, operations). Use with real-world shopping and budgeting tasks.', 'Natural task completion success as reinforcement. Functional independence as motivation.', 'Generalize calculator use to varied functional math contexts: restaurant, store, scheduling.', 'Monthly probe: calculator accuracy across varied real-life computation tasks.'),
('MTH-14', 'Math', 'Record accuracy of change-making per transaction. Criterion: 80%+ correct change across 3 sessions of 5 transactions each.', 'MTH-13 (calculator use); MTH-8 (coin identification); MTH-11 (multi-digit subtraction); money math.', 'Real or play money (coins and bills); simulated store setup; price tags.', 'Set up store context. Child purchases item. "How much change should you get?" Or "Give me change for ___."', 'Child makes correct change using coins and bills in functional transactions independently.', 'Gives incorrect change, cannot calculate difference, or needs calculator for simple transactions.', 'most_to_least', '1. Calculator to determine change amount > 2. Money manipulative counting up > 3. Independent.', 'Count up from price to payment amount; reinforce correct change production.', 'Begin with round dollar amounts. Progress to cents. Use real store situations.', 'Natural purchase success as reinforcement. Functional independence as primary motivation.', 'Generalize to real community purchase and transaction contexts.', 'Monthly probe: change-making accuracy across 5 transactions at varied price points.'),
('MTH-15', 'Math', 'Record application of math skills to real-life problems per session. Criterion: independently solves 3+ real-life math problems per session across 3 sessions.', 'MTH-14 (making change); full math repertoire across Levels 1-3; functional math motivation.', 'Real-life contexts: cooking recipes, measuring, budgeting, scheduling, sports statistics.', 'Present real-life math situation: "We need to double this recipe. How much of each ingredient?" Allow tools.', 'Child applies math skills to solve real-life functional problems independently using appropriate strategies.', 'Cannot identify relevant math operation, gives up when problem requires multi-step solution.', 'least_to_most', '1. No prompt > 2. "What math do you need here?" > 3. Identify operation type together.', 'Guide problem setup; allow child to compute; reinforce correct real-life math application.', 'Use math situations from child interests: cooking, sports, money, travel, building.', 'Natural task accomplishment and functional success as primary reinforcement.', 'Generalize to novel real-life math contexts encountered in community and home settings.', 'Monthly observation: real-life math problem types encountered and independent solution rate.')
ON CONFLICT (milestone_code) DO UPDATE
SET vbmapp_domain = EXCLUDED.vbmapp_domain,
    data_collection = EXCLUDED.data_collection,
    prerequisite_skills = EXCLUDED.prerequisite_skills,
    materials = EXCLUDED.materials,
    sd = EXCLUDED.sd,
    correct_responses = EXCLUDED.correct_responses,
    incorrect_responses = EXCLUDED.incorrect_responses,
    prompting_hierarchy = EXCLUDED.prompting_hierarchy,
    prompting_hierarchy_detail = EXCLUDED.prompting_hierarchy_detail,
    error_correction = EXCLUDED.error_correction,
    transfer_procedure = EXCLUDED.transfer_procedure,
    reinforcement_schedule = EXCLUDED.reinforcement_schedule,
    generalization_plan = EXCLUDED.generalization_plan,
    maintenance_plan = EXCLUDED.maintenance_plan,
    template_origin = EXCLUDED.template_origin;

-- ============================================================
-- SPELLING (SPL-1 through SPL-15)
-- ============================================================

INSERT INTO vbmapp_milestone_templates (milestone_code, vbmapp_domain, data_collection, prerequisite_skills, materials, sd, correct_responses, incorrect_responses, prompting_hierarchy, prompting_hierarchy_detail, error_correction, transfer_procedure, reinforcement_schedule, generalization_plan, maintenance_plan) VALUES
('SPL-1', 'Spelling', 'Record C/I/P per letter-sound identification trial. Criterion: 90%+ across 3 sessions for 10 letters.', 'Basic letter identification; phonological awareness beginning; RDG-4 (all letters identified).', 'Alphabet cards showing letter and picture cue; phonics program materials.', 'Present letter card. "What sound does this letter make?" Wait 5 seconds.', 'Child identifies and names the sound of letters when letters are shown, independently.', 'Produces wrong sound, names the letter instead of sound, or no response.', 'most_to_least', '1. Full echoic model of sound > 2. Partial echoic (first element) > 3. 5-s time delay > 4. Independent.', 'Re-model sound; picture cue; easy known letter; re-probe target.', 'Begin with consistent single-sound letters (b, d, f, m). Separate similarly sounding pairs.', 'CRF during sound acquisition; VR2 once 10 sounds mastered.', 'Generalize to sounds in varied letter fonts and in connected text reading contexts.', 'Monthly probe: letter-sound accuracy across 26 letters in varied presentation formats.'),
('SPL-2', 'Spelling', 'Record legibility and accuracy of name spelling from dictation. Criterion: 80%+ accurate spelling across 3 sessions.', 'SPL-1 (10 letter sounds); WRT-3 (name writing without model); letter formation established.', 'Pencil; lined paper; no name model visible.', 'Therapist says "Spell your name." Child writes all letters from memory in correct sequence.', 'Child spells own first name correctly from dictation without a model, independently.', 'Omits letters, reverses letter order, or requires visual model.', 'most_to_least', '1. Say each letter and child writes it > 2. First letter cue > 3. Dictate name only > 4. Independent.', 'Return to letter-by-letter dictation; fade to whole-word dictation; reinforce accurate spelling.', 'Use name-writing practice to build letter sequence automaticity.', 'CRF for accurate name spelling; VR2 once reliable.', 'Generalize name spelling to varied writing contexts: forms, worksheets, name labels.', 'Monthly probe: name spelling accuracy and sequence from verbal dictation.'),
('SPL-3', 'Spelling', 'Record C/I/P per CVC word spelling trial. Criterion: 80%+ accurate from dictation across 3 sessions for 5 words.', 'SPL-2 (own name); SPL-1 (letter sounds); phonics decoding knowledge.', 'Pencil; lined paper; 5 target CVC words (cat, dog, sit, hot, cup).', 'Therapist says target CVC word once. "Write ___." No visual model.', 'Child spells 5 simple 3-letter CVC words correctly from dictation, independently.', 'Phonemic errors (substitutes vowel), omits a letter, or requires letter-by-letter spelling support.', 'most_to_least', '1. Segment phonemes aloud together ("c-a-t") > 2. First phoneme cue > 3. Full word dictation only.', 'Segment word phonemically; child writes each phoneme; fade segmentation support.', 'Begin with short-a CVC words. Progress to other vowel sounds. Use phonetic patterns.', 'CRF for accurate CVC spelling; VR2 once all 5 words mastered.', 'Generalize CVC spelling to novel words in the same phonetic pattern.', 'Monthly probe: novel CVC word spelling accuracy (words not explicitly taught).'),
('SPL-4', 'Spelling', 'Record C/I/P per letter-tile spelling trial. Criterion: 80%+ accurate across 3 sessions for 5 words.', 'SPL-3 (5 CVC words from dictation); letter identification; phoneme segmentation emerging.', 'Letter tiles or magnetic letters; target CVC word list; no printed model during trial.', 'Therapist says a CVC word. Child arranges letter tiles to spell the word. No visual model.', 'Child arranges letter tiles to spell simple CVC words from a verbal cue, independently.', 'Tiles arranged in wrong order, wrong letter chosen, or requires verbal phoneme segmentation.', 'most_to_least', '1. Phoneme segmentation aloud + point to tile position > 2. Phoneme segmentation only > 3. Independent.', 'Segment phonemes; point to where each tile goes; reinforce correct tile arrangement.', 'Begin with tiles for only the 3 letters needed. Progress to choosing from full alphabet tiles.', 'CRF for accurate tile arrangement; VR2 once 5 words mastered.', 'Generalize to letter-tile spelling of novel words in the same phonetic pattern.', 'Monthly probe: letter-tile spelling accuracy for novel CVC words.'),
('SPL-5', 'Spelling', 'Record C/I/P per sight word spelling trial. Criterion: 80%+ accurate from dictation across 3 sessions for 10 words.', 'SPL-4 (letter tile spelling); RDG-6 (20 sight words read); phonics + sight-word knowledge.', 'Pencil; lined paper; 10 high-frequency sight word list (the, and, is, it, in, was, for, on, are, at).', 'Therapist says sight word once. "Write ___." No visual model. One word per trial.', 'Child spells 10 high-frequency sight words correctly from dictation, independently.', 'Phonetically plausible but incorrect spelling (wuz for was); letter omissions; or requires visual.', 'most_to_least', '1. Spell aloud letter by letter with child writing > 2. First letter cue > 3. Dictation only.', 'Spell letter by letter; fade to first letter; fade to full dictation; reinforce correct spelling.', 'Use Look-Cover-Write-Check strategy for irregular sight words.', 'CRF for accurate sight word spelling; VR2 once all 10 mastered.', 'Generalize to sight word spelling in all writing contexts: sentences, paragraphs, assignments.', 'Monthly probe: 10-word dictation accuracy including novel sight words from same Fry level.'),
('SPL-6', 'Spelling', 'Record C/I/P per grade-level word spelling trial. Criterion: 80%+ accurate from dictation across 3 sessions for 25 words.', 'SPL-5 (10 sight words); expanding spelling vocabulary; phonics/spelling rule knowledge growing.', 'Grade-level spelling word list (Dolch/Fry or school curriculum); pencil; lined paper.', 'Therapist dictates each word once in a sentence for context. "Write ___." No visual model.', 'Child spells 25 words from a grade-level high-frequency word list from dictation, accurately.', 'Misspells more than 5 of 25 words consistently; spelling errors do not decrease over sessions.', 'most_to_least', '1. Phoneme segmentation support > 2. First letter/cluster cue > 3. Full dictation.', 'Segment difficult words; provide initial cue; reinforce correct spelling; rotate teaching priority.', 'Group words by phonetic pattern or spelling rule for more efficient teaching.', 'CRF during acquisition of each spelling level; VR2 once 25 words stable.', 'Generalize spelling to all written communication. Monitor for correct use in sentences.', 'Monthly 10-word dictation probe sampling from the 25-word list.'),
('SPL-7', 'Spelling', 'Record C/I/P per rule-application spelling trial. Criterion: 80%+ accurate across 3 sessions for rule-governed words.', 'SPL-6 (25 sight words); phonics instruction in consonant doubling and silent-e; basic spelling rules.', 'Word lists demonstrating target rules (hop/hopping, bake/baking). Pencil; paper.', 'Therapist dictates word. "Write ___." Rules cover consonant doubling and silent-e pattern.', 'Child correctly applies basic spelling rules (consonant doubling: hop>hopping; silent-e: bake>baking).', 'Writes hop+ping without doubling (hoping), or removes silent-e incorrectly.', 'most_to_least', '1. State the rule before dictation > 2. Signal rule applies ("double it!") > 3. Independent application.', 'State specific rule; child writes with rule applied; fade verbal rule reminder to independence.', 'Teach each rule explicitly with multiple examples before applying to novel words.', 'CRF for rule-correct spelling; VR2 once both rules are reliably applied.', 'Generalize rule application to novel words in reading, writing, and spelling contexts.', 'Monthly probe: novel word spelling with consonant doubling and silent-e requiring rule application.'),
('SPL-8', 'Spelling', 'Record C/I/P per digraph word spelling trial. Criterion: 80%+ accurate across 3 sessions for words with sh, ch, th, wh.', 'SPL-7 (spelling rules); SPL-1 (letter sounds); digraph phonemic awareness.', 'Pencil; lined paper; word lists containing sh, ch, th, wh digraphs (shop, chip, this, when).', 'Therapist dictates digraph word once. "Write ___." No visual model.', 'Child spells words containing common digraphs (sh, ch, th, wh) correctly from dictation.', 'Spells digraph as two separate letters (s+h instead of sh), omits one letter of digraph.', 'most_to_least', '1. Segment and identify digraph aloud > 2. First letter of digraph cue > 3. Full dictation.', 'Identify digraph explicitly; reinforce correct 2-letter digraph spelling; fade guidance.', 'Teach each digraph as a unit. Use sound-spelling pattern cards for visual reference.', 'CRF for digraph-accurate spelling; VR2 once all 4 digraphs mastered.', 'Generalize to all digraph patterns in writing contexts. Include final digraphs (fish, much).', 'Monthly probe: novel digraph word spelling accuracy across all 4 trained digraph types.'),
('SPL-9', 'Spelling', 'Record self-correction instances per writing sample. Criterion: identifies and self-corrects 80%+ of spelling errors in own work across 3 samples.', 'SPL-8 (digraph spelling); WRT-13 (self-editing); self-monitoring awareness.', 'Own written work; editing checklist for spelling; dictionary access if appropriate.', 'Child writes a paragraph or assignment. Then: "Check your spelling. Fix any mistakes you find."', 'Child identifies and self-corrects spelling errors in own written work, independently.', 'Does not notice spelling errors, edits superficially, or needs every error pointed out.', 'most_to_least', '1. Read each word aloud (listening check) > 2. Circle uncertain words > 3. Independent spell-check.', 'Teach word-by-word reading strategy; circle uncertain words; use dictionary; fade support.', 'Teach awareness of uncertain words. Use computer spell-check as a stepping stone to independence.', 'Natural writing improvement as reinforcement.', 'Generalize spell-checking to all academic writing tasks.', 'Monthly probe: proportion of spelling errors self-identified and corrected in written work.'),
('SPL-10', 'Spelling', 'Record C/I/P per prefix/suffix word spelling trial. Criterion: 80%+ accurate across 3 sessions.', 'SPL-9 (self-correction); SPL-7 (basic rules); morphological awareness beginning.', 'Word lists with common prefixes (un-, re-, pre-) and suffixes (-ful, -less, -ness, -tion). Pencil; paper.', 'Therapist dictates prefix/suffix word. "Write ___." No visual model.', 'Child spells words with common prefixes and suffixes correctly from dictation.', 'Misspells base word, misspells prefix/suffix morpheme, or merges/separates incorrectly.', 'most_to_least', '1. Identify morpheme segments before writing > 2. First morpheme cue > 3. Full word dictation.', 'Identify base + prefix/suffix; write separately then combined; reinforce correct morpheme spelling.', 'Teach morpheme meanings alongside spelling. Group words by shared prefix or suffix.', 'CRF for morpheme-accurate spelling; VR2 once common prefixes and suffixes mastered.', 'Generalize morpheme-based spelling to novel words with trained prefixes/suffixes.', 'Monthly probe: novel prefix/suffix word spelling accuracy across 5 trained morpheme types.'),
('SPL-11', 'Spelling', 'Record accurate spelling from dictation per session. Criterion: 80%+ accurate from dictation across 3 sessions for 100 words.', 'SPL-10 (prefixes/suffixes); full spelling foundation across Levels 1-2; expanding spelling vocabulary.', 'Grade-level spelling lists across curriculum subjects; pencil; lined paper.', 'Weekly dictation of rotating words from 100-word pool. One word per trial.', 'Child spells 100 or more words correctly from dictation across sessions, consistently.', 'Accuracy drops significantly from session to session; certain word types consistently produce errors.', 'most_to_least', '1. Phoneme segmentation for difficult words > 2. First letter/morpheme cue > 3. Full dictation.', 'Identify systematic error patterns; provide targeted teaching for error clusters.', 'Rotate probing across all 100 words monthly. Identify and re-teach dropped words promptly.', 'VR3 for well-established words; CRF for newly added words.', 'Generalize correct spelling to all writing contexts, not just spelling tests.', 'Monthly 25-word rotating dictation probe from full 100-word pool.'),
('SPL-12', 'Spelling', 'Record accuracy of advanced spelling rule application per session. Criterion: 80%+ accurate on novel words requiring advanced rules across 3 sessions.', 'SPL-11 (100 words); SPL-7 (basic rules); morphological and phonological rule knowledge.', 'Novel word lists requiring advanced rules: changing y to i (cities), drop silent e (hoping), ie/ei patterns.', 'Dictate novel word requiring specific advanced spelling rule. Child applies rule without being told which.', 'Child applies advanced spelling rules accurately to novel and unfamiliar words.', 'Applies rule incorrectly, applies wrong rule, or treats all words as sight words without rule application.', 'most_to_least', '1. Identify rule family before writing > 2. Signal which rule applies > 3. Independent.', 'Identify rule without stating it explicitly; allow child to apply; reinforce correct rule use.', 'Teach advanced rules explicitly with high-frequency examples before probing novel words.', 'CRF for rule-accurate novel word spelling; VR2 once reliable.', 'Generalize rule application to writing tasks where novel words must be spelled correctly.', 'Monthly probe: novel word spelling accuracy for each advanced spelling rule type.'),
('SPL-13', 'Spelling', 'Record successful dictionary uses per session. Criterion: independently locates and verifies spelling 80%+ of dictionary use opportunities across 3 sessions.', 'SPL-12 (advanced rules); alphabetical order knowledge; basic print reference skills.', 'Dictionary (physical or digital); writing task requiring verification of uncertain spellings.', 'During writing task: "Check the spelling of ___ in the dictionary." Or "Is that how you spell it? Check."', 'Child uses a dictionary to locate and verify correct spelling independently.', 'Cannot alphabetically navigate dictionary, gives up before locating word, or does not use dictionary when uncertain.', 'most_to_least', '1. Guide to correct section of dictionary > 2. Guide to correct letter section > 3. Independent navigation.', 'Guide to approximate section; reinforce systematic alphabetical search strategy.', 'Teach dictionary navigation as explicit skill: A-Z sections, guide words, entry format.', 'Natural spelling verification success as reinforcement. Dictionary as tool for independence.', 'Generalize to digital dictionary and spell-checker use for everyday writing.', 'Monthly probe: dictionary use accuracy and efficiency (time to locate word).'),
('SPL-14', 'Spelling', 'Record phonemic segmentation accuracy per multisyllabic word. Criterion: 80%+ accurate segmentation and spelling across 3 sessions.', 'SPL-13 (dictionary use); SPL-12 (advanced rules); advanced phonological awareness.', 'Multisyllabic word lists (3-4 syllable words); pencil; paper; pronunciation support available.', 'Therapist dictates multisyllabic word. "Say it in syllables, then write it." Allow phonological approach.', 'Child demonstrates phonemic awareness when spelling multisyllabic words using syllabic segmentation strategy.', 'Treats multisyllabic word as unsegmented whole, makes errors on middle or final syllables.', 'most_to_least', '1. Syllabic segmentation aloud before writing > 2. Stress syllable cue > 3. Independent spelling.', 'Segment syllables aloud; child writes each syllable; combine; reinforce accurate multisyllabic spelling.', 'Teach syllable types (open, closed, VCe, r-controlled) to support multisyllabic spelling.', 'CRF for phonemically accurate multisyllabic spelling; VR2 once reliable.', 'Generalize syllabic spelling approach to novel academic vocabulary across all subjects.', 'Monthly probe: novel multisyllabic word spelling accuracy using phonemic awareness strategies.'),
('SPL-15', 'Spelling', 'Record correct spelling in spontaneous written work per sample. Criterion: 80%+ of words correctly spelled in spontaneous writing across 3 samples.', 'SPL-14 (multisyllabic spelling); full spelling repertoire across Levels 1-3; independent writer.', 'Spontaneous writing samples across varied academic and personal writing contexts.', 'Collect spontaneous writing sample from independent work (journal, assignment, email, note).', 'Child spells accurately in spontaneous written communication across varied contexts and genres.', 'Spelling accuracy in isolated test is high but drops significantly in spontaneous writing.', 'least_to_most', '1. No prompt > 2. Encourage use of spell-check or dictionary during writing > 3. Targeted practice for frequent error words.', 'Identify words misspelled frequently in spontaneous writing; add to targeted spelling practice.', 'Build habit of using dictionary and spell-check as writing tools without seeing them as crutches.', 'Natural communication success as reinforcement for accurate spontaneous spelling.', 'Monitor spelling in all academic writing across subjects. Coordinate with classroom teacher.', 'Monthly spontaneous writing sample: proportion of words correctly spelled across varied writing tasks.')
ON CONFLICT (milestone_code) DO UPDATE
SET vbmapp_domain = EXCLUDED.vbmapp_domain,
    data_collection = EXCLUDED.data_collection,
    prerequisite_skills = EXCLUDED.prerequisite_skills,
    materials = EXCLUDED.materials,
    sd = EXCLUDED.sd,
    correct_responses = EXCLUDED.correct_responses,
    incorrect_responses = EXCLUDED.incorrect_responses,
    prompting_hierarchy = EXCLUDED.prompting_hierarchy,
    prompting_hierarchy_detail = EXCLUDED.prompting_hierarchy_detail,
    error_correction = EXCLUDED.error_correction,
    transfer_procedure = EXCLUDED.transfer_procedure,
    reinforcement_schedule = EXCLUDED.reinforcement_schedule,
    generalization_plan = EXCLUDED.generalization_plan,
    maintenance_plan = EXCLUDED.maintenance_plan,
    template_origin = EXCLUDED.template_origin;
